/* ============================================================
   Recall Rx, DOK 3 "Explain why" expansion bank, BIO 004
   These are application and reasoning items, not recall.
   Each forces a structure-to-consequence chain: why a form
   produces a function, or what breaks when the form changes.

   Format matches the base bank:
     { dok:3, q, a, options:[...4], correctIndex, explanation }
   Cards are pushed into the matching topic BEFORE the metadata
   enrichment pass, so they receive global IDs and DOK tags
   automatically. Author: Dr. Sharilyn Rennie.
   ============================================================ */
(function(){
  var C = (typeof window !== "undefined") ? window.BIO004_COURSE_CONTENT : null;
  if (!C || !C.modules) return;
  var byId = {};
  C.modules.forEach(function(m){ (m.topics||[]).forEach(function(t){ byId[t.id] = t; }); });

  // Deterministic option shuffle so the correct answer is not always option A.
  // Seeded by the question text, so the arrangement is stable across reloads
  // (card identity is keyed by global ID, not option order, so this is safe).
  function hashStr(s){ var h = 2166136261; for (var i = 0; i < s.length; i++){ h ^= s.charCodeAt(i); h = Math.imul(h, 16777619); } return h >>> 0; }
  function mulberry32(a){ return function(){ a |= 0; a = a + 0x6D2B79F5 | 0; var t = Math.imul(a ^ a >>> 15, 1 | a); t = t + Math.imul(t ^ t >>> 7, 61 | t) ^ t; return ((t ^ t >>> 14) >>> 0) / 4294967296; }; }
  function shuffleCard(card){
    if (!Array.isArray(card.options) || card.options.length < 2 || typeof card.correctIndex !== "number") return;
    var correct = card.options[card.correctIndex];
    var rng = mulberry32(hashStr(String(card.q)));
    var arr = card.options.slice();
    for (var i = arr.length - 1; i > 0; i--){ var j = Math.floor(rng() * (i + 1)); var tmp = arr[i]; arr[i] = arr[j]; arr[j] = tmp; }
    card.options = arr;
    card.correctIndex = arr.indexOf(correct);
    card.a = correct;
  }

  var DOK3 = {

  /* ---------- TISSUES ---------- */
  "t-tissues": [
    { dok:3, q:"Simple squamous epithelium lines the air sacs of the lungs and the inner walls of capillaries. Why is this flat, single-layer design used in both places?", a:"Both sites move material across the wall, and a thin single layer shortens the diffusion distance.", options:["Both sites need a thick barrier to block all crossing of material.","Both sites move material across the wall, and a thin single layer shortens the diffusion distance.","Both sites face heavy abrasion that flat cells resist best.","Both sites secrete large volumes of mucus that flat cells produce."], correctIndex:1, explanation:"Air sacs and capillary walls both exist to let material cross quickly. A single flat layer is the shortest possible path, so diffusion is fast. A thick barrier would slow crossing, abrasion resistance is the job of stratified epithelium, and mucus secretion is the job of glandular and columnar tissue." },
    { dok:3, q:"The epidermis is stratified squamous epithelium, while the lining of the stomach is simple columnar. Why does each location get a different number of cell layers?", a:"The epidermis faces abrasion and needs many sacrificial layers, while the stomach lining favors a single layer for secretion and absorption.", options:["The stomach faces more abrasion and so needs more layers than skin.","Both should be the same and the difference is an error of classification.","The epidermis faces abrasion and needs many sacrificial layers, while the stomach lining favors a single layer for secretion and absorption.","Layer number is random and unrelated to the work the tissue does."], correctIndex:2, explanation:"Many layers protect against surface wear because the top cells can be lost and replaced, which fits skin. A single layer keeps the diffusion and secretion path short, which fits the stomach lining. The trade is protection versus exchange, so the two sites are built differently on purpose." },
    { dok:3, q:"A tissue must stretch and recoil repeatedly, such as in the wall of a large artery. Which connective tissue fiber should dominate, and why?", a:"Elastic fibers, because they stretch and return to shape without permanent deformation.", options:["Collagen fibers, because they resist stretch with great tensile strength.","Reticular fibers, because they form a soft supporting mesh for cells.","Elastic fibers, because they stretch and return to shape without permanent deformation.","No fibers, because stretch requires the absence of fiber."], correctIndex:2, explanation:"Elastic fibers are built to extend and snap back, which a repeatedly stretched artery wall needs. Collagen resists stretch but does not recoil, reticular fibers only support soft organs, and a wall with no fiber would tear under pressure." },
    { dok:3, q:"Cartilage heals slowly after injury while most epithelium heals quickly. What feature of cartilage best explains the slow repair?", a:"Cartilage is avascular, so cells and nutrients reach the injury only by slow diffusion.", options:["Cartilage is richly vascular, which floods the wound and slows clotting.","Cartilage is avascular, so cells and nutrients reach the injury only by slow diffusion.","Cartilage has no cells at all, so nothing can divide to repair it.","Cartilage is innervated, and nerves block the arrival of repair cells."], correctIndex:1, explanation:"Cartilage has no blood vessels, so oxygen, nutrients, and repair cells must diffuse in through the matrix, which is slow. Epithelium sits on a vascular connective tissue bed and heals fast. Cartilage does contain chondrocytes, and innervation is not the reason for slow healing." },
    { dok:3, q:"Pseudostratified ciliated columnar epithelium lines much of the airway. Why is the ciliated, mucus-trapping design suited to that location?", a:"It traps inhaled debris in mucus and sweeps it away from the lungs, protecting delicate exchange surfaces.", options:["It absorbs inhaled air directly into the bloodstream across the cilia.","It traps inhaled debris in mucus and sweeps it away from the lungs, protecting delicate exchange surfaces.","It provides a thick waterproof seal that blocks all airflow.","It secretes digestive enzymes onto incoming food in the airway."], correctIndex:1, explanation:"Airway epithelium guards the deep, thin exchange surfaces. Cilia and mucus catch particles and move them up and out, keeping debris from reaching the alveoli. Gas exchange itself happens deeper in simple squamous tissue, not here, and the airway is not a digestive or sealing surface." },
    { dok:3, q:"Glands are classified as endocrine or exocrine. Why does an endocrine gland not need a duct, while an exocrine gland does?", a:"Endocrine glands release products into the blood, while exocrine glands deliver products to a surface and need a duct to carry them there.", options:["Endocrine glands release products into the blood, while exocrine glands deliver products to a surface and need a duct to carry them there.","Endocrine glands are larger, so a duct would not fit inside them.","Exocrine glands make hormones that travel only through ducts.","The duct is decorative and neither type of gland actually uses it."], correctIndex:0, explanation:"Endocrine products enter the bloodstream directly, so no tube is required. Exocrine products such as sweat, saliva, or enzymes must reach a specific surface, and the duct is the delivery path. Size is not the issue, and hormones are the endocrine, not exocrine, product." },
    { dok:3, q:"Transitional epithelium lines the urinary bladder. Why is this tissue type, rather than simple squamous, the right choice there?", a:"Transitional epithelium changes shape as the bladder fills and empties, stretching without tearing.", options:["Simple squamous would stretch better and should be there instead.","Transitional epithelium changes shape as the bladder fills and empties, stretching without tearing.","Transitional epithelium speeds diffusion of urine into the blood.","The bladder needs cilia, which only transitional epithelium provides."], correctIndex:1, explanation:"The bladder repeatedly expands and shrinks, so its lining must change shape and area without rupturing. Transitional epithelium does exactly that. The bladder must not let urine diffuse back into the blood, so a leak-prone thin layer would be wrong, and the bladder lining is not ciliated." },
    { dok:3, q:"Adipose tissue stores fat, cushions organs, and insulates the body. Why is its cell structure, a large lipid droplet pushing the nucleus to the edge, well matched to that job?", a:"A single large droplet maximizes the lipid stored per cell, which fits a tissue built for energy storage.", options:["The droplet is empty space that keeps the cell from doing any work.","A single large droplet maximizes the lipid stored per cell, which fits a tissue built for energy storage.","The off-center nucleus produces the fat that fills the droplet.","The droplet conducts heat away from the body to cool it."], correctIndex:1, explanation:"Packing one large droplet into each cell stores the most fat in the least cell volume, which is what a storage and insulating tissue needs. The droplet is full of lipid, not empty, the nucleus does not manufacture the droplet contents that way, and adipose insulates by trapping heat rather than conducting it away." }
  ],

  /* ---------- INTEGUMENTARY ---------- */
  "t-integumentary": [
    { dok:3, q:"The epidermis has no blood vessels of its own, yet its deepest cells stay alive. Why are the deepest epidermal cells living while the surface cells are dead?", a:"The deep cells lie near the vascular dermis and get nutrients by diffusion, while surface cells are too far from that supply.", options:["The surface cells are killed deliberately by sunlight every day.","The deep cells lie near the vascular dermis and get nutrients by diffusion, while surface cells are too far from that supply.","The surface cells have their own blood vessels that later disappear.","Depth has no effect, and which cells die is purely random."], correctIndex:1, explanation:"Because the epidermis is avascular, every epidermal cell depends on diffusion from dermal vessels below. Deep cells are close enough to survive, but as cells are pushed toward the surface they outrun the supply, fill with keratin, and die. The surface layer of dead, keratinized cells is the durable barrier." },
    { dok:3, q:"A deep burn that destroys the dermis often cannot regrow hair or sweat glands, while a shallow scrape can. Why does dermal depth determine this?", a:"Hair follicles and glands are rooted in the dermis, so destroying the dermis removes the structures needed to regenerate them.", options:["Hair and glands live only in the epidermis, which a scrape removes.","Hair follicles and glands are rooted in the dermis, so destroying the dermis removes the structures needed to regenerate them.","Deep burns add new follicles, but shallow scrapes remove them.","Depth is irrelevant, and the difference is due to the burn temperature alone."], correctIndex:1, explanation:"Follicles and glands are dermal structures. A scrape that spares the dermis leaves these intact to rebuild the surface, but a burn that destroys the dermis takes the follicles and glands with it, so they cannot return. This is why full thickness burns scar without hair or sweat function." },
    { dok:3, q:"Melanin granules in keratinocytes cluster on the sun-facing side of the nucleus. Why does that position protect the cell?", a:"The pigment forms a shield between incoming ultraviolet light and the DNA in the nucleus.", options:["The pigment feeds the nucleus extra energy to repair itself.","The pigment forms a shield between incoming ultraviolet light and the DNA in the nucleus.","The pigment heats the nucleus so it divides faster under sun.","The position is random and gives no protection at all."], correctIndex:1, explanation:"Ultraviolet light damages DNA, so placing melanin like a cap over the sun-facing side of the nucleus intercepts the rays before they reach the genetic material. The pigment absorbs and blocks light rather than feeding or heating the nucleus, and the placement is purposeful, not random." },
    { dok:3, q:"Skin helps cool the body when it overheats. Which combination of skin responses lowers body temperature, and why?", a:"Sweat glands release fluid that evaporates and dermal vessels widen to release heat at the surface.", options:["Sweat glands shut down and dermal vessels narrow to trap heat.","Sweat glands release fluid that evaporates and dermal vessels widen to release heat at the surface.","Hair stands up and vessels narrow to push heat outward.","The epidermis thickens to radiate heat from dead cells."], correctIndex:1, explanation:"Evaporating sweat carries heat away, and widening dermal vessels brings warm blood close to the surface where it can shed heat. Shutting sweat down and narrowing vessels conserve heat instead, which is the cold response, and a thicker dead layer does not radiate heat." },
    { dok:3, q:"Thick skin on the palms and soles has an extra epidermal layer, the stratum lucidum, and a deeper stratum corneum. Why is this build found where it is?", a:"Palms and soles face heavy friction and pressure, so extra dead, keratinized layers resist wear.", options:["Palms and soles need to absorb water, which extra layers speed up.","Palms and soles face heavy friction and pressure, so extra dead, keratinized layers resist wear.","Palms and soles must stay thin to feel fine textures, so layers are removed.","The extra layer makes the palms produce more hair than elsewhere."], correctIndex:1, explanation:"Surfaces that grip and bear weight take constant abrasion, so more layers of tough, dead, keratin-filled cells protect the living tissue beneath. Thick skin actually limits water crossing rather than absorbing it, and palms and soles are hairless, so the extra layer is about wear, not hair." },
    { dok:3, q:"Cyanosis, a bluish skin tint, appears when blood oxygen is low. Why does low oxygen change the visible color of the skin?", a:"Oxygen-poor hemoglobin is darker and bluer, and that color shows through the skin where vessels are near the surface.", options:["Low oxygen turns melanin blue throughout the epidermis.","Oxygen-poor hemoglobin is darker and bluer, and that color shows through the skin where vessels are near the surface.","Low oxygen fills the skin with blue pigment made by sweat glands.","The skin reflects sky color more strongly when oxygen drops."], correctIndex:1, explanation:"Hemoglobin without oxygen has a darker, bluish hue compared with bright red oxygenated blood. Where dermal vessels lie close to the surface, that color is visible through the skin. Melanin and sweat glands do not change color with oxygen, and the effect is not reflection of the sky." },
    { dok:3, q:"A patient is dehydrated, and a pinch of their skin stays tented instead of springing back. Which skin property explains the lost spring, and what causes it here?", a:"Skin turgor depends on dermal water and elastic fibers, and dehydration removes the water that keeps the dermis full.", options:["Skin turgor depends only on the dead surface cells, which dry out first.","Skin turgor depends on dermal water and elastic fibers, and dehydration removes the water that keeps the dermis full.","Tenting happens because dehydration adds extra collagen overnight.","Tenting is unrelated to water and reflects melanin loss instead."], correctIndex:1, explanation:"A hydrated dermis is plump and its elastic fibers recoil, so pinched skin snaps back. Dehydration drains dermal water, so the tissue is slack and stays tented. The effect is about dermal hydration and elasticity, not the dead surface layer, added collagen, or pigment." },
    { dok:3, q:"Nail beds and lips appear pink in light-skinned people even though the tissue itself is not red. Why does the pink show there especially?", a:"These regions have thin, translucent surface tissue over rich blood supply, so the red of blood shows through.", options:["These regions make their own pink pigment that other skin lacks.","These regions have thin, translucent surface tissue over rich blood supply, so the red of blood shows through.","These regions reflect more light because they contain extra melanin.","The pink is dye from food and is not related to blood at all."], correctIndex:1, explanation:"Where the covering tissue is thin and lightly pigmented and blood supply is dense, the color of the underlying blood is visible, giving a pink look. There is no special pink pigment, these areas have less melanin rather than more, and the color comes from blood, not food." }
  ],

  /* ---------- BONE HISTOLOGY ---------- */
  "t-bone-histology": [
    { dok:3, q:"Compact bone is arranged in cylindrical osteons with a central canal. Why does the central canal sit at the core of each osteon?", a:"It carries blood vessels that supply the osteocytes, which are too embedded in hard matrix to reach the surface.", options:["It is empty space that lightens the bone with no other role.","It carries blood vessels that supply the osteocytes, which are too embedded in hard matrix to reach the surface.","It stores fat that the bone burns for movement.","It lets the bone bend by acting as a hollow hinge."], correctIndex:1, explanation:"Osteocytes are trapped in hard, calcified matrix and cannot reach a surface for nutrients, so each osteon centers on a canal of vessels, and tiny canaliculi connect the cells to it. The canal is not empty, is not a fat store in this role, and does not act as a hinge." },
    { dok:3, q:"Spongy bone fills the ends of long bones, while compact bone forms the shaft. Why is the lighter spongy bone placed at the ends?", a:"The trabeculae of spongy bone align along stress lines, giving strength at the joints with less weight.", options:["The ends bear no force, so weak bone is acceptable there.","The trabeculae of spongy bone align along stress lines, giving strength at the joints with less weight.","Spongy bone at the ends prevents the bone from growing.","The ends need to be heavy, and spongy bone is the densest tissue."], correctIndex:1, explanation:"Spongy bone is not random. Its struts line up along the directions of force at the joint, so it resists stress where loads change direction while keeping the bone light. The ends do bear force, spongy bone does not block growth, and spongy bone is less dense, not more." },
    { dok:3, q:"Bone constantly remodels through osteoblasts that build and osteoclasts that break down. Why is ongoing breakdown, not just building, necessary for healthy bone?", a:"Remodeling repairs micro-damage and lets bone release stored calcium when the body needs it.", options:["Breakdown is a disease process that healthy bone avoids entirely.","Remodeling repairs micro-damage and lets bone release stored calcium when the body needs it.","Breakdown only happens after death and not in living bone.","Osteoclasts build bone, so more breakdown means more bone mass."], correctIndex:1, explanation:"Bone is a living, dynamic store. Removing old or cracked matrix lets new matrix replace it, and dissolving matrix frees calcium for the blood when levels drop. Breakdown is normal in living bone, osteoclasts resorb rather than build, so the balance of the two processes keeps bone both sound and useful as a mineral reserve." },
    { dok:3, q:"Osteocytes sit in small chambers called lacunae and connect through thin channels called canaliculi. Why are the canaliculi essential to osteocyte survival?", a:"They let nutrients and wastes pass between cells and the blood vessel, since the matrix itself blocks diffusion.", options:["They let the osteocytes crawl out of the bone when damaged.","They let nutrients and wastes pass between cells and the blood vessel, since the matrix itself blocks diffusion.","They store extra calcium crystals away from the cells.","They are sound channels that let the bone hear vibration."], correctIndex:1, explanation:"Calcified matrix is too dense for nutrients to diffuse through freely, so the hair-thin canaliculi form a relay of passages connecting each trapped osteocyte to the central canal supply. They are transport channels, not escape routes, mineral stores, or sound channels." },
    { dok:3, q:"The organic part of bone matrix is mostly collagen, and the inorganic part is mostly calcium mineral. Why does bone need both components together?", a:"Collagen gives flexibility and resists tension, while mineral gives hardness and resists compression.", options:["Collagen makes bone brittle and mineral makes it floppy.","Collagen gives flexibility and resists tension, while mineral gives hardness and resists compression.","Both do the same job, so one of them is unnecessary.","Mineral provides flexibility and collagen provides hardness."], correctIndex:1, explanation:"Mineral alone would be hard but brittle and would shatter, while collagen alone would be flexible but soft and would bend too far. Together, collagen handles pulling forces and gives some give, and mineral handles crushing forces and gives stiffness, so the pair is far stronger than either alone." },
    { dok:3, q:"In a child, the epiphyseal plate is cartilage, but in an adult it becomes a bony line. Why must this plate be cartilage during growth?", a:"Cartilage can grow from within and be replaced by bone, lengthening the bone until growth ends.", options:["Cartilage blocks all lengthening, so growth stops while it is present.","Cartilage can grow from within and be replaced by bone, lengthening the bone until growth ends.","Cartilage is heavier than bone and weighs the limb down to grow it.","The plate is bone in children and turns to cartilage in adults."], correctIndex:1, explanation:"The growth plate adds new cartilage on the epiphyseal side and converts older cartilage to bone on the shaft side, so the bone gets longer. When growth finishes the entire plate ossifies into the epiphyseal line. The plate is cartilage in youth, not adulthood, and it drives, not blocks, lengthening." },
    { dok:3, q:"A bone that is repeatedly loaded, as in a weight lifter, becomes denser over time. Why does mechanical stress increase bone density?", a:"Stress signals osteoblasts to add matrix where load is greatest, strengthening the bone along stress lines.", options:["Stress melts the bone, which then refreezes thicker.","Stress signals osteoblasts to add matrix where load is greatest, strengthening the bone along stress lines.","Stress kills osteoclasts so no bone is ever lost again.","Density is fixed at birth and stress cannot change it."], correctIndex:1, explanation:"Bone responds to demand. Mechanical load stimulates bone-building osteoblasts to lay down matrix where stress is highest, so the bone remodels to be stronger exactly where it is used. Bone does not melt, osteoclasts are not simply killed, and density is not fixed but adapts throughout life." },
    { dok:3, q:"After a fracture, a soft cartilage callus forms first and is later replaced by bone. Why does the body build the cartilage callus before the bony one?", a:"Cartilage can form quickly without a blood supply and bridges the gap until vessels and bone can grow in.", options:["Cartilage is the final repair and never gets replaced.","Cartilage can form quickly without a blood supply and bridges the gap until vessels and bone can grow in.","Cartilage prevents the bone ends from ever rejoining.","Bone forms instantly, so the cartilage step is just a mistake."], correctIndex:1, explanation:"Right after a break the area has torn vessels and little blood flow, and cartilage tolerates low oxygen, so it can form fast to stabilize the gap. As blood supply returns, that callus is replaced by bone. Cartilage is a temporary bridge, not the final tissue, and it aids rather than blocks union." },
    { dok:3, q:"The flat bones of the skull form by ossifying directly within a sheet of fibrous membrane, while long bones form from a cartilage model. Why does this difference suit each bone's job?", a:"Flat protective plates can form quickly as thin sheets, while weight-bearing long bones need the cartilage model that allows lengthwise growth.", options:["Flat protective plates can form quickly as thin sheets, while weight-bearing long bones need the cartilage model that allows lengthwise growth.","Both bone types must form from cartilage or they will be weak.","Membrane bone is stronger under weight than cartilage-derived bone.","The method of formation has no relation to the bone's role."], correctIndex:0, explanation:"Skull plates mainly shield the brain and can be built efficiently as flat sheets directly in membrane. Long bones must grow in length and bear weight, which the cartilage-model method supports through growth plates. Each developmental route matches whether the bone needs to lengthen and load-bear or simply enclose and protect." }
  ],

  /* ---------- ARTICULATIONS (JOINTS) ---------- */
  "t-articulations": [
    { dok:3, q:"The shoulder is the most mobile joint in the body but dislocates more easily than the hip. Why does its structure trade stability for movement?", a:"A shallow socket and loose capsule allow wide motion but hold the head of the humerus less securely.", options:["A deep socket grips the bone tightly, which somehow increases dislocation.","A shallow socket and loose capsule allow wide motion but hold the head of the humerus less securely.","The shoulder has more ligaments than any joint, making it loose.","Mobility and stability always rise together, so the premise is false."], correctIndex:1, explanation:"The shoulder's shallow glenoid cavity and loose capsule let the arm swing in nearly every direction, but the same shallowness means the joint is poorly contained and pops out more readily. The hip's deep socket grips its ball tightly, giving stability at the cost of range. Mobility and stability trade against each other." },
    { dok:3, q:"Synovial joints have a fluid-filled cavity, while sutures of the skull do not move at all. Why does the presence or absence of a joint cavity track with movement?", a:"A fluid-filled cavity separates the bones and lets them glide, while fibrous joints bind bones directly and prevent motion.", options:["The cavity glues the bones together and stops all motion.","A fluid-filled cavity separates the bones and lets them glide, while fibrous joints bind bones directly and prevent motion.","Sutures contain more synovial fluid than synovial joints.","Movement depends on bone color, not on a joint cavity."], correctIndex:1, explanation:"A synovial cavity holds slippery fluid between the bone ends so they slide freely, which is why these joints move. Sutures join bones with fibrous tissue and no cavity, locking them together for protection. The cavity enables movement rather than preventing it, and sutures have no synovial fluid." },
    { dok:3, q:"Articular cartilage covers the bone ends inside a synovial joint, and it has no blood supply. Why does this avascular covering rely on joint movement to stay healthy?", a:"Movement pumps synovial fluid in and out of the cartilage, delivering nutrients it cannot get from blood.", options:["Movement grinds the cartilage away, which keeps it thin and healthy.","Movement pumps synovial fluid in and out of the cartilage, delivering nutrients it cannot get from blood.","Cartilage has its own vessels, so movement is unnecessary.","Movement heats the cartilage so it can make its own nutrients."], correctIndex:1, explanation:"With no blood vessels, articular cartilage is fed by synovial fluid, and compression and release during movement squeeze fluid in and out like a sponge, carrying nutrients in and wastes out. This is why immobilized joints lose cartilage health. Movement nourishes rather than grinds, and the cartilage is avascular." },
    { dok:3, q:"Ligaments connect bone to bone and are built mostly of dense collagen with little elastic fiber. Why is this composition right for a ligament's job?", a:"Collagen resists stretch strongly, so the joint is held in place and not allowed to over-extend.", options:["Elastic fiber would lock the joint, so collagen is used to loosen it.","Collagen resists stretch strongly, so the joint is held in place and not allowed to over-extend.","Collagen lets the ligament stretch endlessly without limiting motion.","Ligaments need to conduct nerve signals, which collagen provides."], correctIndex:1, explanation:"A ligament's role is to limit motion and keep bones aligned, so it needs material that resists pulling and does not stretch much. Dense collagen does this. A stretchy elastic ligament would let the joint move too far, which is why a sprained, overstretched ligament leaves a joint unstable." },
    { dok:3, q:"A hinge joint such as the elbow moves in only one plane, while a ball and socket joint moves in several. Why does the shape of the articulating surfaces set the range of motion?", a:"A hinge's cylinder-in-groove shape permits only back-and-forth motion, while a ball in a cup can rotate in many directions.", options:["Both shapes allow identical motion, so shape does not matter.","A hinge's cylinder-in-groove shape permits only back-and-forth motion, while a ball in a cup can rotate in many directions.","The ball and socket is limited to one plane and the hinge to many.","Range of motion depends only on muscle and never on joint shape."], correctIndex:1, explanation:"Joint shape constrains motion. A hinge fits a rounded surface into a trough, allowing flexion and extension in one plane like a door. A ball and socket places a sphere in a cup, which can tilt and spin in many directions. The geometry, not just the muscle, defines the available movements." },
    { dok:3, q:"Bursae are small fluid sacs placed where tendons rub over bone near a joint. Why does inflammation of a bursa cause pain with movement?", a:"The bursa normally cushions friction, so when it swells and is irritated, the rubbing motion presses on inflamed tissue.", options:["The bursa makes the joint move faster, so swelling speeds it painfully.","The bursa normally cushions friction, so when it swells and is irritated, the rubbing motion presses on inflamed tissue.","Bursae have no role, so their inflammation cannot affect movement.","Pain comes only from bone, never from a fluid sac."], correctIndex:1, explanation:"A bursa is a friction-reducing cushion between moving parts. When it becomes inflamed and swollen, every movement that would normally glide smoothly now compresses the tender, irritated sac, producing pain on motion. The bursa reduces friction rather than adding speed, and inflamed soft tissue is a real pain source." },
    { dok:3, q:"Cartilaginous joints such as those between vertebrae allow slight movement and absorb shock, unlike rigid sutures. Why does the cartilage pad between vertebrae suit the spine's needs?", a:"The pad compresses to cushion loads and allows small movements, giving the spine flexibility and shock absorption.", options:["The pad locks the vertebrae rigidly so the spine cannot bend at all.","The pad compresses to cushion loads and allows small movements, giving the spine flexibility and shock absorption.","The pad is bone, so it transmits shock directly without cushioning.","The pad's only role is to add weight to the spine."], correctIndex:1, explanation:"Each intervertebral disc of cartilage can squash slightly to absorb impact and permits a small amount of bending at each level. Summed over many vertebrae, this gives the spine both flexibility and the ability to cushion loads. A rigid joint would do neither, and cartilage is not bone." },
    { dok:3, q:"When a joint is held still in a cast for weeks, it often becomes stiff and the surrounding tissue tightens. Why does immobilization reduce joint range?", a:"Without movement, connective tissue shortens and articular cartilage loses its fluid-driven nourishment.", options:["Immobilization adds new joint cavity, which over-loosens the joint.","Without movement, connective tissue shortens and articular cartilage loses its fluid-driven nourishment.","Casts inject collagen that permanently fuses the bones.","Stiffness after a cast is imaginary and not based on tissue change."], correctIndex:1, explanation:"Joints depend on regular motion. Held still, the capsule and surrounding connective tissue shorten and tighten, and the cartilage, fed by fluid that movement normally circulates, is undernourished. Both changes cut range, which is why rehabilitation restores motion gradually. The cast does not add cavity or inject collagen." }
  ],

  /* ---------- MUSCLE STRUCTURE ---------- */
  "t-muscle-structure": [
    { dok:3, q:"Skeletal muscle cells are long, multinucleated fibers, while most body cells have a single nucleus. Why does a muscle fiber need many nuclei?", a:"A large fiber has high protein demand, and multiple nuclei supply enough instructions to maintain it.", options:["Extra nuclei store calcium for contraction.","A large fiber has high protein demand, and multiple nuclei supply enough instructions to maintain it.","Extra nuclei let the fiber contract without nerve input.","The nuclei are decorative leftovers with no function."], correctIndex:1, explanation:"A skeletal muscle fiber is enormous compared with a typical cell and must constantly make large amounts of contractile protein. One nucleus could not direct protein production across that whole length, so the fiber fuses from many cells and keeps many nuclei to manage the volume. Calcium is stored in the sarcoplasmic reticulum, not nuclei." },
    { dok:3, q:"A muscle fiber is packed with myofibrils made of repeating sarcomeres. Why does the striped, repeating arrangement of sarcomeres make contraction effective?", a:"Many sarcomeres shortening in series add their small length changes into one large, coordinated shortening.", options:["The stripes are pigment and play no role in contraction.","Many sarcomeres shortening in series add their small length changes into one large, coordinated shortening.","Each sarcomere works against its neighbor, canceling motion out.","The repeats slow the muscle so it cannot move quickly."], correctIndex:1, explanation:"Each sarcomere shortens only a little, but thousands lined up end to end add their tiny changes together, so the whole fiber shortens substantially and pulls strongly. They work in the same direction, not against each other. The striped look comes from the orderly overlap of filaments, not pigment." },
    { dok:3, q:"Each skeletal muscle fiber is wrapped in connective tissue, and these wrappings merge into a tendon at the end. Why is this continuous connective tissue arrangement important for movement?", a:"It transfers the force of contracting fibers to the tendon and then to bone, so the muscle can move the skeleton.", options:["It insulates the fibers so their force never reaches the bone.","It transfers the force of contracting fibers to the tendon and then to bone, so the muscle can move the skeleton.","It allows each fiber to act alone with no connection to the bone.","Its only role is to give the muscle its color."], correctIndex:1, explanation:"The wrappings around fibers, bundles, and the whole muscle are continuous with the tendon, forming an unbroken chain from fiber to bone. When fibers shorten, the force passes through this connective tissue into the tendon and pulls the bone. Without that continuity, contraction could not move the skeleton." },
    { dok:3, q:"The sarcoplasmic reticulum forms a network around each myofibril and stores calcium. Why does placing the calcium store so close to the myofibrils matter for contraction speed?", a:"Calcium can be released and reabsorbed across a tiny distance, so contraction starts and stops quickly.", options:["The closeness slows calcium down so contraction is gentle.","Calcium can be released and reabsorbed across a tiny distance, so contraction starts and stops quickly.","The store must be far away so calcium has time to build up.","Calcium location has no effect on how fast a muscle responds."], correctIndex:1, explanation:"Contraction depends on calcium reaching the filaments and then being pulled back to allow relaxation. Wrapping the calcium store tightly around each myofibril means the diffusion distance is minimal, so release triggers contraction almost instantly and reuptake ends it quickly. Distance would delay both steps." },
    { dok:3, q:"Smooth muscle in the gut wall contracts slowly and can stay contracted for long periods, unlike the fast twitch of skeletal muscle. Why does its structure suit slow, sustained work?", a:"Smooth muscle's arrangement produces slow, economical contractions that hold tone without tiring quickly.", options:["Smooth muscle has more sarcomeres, making it the fastest tissue.","Smooth muscle's arrangement produces slow, economical contractions that hold tone without tiring quickly.","Smooth muscle cannot contract at all and only stretches.","Its structure is identical to skeletal muscle in every way."], correctIndex:1, explanation:"Organs like the gut need steady, prolonged squeezing rather than rapid bursts. Smooth muscle is built to contract slowly and hold tension with little energy and little fatigue, which fits maintaining tone and slow propulsion. It lacks the striped sarcomere pattern of skeletal muscle, so it is not identical and not the fastest tissue." },
    { dok:3, q:"Cardiac muscle cells are joined by intercalated discs containing gap junctions. Why is this connection essential for the heart to function as a pump?", a:"Gap junctions let the electrical signal pass cell to cell so the heart contracts as a coordinated unit.", options:["They electrically isolate each cell so they beat at random.","Gap junctions let the electrical signal pass cell to cell so the heart contracts as a coordinated unit.","They store blood between cells for later ejection.","They prevent the heart cells from ever contracting together."], correctIndex:1, explanation:"A pump must squeeze as one. Gap junctions in the intercalated discs allow the contraction signal to spread directly from cell to cell, so the heart muscle acts like a single connected sheet and beats in unison. Isolated, randomly firing cells could not generate an effective pumping stroke." },
    { dok:3, q:"A muscle that has many fibers per motor unit produces coarse, powerful movements, while one with few fibers per unit produces fine control. Why does the fiber-to-neuron ratio set the precision of a muscle?", a:"Fewer fibers per neuron means each signal moves a smaller amount of muscle, allowing finer adjustments.", options:["More fibers per neuron always gives finer control.","Fewer fibers per neuron means each signal moves a smaller amount of muscle, allowing finer adjustments.","The ratio affects color but not control.","Precision depends only on muscle size, not on motor units."], correctIndex:1, explanation:"A motor unit is one neuron and the fibers it controls. When a neuron commands only a few fibers, each activation changes tension in a small step, allowing delicate, graded movement, as in the eye or hand. Many fibers per neuron move large chunks at once, giving power but not finesse." },
    { dok:3, q:"Muscle fibers contain many mitochondria, especially in muscles used for endurance such as postural muscles. Why does an endurance muscle benefit from abundant mitochondria?", a:"Mitochondria supply sustained energy through aerobic respiration, which endurance work demands.", options:["Mitochondria store the calcium that triggers each contraction.","Mitochondria supply sustained energy through aerobic respiration, which endurance work demands.","Mitochondria make the muscle contract faster but tire sooner.","Mitochondria are present only in muscles that never contract."], correctIndex:1, explanation:"Endurance muscles must keep working for long stretches without fatiguing, which requires a steady supply of energy made with oxygen. Mitochondria are the sites of that aerobic energy production, so endurance fibers are rich in them. Calcium is stored in the sarcoplasmic reticulum, and more mitochondria support stamina, not faster fatigue." }
  ],

  /* ---------- HEART ---------- */
  "t-heart": [
    { dok:3, q:"The atrioventricular valves are anchored by stringy chordae tendineae attached to papillary muscles. Why are these cords necessary when the ventricles contract forcefully?", a:"They hold the valve flaps from flipping backward into the atria under high ventricular pressure.", options:["They pull the valves fully open so blood can leave the atria.","They hold the valve flaps from flipping backward into the atria under high ventricular pressure.","They generate the heartbeat by pulling on the valves.","They store blood inside the valve during contraction."], correctIndex:1, explanation:"When a ventricle contracts, pressure soars and would push the AV valve flaps backward into the atrium, letting blood leak the wrong way. The chordae tendineae, tethered to papillary muscles, act like guy-wires that keep the flaps from prolapsing, so the valve seals. They do not open the valve, create the beat, or store blood." },
    { dok:3, q:"The left ventricle wall is much thicker than the right ventricle wall. Why does this difference in muscle thickness make functional sense?", a:"The left ventricle pumps blood to the whole body against high resistance, while the right only pumps to the nearby lungs.", options:["The right ventricle pumps to the whole body and needs more muscle.","The left ventricle pumps blood to the whole body against high resistance, while the right only pumps to the nearby lungs.","Both pump equally, so the difference is a defect.","The left ventricle is thicker only because it holds more blood."], correctIndex:1, explanation:"The right ventricle sends blood a short way to the low-pressure pulmonary circuit, but the left ventricle must drive blood through the entire high-pressure systemic circulation. Generating that greater pressure requires a thicker, stronger muscular wall. Both ventricles eject similar volumes, so it is pressure, not volume, that explains the wall difference." },
    { dok:3, q:"The fossa ovalis is a small depression in the wall between the two atria. Why does this structure exist in the adult heart?", a:"It is the remnant of a fetal opening that let blood bypass the non-working lungs before birth.", options:["It is a valve that opens during every adult heartbeat.","It is the remnant of a fetal opening that let blood bypass the non-working lungs before birth.","It is a defect that always causes disease in adults.","It is the site where the heart's electrical signal begins."], correctIndex:1, explanation:"Before birth the lungs are collapsed and not used, so the foramen ovale let blood pass directly from the right atrium to the left, skipping the pulmonary circuit. After birth the lungs inflate and the opening normally seals, leaving the fossa ovalis as a scar-like depression. It is not an active valve, the pacemaker site, or inherently a disease." },
    { dok:3, q:"Heart valves open and close passively based on pressure differences rather than muscular effort. Why does this passive design reliably keep blood moving one way?", a:"Valves open toward lower pressure and snap shut when pressure reverses, so flow is allowed only in the forward direction.", options:["Valves are pulled open and closed by nerves timed to each beat.","Valves open toward lower pressure and snap shut when pressure reverses, so flow is allowed only in the forward direction.","Valves stay open at all times, and direction is set elsewhere.","Valves move blood by contracting like small muscles."], correctIndex:1, explanation:"Each valve is a one-way gate driven by the pressure on either side. When upstream pressure exceeds downstream, the valve opens and blood flows forward, and the instant pressure tries to reverse, the backflow pushes the flaps shut. This simple pressure-driven mechanism enforces one-way flow without nerves or valve muscles." },
    { dok:3, q:"The heart has its own coronary arteries even though its chambers are full of blood. Why can the heart not simply nourish itself from the blood inside its chambers?", a:"The thick wall is too deep for chamber blood to diffuse through, so it needs vessels delivering blood into the muscle.", options:["Chamber blood is the wrong color to feed the muscle.","The thick wall is too deep for chamber blood to diffuse through, so it needs vessels delivering blood into the muscle.","The heart muscle does not need any blood supply of its own.","Chamber blood flows too slowly to ever touch the wall."], correctIndex:1, explanation:"The myocardium is far too thick for oxygen to diffuse inward from the blood passing through the chambers. Only the innermost lining could be fed that way. The coronary arteries solve this by carrying blood into the depth of the muscle, which is why a coronary blockage starves heart tissue despite a chamber full of blood." },
    { dok:3, q:"The sinoatrial node sets the heart rate, and its signal spreads to the atria before reaching the ventricles, with a brief delay at the AV node. Why is the delay between atrial and ventricular contraction useful?", a:"It lets the atria finish emptying into the ventricles before the ventricles contract.", options:["It lets the ventricles contract first and then fill afterward.","It lets the atria finish emptying into the ventricles before the ventricles contract.","It slows the heart so it beats only a few times per minute.","It has no purpose and is simply a flaw in the wiring."], correctIndex:1, explanation:"For an efficient pump, the ventricles should be filled before they squeeze. The AV node delay holds the ventricular signal just long enough for the atria to complete their contraction and top off the ventricles, so the following ventricular contraction ejects a full load. Contracting both at once would waste filling." },
    { dok:3, q:"The pericardium surrounds the heart and contains a thin film of fluid between its layers. Why is this fluid-filled sac important during every heartbeat?", a:"The fluid reduces friction so the constantly moving heart does not abrade against surrounding structures.", options:["The fluid powers the heartbeat by pushing on the heart.","The fluid reduces friction so the constantly moving heart does not abrade against surrounding structures.","The fluid stores the blood that the heart will pump next.","The fluid stops the heart from moving at all."], correctIndex:1, explanation:"The heart beats roughly a hundred thousand times a day, sliding against its surroundings each time. The slippery fluid between pericardial layers lets these surfaces glide with minimal friction, preventing irritation. The fluid does not generate the beat, store pumped blood, or immobilize the heart, which must move to function." },
    { dok:3, q:"In the heart, deoxygenated and oxygenated blood are kept on separate right and left sides by a complete septum. Why is full separation of the two sides important?", a:"It prevents oxygen-poor and oxygen-rich blood from mixing, so the body receives fully oxygenated blood.", options:["It lets the two bloods mix to average their oxygen content.","It prevents oxygen-poor and oxygen-rich blood from mixing, so the body receives fully oxygenated blood.","It slows blood so each side beats at a different time.","Separation has no effect on the oxygen the body receives."], correctIndex:1, explanation:"The right side handles oxygen-poor blood headed to the lungs, and the left side handles oxygen-rich blood headed to the body. A complete septum keeps them apart so the body always gets fully loaded blood. If the two mixed, as in a septal defect, the blood sent to the body would carry less oxygen." }
  ],

  /* ---------- BLOOD VESSELS ---------- */
  "t-blood-vessels": [
    { dok:3, q:"Capillary walls are a single layer of flat endothelial cells, with no muscle or connective layers. Why is this extremely thin wall essential to a capillary's job?", a:"Exchange of gases and nutrients happens by diffusion, and a one-cell wall makes the crossing distance as short as possible.", options:["A thick wall would speed exchange, but capillaries got it wrong.","Exchange of gases and nutrients happens by diffusion, and a one-cell wall makes the crossing distance as short as possible.","The thin wall is for strength against high blood pressure.","The wall is thin so blood can clot inside the capillary."], correctIndex:1, explanation:"Capillaries exist to trade oxygen, carbon dioxide, nutrients, and wastes between blood and tissue, all by diffusion. Diffusion is fast only over tiny distances, so a wall just one flat cell thick minimizes the path and maximizes exchange. Extra layers would slow crossing, and capillaries handle low, not high, pressure." },
    { dok:3, q:"Arteries have thick, elastic, muscular walls, while veins of similar size have thinner walls. Why does this difference match the job each vessel does?", a:"Arteries withstand and smooth the high pressure of blood leaving the heart, while veins carry blood back at low pressure.", options:["Veins carry blood at higher pressure and so need thicker walls.","Arteries withstand and smooth the high pressure of blood leaving the heart, while veins carry blood back at low pressure.","Both carry equal pressure, so the difference is meaningless.","Artery walls are thick only to make them heavier than veins."], correctIndex:1, explanation:"Blood leaves the heart in high-pressure surges, so arteries need thick, elastic, muscular walls to contain the pressure and even out the flow between beats. By the time blood returns through veins the pressure is low, so a thinner wall suffices. The pressure difference, not weight, drives the structural difference." },
    { dok:3, q:"Veins, especially in the legs, contain one-way valves that arteries lack. Why do veins need valves while arteries do not?", a:"Venous blood moves slowly at low pressure, often against gravity, so valves stop it from flowing backward.", options:["Arterial blood is more likely to flow backward and needs valves more.","Venous blood moves slowly at low pressure, often against gravity, so valves stop it from flowing backward.","Valves in veins speed blood up to match arterial pressure.","Valves are present only for decoration and serve no function."], correctIndex:1, explanation:"Arteries carry blood under high pressure that keeps it moving forward, so backflow is not a problem. Venous blood, especially returning up the legs, moves slowly and must fight gravity, so without valves it would pool and slide back. The valves let blood pass toward the heart and then close to block any reverse flow." },
    { dok:3, q:"The smallest arteries, arterioles, have rings of smooth muscle that can tighten or relax. Why does this muscular control matter for the body?", a:"By widening or narrowing, arterioles redirect blood flow to the tissues that need it most.", options:["The muscle exists only to make the arteriole heavier.","By widening or narrowing, arterioles redirect blood flow to the tissues that need it most.","The muscle lets the arteriole make new blood cells.","The muscle stops blood from ever reaching the capillaries."], correctIndex:1, explanation:"Arterioles act as adjustable gates. Tightening their smooth muscle reduces flow into a capillary bed, and relaxing it increases flow, so the body can send more blood to active muscles or digestive organs as needs change. This is why arterioles, not capillaries, are the main control point of blood distribution." },
    { dok:3, q:"The aorta has an especially high proportion of elastic tissue in its wall. Why is this elasticity valuable right where blood leaves the heart?", a:"The aorta stretches to absorb each surge of ejected blood, then recoils to keep blood moving between beats.", options:["The elasticity makes the aorta rigid so it cannot expand.","The aorta stretches to absorb each surge of ejected blood, then recoils to keep blood moving between beats.","Elastic tissue lets the aorta contract like the heart to pump blood.","The elasticity stores oxygen for the heart muscle."], correctIndex:1, explanation:"The heart ejects blood in pulses. The elastic aorta balloons to accept each surge, storing energy, then recoils as the heart relaxes, pushing blood onward so flow continues smoothly between beats. This evens out the pulsatile output into steadier downstream flow. The elastic recoil is passive, not active pumping." },
    { dok:3, q:"Blood flow slows dramatically as it passes through capillary beds compared with arteries. Why is slow flow through capillaries actually beneficial?", a:"Slow flow gives more time for substances to diffuse between blood and tissue.", options:["Slow flow means the capillaries are diseased and failing.","Slow flow gives more time for substances to diffuse between blood and tissue.","Slow flow prevents any exchange from happening.","Capillaries actually have the fastest flow in the body."], correctIndex:1, explanation:"Capillaries are where exchange happens, and diffusion takes time. The huge combined cross-section of many capillaries slows the blood, giving oxygen, nutrients, and wastes more time to cross the thin walls. Fast flow would rush blood past before exchange completed, so the slowing is by design, not failure." },
    { dok:3, q:"Atherosclerotic plaque narrows the inside of an artery over time. Based on vessel structure, why does this narrowing threaten the tissue downstream?", a:"A narrower channel reduces blood flow, so the tissue beyond it receives less oxygen.", options:["A narrower channel increases flow, flooding the tissue with oxygen.","A narrower channel reduces blood flow, so the tissue beyond it receives less oxygen.","Plaque has no effect because blood simply passes through it.","Narrowing only changes the color of the blood, not its delivery."], correctIndex:1, explanation:"An artery delivers oxygenated blood to the tissue it feeds. As plaque narrows the channel, less blood can pass, so the downstream tissue is starved of oxygen, causing pain on exertion or, if blocked completely, tissue death. A narrower pipe carries less, not more, and the consequence is reduced delivery." },
    { dok:3, q:"Capillaries are so narrow that red blood cells pass through almost single file. Why is this tight fit useful rather than a problem?", a:"Forcing cells close to the wall shortens the distance for gas exchange between the cell and the tissue.", options:["The tight fit blocks exchange by trapping the cells.","Forcing cells close to the wall shortens the distance for gas exchange between the cell and the tissue.","The tight fit exists to slow the heart rate.","Red cells avoid capillaries entirely because of the fit."], correctIndex:1, explanation:"When a red blood cell is squeezed almost to the capillary wall, the oxygen it carries has the shortest possible distance to diffuse out to the tissue, and carbon dioxide the shortest distance back in. The narrow fit thus improves exchange efficiency rather than obstructing it." }
  ],

  /* ---------- ANATOMICAL TERMINOLOGY ---------- */
  "t-anatomical-terminology": [
    { dok:3, q:"A nurse in California reads a chart written by a surgeon in New York describing a wound as on the lateral, distal arm. Why can the nurse locate it exactly without ever seeing the original patient position?", a:"Directional terms are defined from a fixed anatomical position, so they mean the same thing to everyone everywhere.", options:["The terms describe the patient's current posture, which both clinicians share.","Directional terms are defined from a fixed anatomical position, so they mean the same thing to everyone everywhere.","Lateral and distal are approximate, so close agreement is luck.","The chart includes a photograph that makes the words unnecessary."], correctIndex:1, explanation:"Every directional term assumes the body is in standard anatomical position, a single agreed reference. Because both clinicians use that same baseline, lateral and distal carry one unambiguous meaning regardless of how the patient is actually lying, which is the whole point of a standardized vocabulary." },
    { dok:3, q:"Why would describing a structure as above the heart be risky in a surgical note, while saying superior to the heart is safe?", a:"Above depends on body position, but superior is fixed to anatomical position and does not change when the patient lies down.", options:["Above and superior mean opposite things in medicine.","Above depends on body position, but superior is fixed to anatomical position and does not change when the patient lies down.","Above is more precise because it is an everyday word.","There is no difference, so either term is equally safe."], correctIndex:1, explanation:"In everyday language above shifts with how the body is oriented, so in a supine patient it becomes ambiguous. Superior is locked to anatomical position and always means toward the head, so it stays correct no matter the posture. Anatomical terms are precise exactly because they do not drift with position." },
    { dok:3, q:"A tumor must be reached with the least cutting through other organs. Knowing it lies in the retroperitoneal space behind the abdominal lining, why might a surgeon approach from the back rather than the front?", a:"A retroperitoneal organ sits behind the peritoneum, so a posterior approach avoids opening the peritoneal cavity and its organs.", options:["Retroperitoneal means in front, so the back approach is wrong.","A retroperitoneal organ sits behind the peritoneum, so a posterior approach avoids opening the peritoneal cavity and its organs.","The position of the organ has no bearing on the approach.","A back approach is always used for every abdominal organ."], correctIndex:1, explanation:"Retroperitoneal structures lie behind the peritoneal membrane, between it and the back wall. Reaching them from the front would mean cutting through the peritoneum and the organs it surrounds, while a posterior route reaches them more directly with less disturbance, which is why position guides the surgical approach." },
    { dok:3, q:"Two students argue over whether the thumb is medial or lateral. In correct anatomical position, why is the thumb the lateral digit of the hand?", a:"Anatomical position has palms facing forward, which places the thumb on the outer, lateral side away from the midline.", options:["The thumb is medial because it is the strongest finger.","Anatomical position has palms facing forward, which places the thumb on the outer, lateral side away from the midline.","Medial and lateral cannot be applied to fingers at all.","The thumb is lateral only when the palm faces backward."], correctIndex:1, explanation:"With the forearm supinated and palms forward, as anatomical position requires, the thumb points away from the midline, making it lateral. If you let the hand rotate, the thumb could appear medial, which is exactly why all such terms are referenced to the fixed position rather than to a casual hand posture." },
    { dok:3, q:"A radiologist needs an image that shows both the left and right lungs side by side in one slice. Which plane should the scan use, and why?", a:"A frontal (coronal) plane, because it separates front from back and shows left and right structures together.", options:["A transverse plane, because it shows only one lung at a time.","A frontal (coronal) plane, because it separates front from back and shows left and right structures together.","A midsagittal plane, because it passes between the two lungs.","No single plane can show both lungs."], correctIndex:1, explanation:"A frontal plane runs vertically and divides the body into anterior and posterior portions, so a single coronal slice can display left and right lungs side by side. A midsagittal cut would pass between them showing neither well, and a transverse slice shows a horizontal cross-section. The imaging goal dictates the plane." },
    { dok:3, q:"Why is it more useful to chart a laceration as anterior to the midaxillary line rather than just on the side of the chest?", a:"A named reference line gives a precise, reproducible location, while side of the chest is vague.", options:["The two phrases are equally precise.","A named reference line gives a precise, reproducible location, while side of the chest is vague.","Side of the chest is the official medical term and the line is informal.","Reference lines are decorative and add no precision."], correctIndex:1, explanation:"Anatomical reference lines such as the midaxillary line are agreed landmarks, so describing a wound relative to one lets any clinician find the same spot. Side of the chest could mean many places. Precise localization matters for documentation, follow-up, and communicating across a care team." },
    { dok:3, q:"A patient's left arm is paralyzed after a stroke on the right side of the brain. Why does a clinician describe the brain injury and the paralysis as contralateral?", a:"Contralateral means opposite sides, and a right-brain injury affecting the left body fits that crossed relationship.", options:["Contralateral means the same side, matching right brain and right arm.","Contralateral means opposite sides, and a right-brain injury affecting the left body fits that crossed relationship.","Contralateral describes front-to-back relationships only.","The term is wrong because brain and arm cannot be compared."], correctIndex:1, explanation:"Contralateral specifies that two findings are on opposite sides of the body. A lesion on the right controlling movement on the left is a crossed, contralateral pattern, which is common because many motor pathways cross. The single word captures that left-right relationship precisely for the record." },
    { dok:3, q:"Why does the abdominopelvic region get divided into nine named regions or four quadrants rather than being described as just the belly?", a:"Subdividing the area lets clinicians localize pain or organs to a specific zone, narrowing the likely cause.", options:["The divisions are tradition only and carry no clinical use.","Subdividing the area lets clinicians localize pain or organs to a specific zone, narrowing the likely cause.","The belly contains no organs worth localizing.","Nine regions and four quadrants describe completely different body areas."], correctIndex:1, explanation:"Mapping the abdomen into regions or quadrants ties a symptom to the organs that lie there, so right lower quadrant pain raises suspicion of the appendix, for example. A single label of belly would lose that diagnostic power. The grid turns a vague area into specific, organ-linked zones." }
  ],

  /* ---------- BODY CAVITIES AND MEMBRANES ---------- */
  "t-body-cavities": [
    { dok:3, q:"Serous membranes such as the pleura secrete a thin fluid into the space between their two layers. Why is this fluid essential as the lungs expand and recoil thousands of times a day?", a:"The fluid lets the two membrane layers slide over each other with little friction during breathing.", options:["The fluid glues the lung to the chest wall so it cannot move.","The fluid lets the two membrane layers slide over each other with little friction during breathing.","The fluid inflates the lung by filling the space with air.","The fluid carries oxygen directly into the lung tissue."], correctIndex:1, explanation:"A serous membrane has two layers with a fluid film between them. During breathing the lung surface and chest wall surface must glide past each other constantly, and the serous fluid reduces friction so this happens smoothly. It does not inflate the lung or carry oxygen, and it allows movement rather than gluing the surfaces." },
    { dok:3, q:"The brain and spinal cord sit within the dorsal cavity, surrounded by bone. Why is a bony enclosure suited to these organs specifically?", a:"Nervous tissue is soft and easily damaged, so rigid bone shields it from impact.", options:["Bone supplies the brain with oxygen directly.","Nervous tissue is soft and easily damaged, so rigid bone shields it from impact.","Bone lets the brain expand and contract with each thought.","The brain produces bone, so it must be surrounded by it."], correctIndex:1, explanation:"The brain and spinal cord are delicate and cannot regenerate well, so the skull and vertebral column form a hard case that absorbs and deflects mechanical force. The ventral cavity organs, which must change volume, get more flexible coverings instead. Form follows the need for protection here." },
    { dok:3, q:"The heart sits in its own pericardial sac within the mediastinum, separate from the lungs' pleural sacs. Why is it useful that each organ has its own serous cavity rather than sharing one large space?", a:"Separate cavities let each organ move independently and limit the spread of infection or fluid between them.", options:["Separate cavities make the organs heavier and easier to find.","Separate cavities let each organ move independently and limit the spread of infection or fluid between them.","Sharing one cavity would make breathing and heartbeat faster.","The separation has no functional benefit at all."], correctIndex:1, explanation:"Giving the heart and each lung their own serous sac means each can move on its own schedule without dragging the others, and a problem like infection or fluid buildup in one sac is contained rather than flooding the whole chest. Compartmentalization protects function and limits spread." },
    { dok:3, q:"The diaphragm separates the thoracic cavity from the abdominopelvic cavity. Beyond dividing the trunk, why is this muscular partition important to breathing?", a:"Its contraction enlarges the thoracic cavity, drawing air into the lungs.", options:["It seals the lungs so no air can ever enter them.","Its contraction enlarges the thoracic cavity, drawing air into the lungs.","It pumps blood from the abdomen to the chest.","It has no role in breathing and only divides organs."], correctIndex:1, explanation:"The diaphragm is both a divider and the main breathing muscle. When it contracts and flattens, the thoracic cavity expands, lowering pressure so air flows into the lungs. So this partition does double duty, separating cavities and actively driving inhalation, which a passive sheet could not do." },
    { dok:3, q:"Abdominal organs are described as either intraperitoneal or retroperitoneal. Why does knowing which category an organ falls into matter to a surgeon?", a:"It tells the surgeon whether reaching the organ means entering the peritoneal cavity or approaching from behind it.", options:["It tells the surgeon the organ's color before cutting.","It tells the surgeon whether reaching the organ means entering the peritoneal cavity or approaching from behind it.","The category determines the patient's blood type.","Both categories mean the organ floats freely in fluid."], correctIndex:1, explanation:"Intraperitoneal organs are wrapped in peritoneum within the cavity, while retroperitoneal organs lie behind it against the back wall. The category guides the safest approach and which structures will be encountered, so it directly shapes surgical planning rather than being a trivial label." },
    { dok:3, q:"Inflammation of a serous membrane, such as pleurisy, makes breathing sharply painful. Based on the membrane's normal job, why does inflammation cause pain with movement?", a:"Inflamed surfaces lose their smooth glide and rub against each other as the lung moves.", options:["Inflammation fills the lung with extra serous fluid that feels good.","Inflamed surfaces lose their smooth glide and rub against each other as the lung moves.","Pain comes from the membrane growing new bone.","The membrane stops the lung from moving, which is painless."], correctIndex:1, explanation:"Normally serous fluid lets pleural layers slide painlessly. When the membrane inflames, the surfaces become roughened and may have less effective lubrication, so each breath drags them against each other, producing the sharp, movement-linked pain of pleurisy. The symptom follows directly from the lost low-friction glide." },
    { dok:3, q:"The thoracic cavity is more rigidly enclosed by the rib cage, while the abdominal cavity wall is mostly muscle. Why does this difference in wall stiffness suit the organs each contains?", a:"The rib cage protects the heart and lungs and aids breathing, while a flexible abdominal wall lets digestive organs expand after meals.", options:["The rib cage protects the heart and lungs and aids breathing, while a flexible abdominal wall lets digestive organs expand after meals.","A rigid abdomen would digest food faster than a flexible one.","Both walls are equally rigid, so the premise is false.","Muscle walls cannot protect organs at all, so the abdomen is unprotected."], correctIndex:0, explanation:"Vital, constantly moving heart and lungs benefit from a bony cage that shields them and changes volume for breathing. Digestive organs need room to swell as they fill, so a muscular, distensible wall accommodates that change. Each wall design matches the behavior of the organs it surrounds." },
    { dok:3, q:"A buildup of fluid in the pericardial sac can compress the heart, a condition called tamponade. Using the structure of the sac, why does fluid there threaten the heart's pumping?", a:"The tough sac cannot stretch quickly, so accumulating fluid raises pressure that squeezes the heart and limits filling.", options:["The fluid makes the heart beat stronger by pushing on it.","The tough sac cannot stretch quickly, so accumulating fluid raises pressure that squeezes the heart and limits filling.","The fluid drains instantly, so it never affects the heart.","The pericardial sac is open, so fluid cannot collect there."], correctIndex:1, explanation:"The fibrous pericardium resists sudden stretching, so when fluid collects rapidly in the sac the pressure climbs and presses inward on the heart. The chambers cannot fill fully, and output drops. The very toughness that normally protects the heart becomes the reason trapped fluid is dangerous." }
  ],

  /* ---------- CELL ANATOMY ---------- */
  "t-cell-anatomy": [
    { dok:3, q:"A cell that makes and exports large amounts of protein, such as a digestive gland cell, is packed with rough endoplasmic reticulum. Why does heavy protein export demand abundant rough ER?", a:"Ribosomes on the rough ER make proteins destined for export, so high output needs a lot of it.", options:["Rough ER stores the finished protein permanently inside the cell.","Ribosomes on the rough ER make proteins destined for export, so high output needs a lot of it.","Rough ER breaks down proteins the cell wants to discard.","Rough ER has no link to protein and only stores water."], correctIndex:1, explanation:"The ribosomes studding rough ER synthesize proteins that will be packaged and secreted. A cell whose job is large-scale protein export must run a big production line, so it carries extensive rough ER. Cells that export little have far less, matching organelle abundance to the cell's workload." },
    { dok:3, q:"Cells that are highly active, such as muscle and liver cells, contain very large numbers of mitochondria. Why does high activity track with mitochondrial number?", a:"Mitochondria produce usable energy, so cells doing more work need more of them.", options:["Mitochondria store the cell's genetic blueprint for activity.","Mitochondria produce usable energy, so cells doing more work need more of them.","Mitochondria slow the cell down, so active cells avoid them.","Mitochondria are present only in cells that never work."], correctIndex:1, explanation:"Mitochondria are the cell's main energy producers. A cell with high energy demands, like a contracting muscle fiber or a metabolically busy liver cell, needs many mitochondria to keep up. Counting mitochondria roughly indicates how energy-hungry a cell is, since organelle number scales with demand." },
    { dok:3, q:"The plasma membrane is a phospholipid bilayer with water-fearing tails facing inward. Why does this arrangement make the membrane a selective barrier?", a:"The oily interior blocks water-soluble substances, so only certain molecules cross freely while others need transport help.", options:["The oily interior lets everything pass equally and quickly.","The oily interior blocks water-soluble substances, so only certain molecules cross freely while others need transport help.","The arrangement makes the membrane fully solid and impassable.","The tails face outward, so the membrane dissolves in water."], correctIndex:1, explanation:"Because the bilayer's core is oily and water-repelling, small nonpolar molecules slip through while charged or water-loving substances are held back and must use channels or carriers. This selective permeability lets the cell control its internal environment, which a freely permeable or totally sealed barrier could not do." },
    { dok:3, q:"The nucleus is wrapped in a double membrane studded with pores rather than being sealed shut. Why are these pores necessary?", a:"They let large molecules like RNA leave the nucleus and needed proteins enter, while still containing the DNA.", options:["They let the DNA leak out into the cytoplasm constantly.","They let large molecules like RNA leave the nucleus and needed proteins enter, while still containing the DNA.","They allow the nucleus to fill completely with water.","They serve no purpose and weaken the nucleus."], correctIndex:1, explanation:"The genetic instructions stay in the nucleus, but the messages copied from them, and the proteins that act on DNA, must cross the envelope. Nuclear pores are regulated gateways that allow this two-way traffic of large molecules while keeping the chromosomes safely inside. A sealed envelope would trap the instructions uselessly." },
    { dok:3, q:"Lysosomes are membrane-bound sacs full of digestive enzymes. Why is it important that these enzymes are kept inside a membrane rather than loose in the cytoplasm?", a:"The membrane confines the destructive enzymes so they digest only targeted material and not the whole cell.", options:["The membrane keeps the enzymes cold so they work slowly.","The membrane confines the destructive enzymes so they digest only targeted material and not the whole cell.","The membrane has no role, since the enzymes are harmless.","The membrane makes the enzymes, then releases them everywhere."], correctIndex:1, explanation:"Lysosomal enzymes break down worn parts and engulfed material, and if loose they could digest the cell's own structures. Sealing them in a membrane lets the cell deliver them only to what should be destroyed. This containment is why a ruptured lysosome can damage the cell, underscoring the membrane's protective role." },
    { dok:3, q:"Microvilli are tiny folds that greatly increase the surface of cells lining the small intestine. Why does that extra surface matter where it is found?", a:"More surface area means more room for absorbing nutrients from digested food.", options:["More surface area makes the cells secrete acid faster.","More surface area means more room for absorbing nutrients from digested food.","More surface area slows absorption to protect the cell.","Microvilli reduce surface area to limit nutrient uptake."], correctIndex:1, explanation:"Absorption happens across the cell surface, so folding the membrane into countless microvilli multiplies the area available to take in nutrients. In the intestine, where efficient uptake is the goal, this hugely increases capacity. Structure again matches function, with extra surface placed exactly where absorption is the job." },
    { dok:3, q:"The Golgi apparatus receives proteins from the ER, modifies them, and ships them in vesicles. Why is its position and packaging role described as the cell's shipping department?", a:"It sorts and tags finished products and dispatches them to the right destination, like a shipping hub.", options:["It manufactures all proteins from scratch using its own ribosomes.","It sorts and tags finished products and dispatches them to the right destination, like a shipping hub.","It destroys every protein that the ER makes.","It stores DNA and copies it for the cell."], correctIndex:1, explanation:"The Golgi takes proteins delivered from the ER, refines and labels them, then packs them into vesicles addressed for the membrane, secretion, or other organelles. That receive, finish, and dispatch sequence is exactly what a shipping department does, which is why the analogy fits its role." },
    { dok:3, q:"A red blood cell loses its nucleus as it matures, while a neuron keeps its nucleus for life. Why does this difference make sense given each cell's job?", a:"A red cell needs maximum room for oxygen carriers and does not divide, while a neuron must keep directing protein synthesis to maintain itself.", options:["A red cell needs maximum room for oxygen carriers and does not divide, while a neuron must keep directing protein synthesis to maintain itself.","A neuron does not need its nucleus and keeps it by accident.","Both cells should keep their nuclei, so the red cell is defective.","The nucleus carries oxygen, so the red cell should keep it."], correctIndex:0, explanation:"Ejecting the nucleus frees space in the red cell for hemoglobin and lets it flex through capillaries, and since it will not divide or rebuild, it can manage without one for its short life. A neuron must last decades and constantly remake its components, so it needs the nucleus directing that ongoing work." }
  ],

  /* ---------- AXIAL SKELETON: SKULL ---------- */
  "t-axial-skeleton-skull": [
    { dok:3, q:"The bones of an infant's skull are joined by soft fibrous fontanelles rather than fused sutures. Why is this unfused design important both at birth and in early life?", a:"It lets the skull compress during birth and then expand as the brain grows.", options:["It lets the skull compress during birth and then expand as the brain grows.","It makes the infant skull heavier for stability.","It prevents the brain from growing until the bones fuse.","It allows the skull bones to slide off during feeding."], correctIndex:0, explanation:"Flexible fontanelles allow the skull plates to overlap slightly as the head passes through the birth canal, and afterward they leave room for the rapidly growing brain to enlarge the skull. Fully fused bones at birth would obstruct delivery and constrain brain growth, so the soft spots serve both purposes." },
    { dok:3, q:"The cranial bones meet at immovable interlocking sutures. Why is an immovable joint the right choice for the bones surrounding the brain?", a:"Rigid, locked joints form a stable protective case that resists forces from any direction.", options:["Rigid, locked joints form a stable protective case that resists forces from any direction.","Movable joints would let the brain expand and contract with thinking.","Sutures must move so the skull can breathe.","Immovable joints make the skull lighter than movable ones would."], correctIndex:0, explanation:"The skull's job around the brain is protection, and a box whose seams cannot shift is far stronger against impact than one with movable joints. The jagged, interlocking sutures knit the plates into a single rigid vault, which is exactly what shielding delicate nervous tissue requires." },
    { dok:3, q:"Many skull bones, such as the maxillae and frontal bone, contain hollow air-filled sinuses. Why is a hollow design advantageous for these bones?", a:"The cavities lighten the skull while keeping its outer strength, and they add resonance to the voice.", options:["The cavities make the skull much heavier and denser.","The cavities lighten the skull while keeping its outer strength, and they add resonance to the voice.","The cavities store extra blood for the brain.","The cavities exist only to collect infection."], correctIndex:1, explanation:"Air-filled sinuses remove bone mass from regions that do not need to be solid, lightening the head so the neck supports it more easily, while the surrounding walls keep enough strength. They also give the voice resonance. Their tendency to harbor infection is a side effect, not their purpose." },
    { dok:3, q:"The foramen magnum is a large opening in the occipital bone at the base of the skull. Why must an opening of this size exist there specifically?", a:"It is where the brainstem connects to the spinal cord, so the cord must pass through the skull base.", options:["It is where the brainstem connects to the spinal cord, so the cord must pass through the skull base.","It is where food enters the skull from the mouth.","It is a weak spot that serves no function.","It lets the brain drain excess bone."], correctIndex:0, explanation:"The central nervous system is continuous, with the brainstem passing into the spinal cord. The foramen magnum is the large hole at the skull base that this junction passes through, connecting brain to cord. Its size and location are dictated by the structure that must traverse it." },
    { dok:3, q:"The mandible is the only freely movable bone of the skull, meeting the temporal bone at the temporomandibular joint. Why does the jaw need a movable joint while the rest of the skull does not?", a:"Chewing and speaking require the lower jaw to move, unlike the protective bones around the brain.", options:["Chewing and speaking require the lower jaw to move, unlike the protective bones around the brain.","The mandible moves to let the brain expand.","All skull bones move equally, so the mandible is not special.","The jaw must move to circulate cerebrospinal fluid."], correctIndex:0, explanation:"Eating and talking depend on opening, closing, and grinding motions of the lower jaw, which demand a true movable joint. The cranial bones, by contrast, exist to protect and need to stay fixed. The mandible's mobility matches its active mechanical role, distinct from the static braincase." },
    { dok:3, q:"The ethmoid bone has a perforated plate, the cribriform plate, through which smell nerves pass. Why does this thin, hole-filled bone create a risk after a hard blow to the head?", a:"Its many perforations and thinness make it easy to fracture, which can tear the nerves or leak cerebrospinal fluid.", options:["Its many perforations and thinness make it easy to fracture, which can tear the nerves or leak cerebrospinal fluid.","It is the thickest skull bone and never breaks.","Perforations make it stronger than solid bone.","The plate has no nerves passing through it."], correctIndex:0, explanation:"The cribriform plate is delicate and riddled with holes for olfactory nerve fibers, so a forceful impact can crack it. That can shear the smell nerves, causing loss of smell, and breach the barrier so cerebrospinal fluid leaks into the nose. The very design that lets smell nerves pass makes it vulnerable." },
    { dok:3, q:"The orbit that holds the eye is formed from parts of several different skull bones rather than one. Why might a single direct blow to the eye socket cause a fracture in a thin floor region called a blowout fracture?", a:"The orbital floor is a thin shared wall, so a sudden pressure spike breaks the weakest part rather than the sturdy rim.", options:["The orbital floor is a thin shared wall, so a sudden pressure spike breaks the weakest part rather than the sturdy rim.","The eye socket is solid bone with no weak areas.","The blow strengthens the floor by compressing it.","The orbit is made of cartilage that cannot fracture."], correctIndex:0, explanation:"The orbit is a composite cavity whose floor is a thin plate. A blunt blow that raises pressure inside the socket transmits force to the weakest surface, the thin floor, which gives way while the thick rim stays intact. Understanding which wall is thinnest predicts where it fails." },
    { dok:3, q:"The temporal bone houses the delicate structures of the inner ear deep within its dense petrous portion. Why is the inner ear placed inside the hardest part of the skull?", a:"The fragile hearing and balance organs need the protection of very dense surrounding bone.", options:["The fragile hearing and balance organs need the protection of very dense surrounding bone.","Dense bone amplifies sound better than soft tissue.","The inner ear makes bone, so it sits inside it.","The location is random and unrelated to protection."], correctIndex:0, explanation:"The inner ear's sensory structures are tiny and irreplaceable, so the body encloses them in the petrous portion, the densest bone in the skull. This hard casing shields the hearing and balance organs from damage. Placement in the toughest bone reflects how vital and vulnerable these structures are." }
  ],

  /* ---------- AXIAL SKELETON: SPINE ---------- */
  "t-axial-skeleton-spine": [
    { dok:3, q:"The vertebral column has four curves rather than being a straight rod. Why do these curves make the spine better at its job than a straight column would be?", a:"The curves act like springs, absorbing shock and distributing weight during standing and walking.", options:["The curves act like springs, absorbing shock and distributing weight during standing and walking.","The curves make the spine weaker so it bends more easily.","A straight spine would absorb shock better than curves.","The curves exist only to make a person taller."], correctIndex:0, explanation:"A curved column flexes and rebounds under load like a spring, cushioning the jolts of walking and balancing the body's weight over its base. A straight rod would transmit impact directly upward to the skull. The S-shaped curvature is a mechanical adaptation for upright, shock-absorbing support." },
    { dok:3, q:"Lumbar vertebrae have much larger, thicker bodies than cervical vertebrae. Why does the size increase from neck to lower back make functional sense?", a:"Lower vertebrae bear more of the body's weight, so larger bodies are needed to support the load.", options:["Lower vertebrae bear more of the body's weight, so larger bodies are needed to support the load.","Cervical vertebrae carry more weight and should be larger.","Vertebral size is random along the column.","Larger lumbar bodies make the spine more flexible than the neck."], correctIndex:0, explanation:"Weight accumulates down the spine, so the lumbar vertebrae support the head, arms, and trunk above them, far more than the cervical vertebrae carry. Their bigger, sturdier bodies spread that greater load. The progressive enlargement directly tracks the increasing weight each level must bear." },
    { dok:3, q:"Between the vertebral bodies sit intervertebral discs with a soft gel center and a tough outer ring. Why does this two-part construction suit the disc's role?", a:"The gel center absorbs and redistributes pressure while the tough ring contains it and resists tearing.", options:["The gel center absorbs and redistributes pressure while the tough ring contains it and resists tearing.","The gel center makes the disc rigid and immovable.","The tough ring carries blood into the spinal cord.","Both layers are identical, so the structure is pointless."], correctIndex:0, explanation:"When the spine is loaded, the gelatinous core squashes and spreads the force evenly, cushioning the bones, while the fibrous outer ring holds the gel in place and withstands the resulting tension. The pairing gives both shock absorption and containment, which is why a torn ring lets the core herniate." },
    { dok:3, q:"The first cervical vertebra, the atlas, lacks a body and forms a ring that lets the skull nod. Why is this ring shape suited to its position?", a:"The ring cradles the skull and allows the yes nodding motion while making room for the spinal cord.", options:["The ring cradles the skull and allows the yes nodding motion while making room for the spinal cord.","The ring stores cerebrospinal fluid for the brain.","The missing body makes the atlas the strongest vertebra.","The ring shape prevents any head movement."], correctIndex:0, explanation:"The atlas is built to support and pivot the head. Its open ring receives the rounded occipital condyles so the skull can rock forward and back to nod yes, and the wide opening leaves space for the spinal cord. The shape is tailored to bearing and moving the skull, not to strength or fluid storage." },
    { dok:3, q:"The second cervical vertebra, the axis, has an upward peg called the dens that the atlas rotates around. Why is this peg-and-ring arrangement important?", a:"It lets the head turn side to side, the no motion, by allowing the atlas and skull to pivot on the dens.", options:["It lets the head turn side to side, the no motion, by allowing the atlas and skull to pivot on the dens.","It locks the head so it cannot rotate at all.","The dens carries the spinal cord upward into the skull.","The peg exists only to make the vertebra heavier."], correctIndex:0, explanation:"The dens projects up into the atlas's ring and serves as a pivot, so the atlas, carrying the skull, can rotate around it to turn the head left and right. This specialized joint is why we can shake our head no. The structure exists specifically to permit that rotational movement." },
    { dok:3, q:"Thoracic vertebrae have special facets on their bodies and transverse processes that cervical and lumbar vertebrae lack. Why are these extra facets present only in the thoracic region?", a:"They form joints with the ribs, which attach only along the thoracic spine.", options:["They form joints with the ribs, which attach only along the thoracic spine.","They make the thoracic vertebrae lighter than the others.","They are leftover features with no function.","They attach the thoracic vertebrae to the skull."], correctIndex:0, explanation:"Ribs articulate with the vertebral column only in the thoracic region, and those articulations need joint surfaces. The thoracic vertebrae therefore carry costal facets that the rib heads and tubercles meet. Cervical and lumbar vertebrae have no ribs to join, so they lack these facets, matching structure to attachment." },
    { dok:3, q:"The sacrum is formed from five vertebrae fused into one solid bone. Why is fusion advantageous at this location rather than keeping separate movable vertebrae?", a:"A fused sacrum gives a strong, stable base that transfers body weight to the pelvis and legs.", options:["A fused sacrum gives a strong, stable base that transfers body weight to the pelvis and legs.","Fusion makes the lower spine more flexible for twisting.","Separate vertebrae would carry weight better than a fused bone.","The sacrum fuses only to make the spine longer."], correctIndex:0, explanation:"The sacrum is the keystone that passes the weight of the upper body into the pelvic girdle and down to the legs. A single fused block provides the rigidity and strength that this load transfer demands, where mobility would be a liability. Stability, not flexibility, is the priority at the spine's base." },
    { dok:3, q:"The spinal cord runs through the vertebral foramina, the openings stacked along the column. Why is it important that these openings line up into a continuous canal?", a:"The aligned canal forms a bony tunnel that protects the spinal cord along its whole length.", options:["The aligned canal forms a bony tunnel that protects the spinal cord along its whole length.","The canal carries food down to the stomach.","The openings must misalign to let nerves escape.","The canal exists to lighten the vertebrae."], correctIndex:0, explanation:"Each vertebra contributes a ring, and stacked together they create a continuous protective tunnel around the spinal cord, much as the skull guards the brain. If the foramina did not align, the cord would be exposed. Nerves exit through separate side openings, leaving the main canal as a continuous shield." }
  ],

  /* ---------- APPENDICULAR SKELETON: UPPER LIMB ---------- */
  "t-appendicular-skeleton-upper": [
    { dok:3, q:"The pectoral girdle attaches to the axial skeleton only at the small sternoclavicular joint, leaving the shoulder blade fairly free. Why does this loose attachment benefit the upper limb?", a:"It lets the shoulder move through a wide range, giving the arm great mobility.", options:["It lets the shoulder move through a wide range, giving the arm great mobility.","It makes the shoulder the most stable joint in the body.","It locks the arm in place for heavy lifting.","It prevents the arm from moving away from the body."], correctIndex:0, explanation:"With only one bony link to the trunk and a scapula that glides over the back, the pectoral girdle trades firmness for freedom. This lets the shoulder and arm reach in nearly every direction. The cost is reduced stability, but for a limb meant to manipulate the world, wide mobility is the priority." },
    { dok:3, q:"The clavicle is one of the most commonly broken bones, sitting just under the skin across the top of the chest. Why does its exposed position and role make it prone to fracture?", a:"It braces the shoulder and transmits force from the arm to the trunk, so a fall on an outstretched arm loads it heavily.", options:["It braces the shoulder and transmits force from the arm to the trunk, so a fall on an outstretched arm loads it heavily.","It is buried deep in muscle and rarely takes any force.","It carries no load and breaks for no reason.","It is made of cartilage that snaps easily."], correctIndex:0, explanation:"The clavicle acts as a strut holding the shoulder out from the body and channels force between the arm and the axial skeleton. When someone falls onto an outstretched hand, that force travels up the arm and concentrates in the slender, superficial clavicle, which often fails, explaining its high fracture rate." },
    { dok:3, q:"The humerus fits into the shallow glenoid cavity of the scapula. Why does this shallow socket give the shoulder its enormous range of motion but also its tendency to dislocate?", a:"A shallow socket lets the ball move freely in many directions but holds it less securely.", options:["A shallow socket lets the ball move freely in many directions but holds it less securely.","A shallow socket grips the bone more tightly than a deep one.","The socket depth has no effect on movement or stability.","A shallow socket prevents all shoulder movement."], correctIndex:0, explanation:"Range and security trade off in a ball-and-socket joint. The glenoid's shallowness frees the humeral head to swing widely, granting the shoulder its mobility, but the same lack of bony containment means the head can slip out under stress. The structure explains both the joint's reach and its instability." },
    { dok:3, q:"The radius and ulna are two parallel forearm bones rather than one. Why is having two bones essential to forearm function?", a:"It allows the radius to rotate over the ulna, turning the palm up and down.", options:["It allows the radius to rotate over the ulna, turning the palm up and down.","Two bones make the forearm completely rigid.","Two bones simply add weight with no benefit.","One bone would rotate better than two."], correctIndex:0, explanation:"Pronation and supination, turning the palm down and up, depend on one bone crossing over the other. The radius pivots around the ulna to produce this rotation, which a single forearm bone could not do. The paired design is what gives the hand its versatile orientation for grasping and manipulating." },
    { dok:3, q:"At the elbow, the humerus and ulna form a hinge that moves in only one plane. Why is a hinge, rather than a ball and socket, appropriate for the elbow?", a:"The elbow needs stable bending and straightening in one plane to position the hand, not multidirectional motion.", options:["The elbow needs stable bending and straightening in one plane to position the hand, not multidirectional motion.","The elbow must rotate in all directions to function.","A ball and socket would make the elbow stronger and is used there.","Hinge joints cannot bear any weight, so the elbow avoids them."], correctIndex:0, explanation:"The elbow's task is to lengthen and shorten the arm's reach by flexing and extending, which a stable one-plane hinge does reliably and strongly. Multidirectional play would make the joint wobbly and weak for lifting and pushing. Forearm rotation is handled separately, so the elbow itself can specialize as a hinge." },
    { dok:3, q:"The wrist contains eight small carpal bones rather than one solid block. Why does breaking the wrist into many small bones help the hand?", a:"Many small bones gliding on each other let the wrist flex, extend, and angle in a flexible yet stable way.", options:["Many small bones gliding on each other let the wrist flex, extend, and angle in a flexible yet stable way.","Many bones make the wrist completely rigid.","A single wrist bone would be more flexible than eight.","The small bones store blood for the hand."], correctIndex:0, explanation:"A cluster of small bones with many joints between them allows movement to be shared across numerous small glides, producing a wrist that bends and tilts smoothly while staying stable under load. One solid bone could not flex this way. Subdividing the wrist trades a single stiff piece for distributed, controllable motion." },
    { dok:3, q:"The thumb's carpometacarpal joint is a saddle joint, unlike the other fingers' joints. Why is this special joint shape critical to human hand function?", a:"It lets the thumb swing across the palm to oppose the fingers, enabling a precise grip.", options:["It lets the thumb swing across the palm to oppose the fingers, enabling a precise grip.","It locks the thumb so it cannot move toward the fingers.","It makes the thumb identical in motion to the other fingers.","The saddle shape only adds bulk with no function."], correctIndex:0, explanation:"Opposition, bringing the thumb across to meet the fingertips, is what makes a precision grip possible, and the saddle joint at the thumb's base provides the two-axis motion that allows it. Without this joint shape the thumb could not oppose, and the hand would lose its defining ability to pinch and grasp finely." },
    { dok:3, q:"The bones of the fingers, the phalanges, are connected by hinge joints between multiple short segments. Why is a multi-segment, hinged finger more useful than a single rigid digit?", a:"Multiple hinges let the finger curl around objects of different shapes for a secure grip.", options:["Multiple hinges let the finger curl around objects of different shapes for a secure grip.","Multiple segments make the finger unable to bend.","A single rigid finger would grip objects better.","The segments exist only to lengthen the finger."], correctIndex:0, explanation:"Several hinge joints along each finger allow it to bend at multiple points and wrap closely around objects of varied shape and size, conforming to what is held. A single straight digit could only poke, not grasp. The segmented, jointed design is what lets fingers form a secure, adaptable grip." }
  ],

  /* ---------- APPENDICULAR SKELETON: LOWER LIMB ---------- */
  "t-appendicular-skeleton-lower": [
    { dok:3, q:"The head of the femur sits deep within the acetabulum of the hip, unlike the shallow shoulder socket. Why does the hip trade some mobility for this deep socket?", a:"The hip bears the body's weight and needs the stability that a deep, secure socket provides.", options:["The hip bears the body's weight and needs the stability that a deep, secure socket provides.","The hip needs more mobility than the shoulder, so it is deeper.","A deep socket makes the hip dislocate more easily than the shoulder.","Socket depth has no effect on stability."], correctIndex:0, explanation:"The hip must support the entire upper body and withstand the forces of standing, walking, and running, so it prioritizes stability. The deep acetabulum grips the femoral head firmly, making the hip far harder to dislocate than the shoulder, at the cost of some range. Weight-bearing drives the trade toward security." },
    { dok:3, q:"The femur is the longest and strongest bone in the body. Why does its location and role demand such strength?", a:"It carries and transmits the full body weight through the thigh during movement, so it must resist large forces.", options:["It carries and transmits the full body weight through the thigh during movement, so it must resist large forces.","It is strong only because it is far from the heart.","The femur bears no weight and is strong by accident.","Its strength is needed to protect the brain."], correctIndex:0, explanation:"The thigh bone bridges the hip and knee and bears the body's weight with every step, plus the amplified forces of running and jumping. Meeting those loads without breaking requires great length and strength, which is why the femur is the body's sturdiest bone. Its build matches the mechanical demand on it." },
    { dok:3, q:"The patella, or kneecap, sits within the tendon in front of the knee. Why does this bone embedded in a tendon improve knee function?", a:"It increases the leverage of the thigh muscle, making knee extension more powerful.", options:["It increases the leverage of the thigh muscle, making knee extension more powerful.","It locks the knee so it cannot straighten.","It carries blood from the thigh to the foot.","It only adds weight and has no mechanical role."], correctIndex:0, explanation:"By sitting in the tendon in front of the joint, the patella holds the tendon farther from the knee's pivot, increasing the leverage with which the quadriceps straightens the leg. This makes extension more forceful and protects the joint. A tendon without this bone would pull with less mechanical advantage." },
    { dok:3, q:"Like the forearm, the lower leg has two bones, the tibia and fibula, but the tibia is much thicker than the fibula. Why does the tibia bear most of the load while the fibula stays slender?", a:"The tibia transmits body weight from the knee to the ankle, while the fibula mainly anchors muscles and stabilizes the ankle.", options:["The tibia transmits body weight from the knee to the ankle, while the fibula mainly anchors muscles and stabilizes the ankle.","The fibula carries all the weight and should be thicker.","Both bones carry equal weight, so their sizes should match.","The thinner fibula bears more force than the tibia."], correctIndex:0, explanation:"In the leg, the heavy tibia is positioned to carry weight straight from the knee to the ankle, so it is robust. The fibula sits to the side, out of the main weight path, serving chiefly as a muscle attachment and ankle stabilizer, so it can be slender. Their sizes reflect their different mechanical jobs." },
    { dok:3, q:"The bones of the foot form arches rather than lying flat. Why is an arched structure better for the foot than a flat platform?", a:"The arches distribute weight and act as springs, absorbing shock and returning energy during walking.", options:["The arches distribute weight and act as springs, absorbing shock and returning energy during walking.","A flat foot absorbs shock far better than arches.","The arches make the foot rigid and unable to flex.","The arches exist only to make the foot look curved."], correctIndex:0, explanation:"Arches spread the body's weight across the foot's contact points and flex under load like springs, cushioning each step and then recoiling to help push off. A flat foot would transmit impact straight up the leg. The arched architecture gives the foot both load distribution and energy-saving spring." },
    { dok:3, q:"The ankle joint allows the foot to move up and down but resists side-to-side motion. Why is this restricted motion appropriate for the ankle?", a:"A stable up-and-down hinge supports body weight during walking while resisting the sideways forces that would cause sprains.", options:["A stable up-and-down hinge supports body weight during walking while resisting the sideways forces that would cause sprains.","Free side-to-side motion would make the ankle stronger.","The ankle should rotate fully like a ball and socket.","Restricting motion serves no protective purpose."], correctIndex:0, explanation:"Walking requires the foot to lever up and down while bearing weight, so a hinge-like ankle provides that motion with stability. Limiting side-to-side movement protects the joint, since excessive sideways force is exactly what tears ankle ligaments. The constrained range matches the need for a stable, weight-bearing platform." },
    { dok:3, q:"The pelvis of a typical female is generally wider with a broader pelvic outlet than a typical male pelvis. Why does this structural difference exist?", a:"A wider outlet accommodates the passage of a baby during childbirth.", options:["A wider outlet accommodates the passage of a baby during childbirth.","A wider pelvis makes walking impossible.","The difference is random and has no function.","A narrower female pelvis would aid childbirth more."], correctIndex:0, explanation:"The female pelvis is shaped to allow a newborn to pass through the pelvic outlet during birth, so it tends to be wider with a larger, rounder opening. This is a structural adaptation to the demands of childbirth, which is why the bony pelvis is one of the clearest skeletal differences between the sexes." },
    { dok:3, q:"The calcaneus, the heel bone, is large and strong and projects backward behind the ankle. Why is this rugged, rearward-projecting bone shaped that way?", a:"It bears the impact of the heel strike and gives the calf tendon leverage to push off.", options:["It bears the impact of the heel strike and gives the calf tendon leverage to push off.","It is large only to make the foot heavier.","It projects backward to store body fat.","It carries no force and could be much smaller."], correctIndex:0, explanation:"The heel bone takes the body's weight at every heel strike, so it must be sturdy. Its backward projection also lengthens the lever arm for the calf tendon, so the calf muscles can lift the heel and push the body forward with greater force. Both the strength and the shape serve walking mechanics." }
  ],

  /* ---------- MUSCLE FASCICLE ARRANGEMENT ---------- */
  "t-muscle-fascicles": [
    { dok:3, q:"A muscle whose fascicles run parallel to its long axis, such as a strap-like muscle, shortens a great deal but with modest force. Why does parallel arrangement favor range over power?", a:"Parallel fibers run the full length of the muscle, so their shortening adds up to a large change in length.", options:["Parallel fibers run the full length of the muscle, so their shortening adds up to a large change in length.","Parallel fibers pack tightly to maximize force at the expense of range.","Parallel arrangement prevents the muscle from shortening at all.","Fiber direction has no effect on range or force."], correctIndex:0, explanation:"In a parallel muscle the fibers run end to end along the whole muscle, so when each shortens, their lengths add up to a big overall shortening and wide range of motion. Because relatively few fibers lie across any cross-section, the force is moderate. The geometry favors distance over strength." },
    { dok:3, q:"A pennate muscle has short fascicles attaching at an angle to a central tendon, like a feather. Why does this design generate more force than a parallel muscle of the same size?", a:"Angled packing fits many more fibers into the same volume, and more fibers pulling means more force.", options:["Angled packing fits many more fibers into the same volume, and more fibers pulling means more force.","Pennate muscles have fewer fibers, which increases force.","The angle removes all force from the muscle.","Pennate and parallel muscles always produce identical force."], correctIndex:0, explanation:"Setting fibers at an angle to the tendon lets far more of them pack into a given volume than running them straight through. Since the force a muscle produces depends on how many fibers cross its functional axis, this dense packing yields greater strength, though each fiber's angled pull and shorter length reduce range." },
    { dok:3, q:"The deltoid muscle of the shoulder is multipennate and built for powerful, varied arm movements. Why does a joint requiring strength in many directions favor a pennate design?", a:"Pennate packing provides the high force such movements demand within a compact muscle.", options:["Pennate packing provides the high force such movements demand within a compact muscle.","Pennate muscles are weak, so they suit gentle motion only.","The shoulder needs maximum range, not force, so pennate is wrong.","Muscle architecture is unrelated to the forces a joint needs."], correctIndex:0, explanation:"Lifting and moving the arm against gravity and loads takes considerable force, and a multipennate muscle packs many fibers into a manageable size to deliver it. The deltoid's architecture is matched to the strength its job requires, illustrating how fascicle arrangement is tuned to a muscle's mechanical demands." },
    { dok:3, q:"A circular muscle, such as a sphincter, has fascicles arranged in rings around an opening. Why is this ring arrangement ideal for controlling a passage?", a:"Contracting the ring narrows or closes the opening, acting as a valve.", options:["Contracting the ring narrows or closes the opening, acting as a valve.","Contracting the ring widens the opening permanently.","Ring arrangement prevents the muscle from contracting.","Circular fibers move a bone like a lever."], correctIndex:0, explanation:"When the concentric fibers of a sphincter shorten, the ring tightens and the central opening closes or narrows, controlling what passes through, as at the mouth or the openings of the digestive and urinary tracts. The circular geometry turns muscle contraction into a valve, a job that parallel or pennate muscles could not do." },
    { dok:3, q:"A convergent muscle, such as the pectoralis major, has a broad origin that narrows to a single tendon. Why does this fan shape give the muscle versatility?", a:"Different parts of the broad muscle can pull in slightly different directions on the same tendon.", options:["Different parts of the broad muscle can pull in slightly different directions on the same tendon.","The narrow tendon prevents the muscle from moving the bone.","Convergent muscles can only ever pull in one fixed direction.","The fan shape stores fat rather than producing movement."], correctIndex:0, explanation:"Because a convergent muscle spreads over a wide origin but inserts at one point, activating its upper, middle, or lower fibers pulls the insertion in different directions. This lets one muscle perform several related movements, giving the broad, fan-shaped pectoralis its versatility at the shoulder." },
    { dok:3, q:"The same biceps contraction produces a large movement at the hand but the muscle itself shortens only a little. Why does a small muscle shortening create a large movement at the end of the limb?", a:"The muscle inserts near the joint, so its short pull is amplified into a wide arc at the far end of the lever.", options:["The muscle inserts near the joint, so its short pull is amplified into a wide arc at the far end of the lever.","The muscle shortens far more than the hand moves.","Levers in the body reduce all movement to nothing.","The hand moves only because a separate muscle pushes it."], correctIndex:0, explanation:"The forearm acts as a lever pivoting at the elbow, and the biceps attaches close to that pivot. A small change in the muscle's length near the joint swings the far end, the hand, through a much larger distance. This lever arrangement trades force for speed and range at the limb's tip." },
    { dok:3, q:"Muscles usually work in antagonistic pairs, such as the biceps and triceps at the elbow. Why can a single muscle not both bend and straighten a joint by itself?", a:"A muscle can only pull, not push, so an opposing muscle is needed to move the joint the other way.", options:["A muscle can only pull, not push, so an opposing muscle is needed to move the joint the other way.","A single muscle can push the bone back to its start position.","Muscles work alone and never need partners.","Antagonist pairs cancel each other so no movement occurs."], correctIndex:0, explanation:"Muscle tissue generates force only by shortening, a pull, and cannot actively lengthen to push. So bending the elbow takes one muscle and straightening it takes its antagonist on the opposite side. The pair lets the joint move both ways, with one contracting while the other relaxes." }
  ],

  /* ---------- RESPIRATORY SYSTEM ---------- */
  "t-respiratory": [
    { dok:3, q:"The alveoli of the lungs are tiny, numerous, and wrapped in capillaries. Why is this design ideal for gas exchange?", a:"Millions of small sacs create an enormous thin surface in close contact with blood for rapid diffusion.", options:["Millions of small sacs create an enormous thin surface in close contact with blood for rapid diffusion.","A few large sacs would exchange gas faster than many small ones.","The alveoli are thick to slow gas exchange down.","Capillaries around alveoli block oxygen from entering blood."], correctIndex:0, explanation:"Breaking the gas-exchange surface into millions of tiny alveoli maximizes total surface area, and their thin walls pressed against capillaries minimize the diffusion distance. Together these let oxygen and carbon dioxide cross quickly between air and blood. Fewer, larger sacs would offer far less surface and slower exchange." },
    { dok:3, q:"The walls of the alveoli and the capillaries beside them are each only one cell thick. Why is this extreme thinness essential at the gas-exchange surface?", a:"A short diffusion path lets oxygen and carbon dioxide cross between air and blood almost instantly.", options:["A short diffusion path lets oxygen and carbon dioxide cross between air and blood almost instantly.","A thicker wall would speed gas exchange.","The thin wall blocks gases from crossing.","Wall thickness has no effect on gas exchange."], correctIndex:0, explanation:"Diffusion is rapid only across tiny distances, so making both the alveolar wall and the capillary wall a single flat cell thick gives gases the shortest possible route between air and blood. This is the same principle as the thin capillary wall, applied at the lung's exchange surface. Thickening the barrier, as in some lung diseases, slows exchange." },
    { dok:3, q:"The trachea is held open by C-shaped rings of cartilage with the gap facing the esophagus behind it. Why is the open part of the C placed toward the esophagus?", a:"The gap lets the esophagus bulge forward when swallowing food, while the cartilage keeps the airway open.", options:["The gap lets the esophagus bulge forward when swallowing food, while the cartilage keeps the airway open.","The gap lets air escape from the trachea into the esophagus.","The cartilage rings close the airway during breathing.","The open part faces forward, away from the esophagus."], correctIndex:0, explanation:"The cartilage rings stop the trachea from collapsing so air always has a path, but a complete ring would press on the esophagus behind it. Leaving the back open lets a swallowed mass of food expand the esophagus forward into that gap. The shape keeps the airway open while accommodating swallowing." },
    { dok:3, q:"The right lung has three lobes while the left has only two. Why does the left lung have less room and fewer lobes?", a:"The heart sits slightly left of center, occupying space that would otherwise hold lung tissue.", options:["The heart sits slightly left of center, occupying space that would otherwise hold lung tissue.","The left lung does less breathing and shrank over time.","The liver pushes up on the left lung.","Lobe number is random and unrelated to nearby organs."], correctIndex:0, explanation:"The heart is positioned a bit to the left, and its space is carved out of the left lung, which even has a notch, the cardiac notch, to accommodate it. With less room, the left lung has two lobes to the right lung's three. The asymmetry reflects the heart's location, not a difference in breathing." },
    { dok:3, q:"Airway passages branch repeatedly, getting smaller from the trachea down to the bronchioles. Why does this branching tree pattern serve breathing well?", a:"Repeated branching distributes air evenly to millions of alveoli throughout both lungs.", options:["Repeated branching distributes air evenly to millions of alveoli throughout both lungs.","Branching slows air so it never reaches the alveoli.","A single wide tube would deliver air to alveoli better.","The branches exist only to make the lung heavier."], correctIndex:0, explanation:"A branching tree of progressively smaller tubes spreads incoming air from the single trachea out to the vast number of alveoli packed throughout the lungs, so all the exchange surface gets ventilated. One undivided tube could not reach and supply the millions of scattered air sacs. The architecture delivers air everywhere it is needed." },
    { dok:3, q:"The epiglottis folds down over the larynx during swallowing. Why is this flap essential despite not being part of breathing itself?", a:"It covers the airway so food goes into the esophagus rather than the lungs.", options:["It covers the airway so food goes into the esophagus rather than the lungs.","It pushes air into the stomach during meals.","It opens the airway wider while swallowing.","It produces the voice during swallowing."], correctIndex:0, explanation:"The air and food passages cross in the throat, so when swallowing, something must keep food out of the airway. The epiglottis folds over the laryngeal opening, directing the swallowed mass into the esophagus behind it. Without this flap, food would enter the trachea, which is why choking happens when it fails." },
    { dok:3, q:"The lining of the bronchi is covered with cilia and mucus-producing cells. Why is this combination important above the delicate alveoli?", a:"Mucus traps inhaled debris and cilia sweep it upward, keeping particles from reaching the alveoli.", options:["Mucus traps inhaled debris and cilia sweep it upward, keeping particles from reaching the alveoli.","Cilia push debris down into the alveoli for exchange.","Mucus carries oxygen directly into the blood.","The lining digests inhaled food particles."], correctIndex:0, explanation:"The alveoli are thin and unprotected, so the airways leading to them act as a cleaning system. Sticky mucus catches dust and microbes, and the beating cilia move that mucus up and out toward the throat to be swallowed or expelled. This escalator keeps harmful particles away from the fragile exchange surface." },
    { dok:3, q:"When the diaphragm contracts and flattens, air flows into the lungs. Why does contracting this muscle cause inhalation?", a:"Flattening the diaphragm enlarges the chest cavity, lowering the pressure so air is drawn in.", options:["Flattening the diaphragm enlarges the chest cavity, lowering the pressure so air is drawn in.","Contracting the diaphragm squeezes the lungs to pull air in.","The diaphragm blows air into the lungs like a pump.","Diaphragm movement has no effect on airflow."], correctIndex:0, explanation:"Breathing in works by changing volume and pressure. When the dome-shaped diaphragm contracts, it drops and flattens, increasing the thoracic cavity's volume. The pressure inside falls below outside air pressure, so air flows in to equalize. Relaxation reverses this, raising pressure and pushing air out." }
  ],

  /* ---------- NERVOUS TISSUE ---------- */
  "t-nervous-tissue": [
    { dok:3, q:"A neuron has many short dendrites but typically a single long axon. Why does this asymmetry suit the neuron's signaling job?", a:"Dendrites gather many incoming signals while the single axon carries one outgoing signal to its targets.", options:["Dendrites gather many incoming signals while the single axon carries one outgoing signal to its targets.","Axons receive signals and dendrites send them.","Both dendrites and axons only receive signals.","The shape is random and unrelated to signaling."], correctIndex:0, explanation:"A neuron integrates input and produces output. Its many branching dendrites provide a large surface to collect signals from numerous other cells, while the single axon conducts the neuron's combined response outward to its targets. The input-versus-output roles explain why one end branches widely and the other extends as a single fiber." },
    { dok:3, q:"Many axons are wrapped in a fatty myelin sheath with small gaps along the way. Why does myelin speed up signal conduction?", a:"The signal jumps between the gaps instead of moving slowly along the whole membrane, so it travels faster.", options:["The signal jumps between the gaps instead of moving slowly along the whole membrane, so it travels faster.","Myelin slows the signal to protect the neuron.","Myelin blocks the signal from leaving the cell body.","The gaps stop the signal entirely."], correctIndex:0, explanation:"Myelin insulates the axon, and the signal regenerates only at the bare gaps between sheath segments, leaping from gap to gap rather than crawling continuously along the membrane. This jumping conduction is far faster than unmyelinated conduction, which is why diseases that strip myelin slow or block nerve signals." },
    { dok:3, q:"Neurons communicate across tiny gaps called synapses using chemical messengers rather than direct electrical contact. Why is a chemical synapse useful despite being slower than a direct connection?", a:"Chemicals let the signal be amplified, adjusted, or inhibited, giving the nervous system flexible control.", options:["Chemicals let the signal be amplified, adjusted, or inhibited, giving the nervous system flexible control.","Chemicals make every signal identical and unchangeable.","Chemical synapses prevent neurons from communicating at all.","Chemicals are used only because neurons cannot touch."], correctIndex:0, explanation:"By converting the electrical signal into a chemical message at the synapse, the nervous system can vary the amount released, use excitatory or inhibitory messengers, and modulate the response. This grants fine, flexible control over whether and how strongly the next neuron fires, which a fixed direct connection could not provide." },
    { dok:3, q:"Mature neurons in the central nervous system generally cannot divide to replace themselves. Why does this make damage to the brain or spinal cord especially serious?", a:"Lost neurons are not readily replaced, so the functions they served can be permanently impaired.", options:["Lost neurons are not readily replaced, so the functions they served can be permanently impaired.","Neurons divide rapidly, so any loss is quickly fixed.","Neuron loss has no effect because other cells take over instantly.","The brain grows new neurons faster after injury."], correctIndex:0, explanation:"Because mature neurons largely do not divide, neurons killed by injury or stroke are not simply regrown, and the circuits they belonged to may be lost. This is why central nervous system damage often causes lasting deficits, unlike tissues such as skin that replace lost cells readily." },
    { dok:3, q:"Glial cells vastly outnumber neurons and do not transmit signals themselves. Why are these supporting cells essential to the nervous system?", a:"They nourish, insulate, and protect neurons and maintain the environment neurons need to function.", options:["They nourish, insulate, and protect neurons and maintain the environment neurons need to function.","They replace neurons by transmitting signals for them.","They serve no purpose and only fill space.","They prevent neurons from ever communicating."], correctIndex:0, explanation:"Neurons cannot work in isolation. Glial cells form myelin, supply nutrients, remove debris, and keep the chemical surroundings stable, among other support roles. By maintaining the conditions neurons require, glia are indispensable even though they do not carry signals themselves, which is why they are so numerous." },
    { dok:3, q:"Sensory neurons carry signals toward the central nervous system, while motor neurons carry signals away from it. Why is this one-way division of labor important for a reflex?", a:"It creates a clear input-then-output pathway, so a stimulus reliably produces the right response.", options:["It creates a clear input-then-output pathway, so a stimulus reliably produces the right response.","It lets each neuron send signals in both directions at once.","It slows reflexes so they cannot protect the body.","Direction of signaling has no role in reflexes."], correctIndex:0, explanation:"A reflex depends on information flowing in a set direction, sensing the stimulus, processing it, then commanding a response. Sensory neurons bring the input in and motor neurons send the command out, so the loop runs reliably from detection to action. Mixing directions would scramble the orderly input-to-output sequence a reflex needs." },
    { dok:3, q:"The cell body of a neuron contains abundant rough endoplasmic reticulum and ribosomes. Why does a neuron need such heavy protein-making machinery in its cell body?", a:"It must continually supply proteins to maintain a cell that can be very long and long-lived.", options:["It must continually supply proteins to maintain a cell that can be very long and long-lived.","Neurons make protein to digest other cells.","The machinery exists only to store the signal chemicals.","Neurons do not actually need protein and the machinery is unused."], correctIndex:0, explanation:"A neuron can extend a meter or more and must persist for decades, so it constantly manufactures proteins to maintain its long axon and dendrites and to keep functioning. The cell body's rich rough ER and ribosomes are the production center for that ongoing demand, matching the cell's size and longevity." }
  ],

  /* ---------- ENDOCRINE SYSTEM ---------- */
  "t-endocrine": [
    { dok:3, q:"Endocrine glands release their hormones directly into the bloodstream rather than through ducts. Why does this delivery method suit hormones that must reach widely separated organs?", a:"The blood carries hormones throughout the body, so distant target organs can all be reached at once.", options:["The blood carries hormones throughout the body, so distant target organs can all be reached at once.","Ducts would spread hormones faster than the bloodstream.","Hormones act only on the gland that makes them.","Bloodstream delivery keeps hormones from ever reaching organs."], correctIndex:0, explanation:"Hormones often must act on organs far from the gland that makes them, so releasing them into the circulating blood lets them travel everywhere and reach every target with the right receptor. A duct can only deliver to one nearby surface, which is why ductless, blood-borne delivery fits the endocrine system's body-wide reach." },
    { dok:3, q:"Although hormones travel in the blood to nearly every cell, each hormone affects only certain target cells. Why does a hormone act on some cells and not others?", a:"Only cells with the matching receptor for that hormone can respond to it.", options:["Only cells with the matching receptor for that hormone can respond to it.","Hormones reach only the cells nearest the gland.","Every cell responds equally to every hormone.","Hormones choose targets at random each time."], correctIndex:0, explanation:"A hormone circulates past all cells, but it can only trigger a response in cells that carry a receptor shaped to bind it. Cells without that receptor ignore the hormone. This lock-and-key specificity is why a single hormone in the shared bloodstream produces effects in some tissues but not others." },
    { dok:3, q:"The pituitary gland is often called the master gland because it controls several other endocrine glands. Why is having one gland direct others useful for the body?", a:"Central control lets the body coordinate many glands into organized, balanced responses.", options:["Central control lets the body coordinate many glands into organized, balanced responses.","It lets each gland work in complete isolation.","A master gland makes the other glands unnecessary.","Central control prevents the glands from ever releasing hormones."], correctIndex:0, explanation:"By having the pituitary release hormones that switch other glands on and off, the body can orchestrate the thyroid, adrenal cortex, and reproductive glands together rather than letting each act alone. This central coordination keeps responses like growth, metabolism, and stress reactions organized and balanced across the system." },
    { dok:3, q:"The adrenal glands sit directly on top of the kidneys, and their inner part releases hormones during stress. Why is rapid release into a rich blood supply important for these stress hormones?", a:"Stress hormones must reach the whole body fast to ready it for action, so quick entry into abundant blood flow speeds the response.", options:["Stress hormones must reach the whole body fast to ready it for action, so quick entry into abundant blood flow speeds the response.","Stress hormones act slowly over many days.","The adrenal location keeps the hormones from entering the blood.","Stress hormones affect only the kidney beneath the gland."], correctIndex:0, explanation:"A fight-or-flight response needs to mobilize the heart, muscles, and airways within seconds. Releasing the hormones into the adrenal glands' generous blood supply spreads them quickly throughout the body so many organs respond almost at once. Speed of delivery matches the urgency of the stress response." },
    { dok:3, q:"The pancreas works as both an endocrine gland, releasing hormones into blood, and an exocrine gland, releasing enzymes through a duct. Why is this dual role efficient?", a:"One organ can both regulate blood sugar by hormones and deliver digestive enzymes to the intestine.", options:["One organ can both regulate blood sugar by hormones and deliver digestive enzymes to the intestine.","The pancreas must choose only one role and abandons the other.","Both roles do exactly the same thing twice.","Dual function prevents the pancreas from working at all."], correctIndex:0, explanation:"The pancreas handles two related jobs around nutrition: its endocrine cells secrete hormones into the blood to control blood sugar, while its exocrine cells send digestive enzymes through a duct to the small intestine. Combining both in one organ near the digestive tract is an efficient arrangement for managing nutrients." },
    { dok:3, q:"The thyroid gland stores its hormone and releases it slowly, producing effects that build over hours to days. Why does slow, steady release suit the thyroid's role in metabolism?", a:"Metabolic rate is a long-term setting, so a steady hormone level maintains it better than rapid bursts.", options:["Metabolic rate is a long-term setting, so a steady hormone level maintains it better than rapid bursts.","Metabolism changes second to second and needs instant bursts.","Slow release means the thyroid hormone never reaches cells.","The thyroid must release everything at once to work."], correctIndex:0, explanation:"The thyroid sets the body's baseline metabolic pace, which should stay stable rather than swing moment to moment. Storing hormone and releasing it gradually keeps a steady level in the blood, holding metabolism at a consistent rate. This contrasts with the fast bursts of stress hormones, matching release pattern to the job." },
    { dok:3, q:"Many hormones are controlled by negative feedback, where a rising hormone level shuts off its own production. Why is this self-limiting loop valuable?", a:"It keeps hormone levels within a safe range by preventing overproduction.", options:["It keeps hormone levels within a safe range by preventing overproduction.","It causes hormone levels to rise without limit.","It stops the gland from ever making the hormone.","Feedback has no effect on hormone levels."], correctIndex:0, explanation:"Negative feedback works like a thermostat: as a hormone rises and produces its effect, that rise signals the gland to slow down, so levels do not climb out of control. This automatic braking keeps hormones balanced within a healthy range, which is essential because too much of a hormone is as harmful as too little." }
  ],

  /* ---------- BLOOD ---------- */
  "t-blood": [
    { dok:3, q:"Mature red blood cells have a biconcave disc shape, pinched in on both sides. Why is this shape advantageous for their job?", a:"The dimpled disc increases surface area for gas exchange and lets the cell bend through narrow capillaries.", options:["The dimpled disc increases surface area for gas exchange and lets the cell bend through narrow capillaries.","The shape makes the cell rigid so it cannot enter capillaries.","The shape reduces surface area to slow oxygen pickup.","The dimples store oxygen permanently inside the cell."], correctIndex:0, explanation:"A biconcave disc has more surface relative to its volume than a sphere, speeding oxygen loading and unloading, and its flexible shape lets the cell fold to squeeze through capillaries narrower than itself. Both features serve the red cell's task of carrying gases and reaching every tissue, so the shape is functionally ideal." },
    { dok:3, q:"White blood cells can squeeze out of blood vessels and move into tissues, unlike red blood cells. Why is this ability essential to their function?", a:"They must leave the blood to reach sites of infection or injury in the tissues and fight invaders there.", options:["They must leave the blood to reach sites of infection or injury in the tissues and fight invaders there.","They leave the blood only by accident and serve no purpose outside it.","Leaving the vessel kills the white blood cell immediately.","White blood cells fight infection only while inside vessels."], correctIndex:0, explanation:"Infections and damage occur in tissues, not just in the bloodstream, so defensive white blood cells must be able to exit the vessels and crawl through tissue to reach the trouble. Their capacity to slip between vessel-wall cells and migrate to a site of infection is what lets them defend the whole body, not just the blood." },
    { dok:3, q:"Platelets are cell fragments without a nucleus that gather rapidly at the site of a cut. Why does the body rely on these small fragments for the first response to bleeding?", a:"Being numerous and quick to stick together, they can plug a damaged vessel almost immediately.", options:["Being numerous and quick to stick together, they can plug a damaged vessel almost immediately.","They are too large to reach the wound quickly.","They prevent clotting and keep wounds bleeding.","Platelets carry oxygen instead of stopping bleeding."], correctIndex:0, explanation:"When a vessel is breached, bleeding must be stopped fast. Platelets are plentiful in blood and rapidly adhere to the damaged site and to one another, forming a plug within seconds to slow blood loss while a sturdier clot forms. Their abundance and stickiness make them ideal for this immediate first response." },
    { dok:3, q:"Blood plasma is mostly water but also carries dissolved proteins, nutrients, wastes, and hormones. Why is a watery liquid the right medium for these many cargoes?", a:"Water can dissolve and suspend a wide variety of substances and flow easily through vessels to distribute them.", options:["Water can dissolve and suspend a wide variety of substances and flow easily through vessels to distribute them.","Water blocks substances from dissolving in the blood.","A solid medium would distribute cargo through vessels better.","Plasma carries nothing and is just filler."], correctIndex:0, explanation:"A great many of the body's transported materials are water-soluble, and a fluid flows readily through the vascular network. Water-based plasma can therefore dissolve or carry nutrients, wastes, hormones, and proteins and move them everywhere blood travels. Its fluidity and solvent power make it the ideal transport medium." },
    { dok:3, q:"Red blood cells are packed with hemoglobin but have no nucleus and no mitochondria. Why is losing these organelles actually helpful for a red blood cell?", a:"It frees space for more hemoglobin and means the cell does not consume the oxygen it carries.", options:["It frees space for more hemoglobin and means the cell does not consume the oxygen it carries.","It makes the cell unable to carry oxygen.","It causes the cell to use up all the oxygen itself.","The missing organelles make the cell rigid and fragile only."], correctIndex:0, explanation:"Without a nucleus and mitochondria, a red cell has more room for the oxygen-carrying hemoglobin that is its whole purpose, and lacking mitochondria it does not burn the oxygen it transports, delivering more to tissues. Shedding these organelles thus serves the cell's role as a dedicated oxygen carrier." },
    { dok:3, q:"A person living at high altitude, where air holds less oxygen, gradually produces more red blood cells. Why does the body respond this way?", a:"More red cells carry more oxygen, compensating for the thinner air.", options:["More red cells carry more oxygen, compensating for the thinner air.","More red cells reduce the oxygen reaching tissues.","The extra cells have nothing to do with oxygen.","Fewer red cells would help at high altitude."], correctIndex:0, explanation:"At altitude each breath delivers less oxygen, so the body adapts by making more red blood cells to increase total oxygen-carrying capacity. With more carriers in the blood, tissues can still receive enough oxygen despite the thinner air. The response directly offsets the lower oxygen availability." },
    { dok:3, q:"Blood is classified into types such as A, B, AB, and O based on markers on red blood cells. Why does matching blood type matter before a transfusion?", a:"The immune system attacks red cells carrying unfamiliar markers, so a mismatch causes a dangerous reaction.", options:["The immune system attacks red cells carrying unfamiliar markers, so a mismatch causes a dangerous reaction.","Blood type affects only the color of the blood.","Any blood type can be given to anyone safely.","Matching type makes the transfusion reaction worse."], correctIndex:0, explanation:"The surface markers that define blood type are recognized by the immune system. If transfused red cells carry markers the recipient's body sees as foreign, the immune system attacks them, causing clumping and a serious, potentially fatal reaction. Matching types ensures the donated cells are not recognized as foreign, making transfusion safe." }
  ],

  /* ---------- URINARY SYSTEM ---------- */
  "t-urinary-system": [
    { dok:3, q:"Each kidney contains about a million tiny filtering units called nephrons. Why is dividing the filtering work among so many small units advantageous?", a:"Many units provide enormous total filtering capacity and a reserve if some are lost.", options:["Many units provide enormous total filtering capacity and a reserve if some are lost.","A single large filter would clean blood far better.","More units slow filtration and harm the body.","The nephrons do not filter and merely store urine."], correctIndex:0, explanation:"Splitting filtration among a million nephrons gives the kidney a vast combined surface to process large volumes of blood, and it builds in redundancy, so even if many nephrons are damaged, the rest can carry on. This is why people can survive with reduced kidney function or even one kidney." },
    { dok:3, q:"The glomerulus is a tight ball of capillaries where blood is filtered under pressure. Why is a high-pressure capillary cluster suited to the first step of urine formation?", a:"The pressure forces water and small solutes out of the blood to begin filtration.", options:["The pressure forces water and small solutes out of the blood to begin filtration.","High pressure prevents anything from leaving the blood.","The cluster stores urine rather than filtering blood.","Low pressure would filter blood better than high pressure."], correctIndex:0, explanation:"Filtration in the kidney is driven by pressure pushing fluid out of the blood through the capillary walls. Bundling capillaries into a high-pressure glomerulus drives water and small molecules out into the nephron to start forming filtrate, while large items like cells and proteins stay behind. The pressure is what initiates filtering." },
    { dok:3, q:"After filtration, the nephron tubules reabsorb most of the water and useful substances back into the blood. Why is this reabsorption step necessary rather than excreting everything filtered?", a:"The kidney filters far more than it should lose, so it recovers water and nutrients the body needs.", options:["The kidney filters far more than it should lose, so it recovers water and nutrients the body needs.","Everything filtered is waste, so reabsorption is pointless.","Reabsorption adds waste back into the blood on purpose.","The tubules destroy the filtered nutrients."], correctIndex:0, explanation:"Filtration is not selective enough on its own; it removes huge amounts of water, glucose, and ions along with wastes. Reabsorption reclaims the valuable water and nutrients back into the blood so they are not lost in urine, leaving mainly waste to be excreted. Without it, the body would rapidly lose vital substances." },
    { dok:3, q:"The ureters carry urine from the kidneys to the bladder using waves of muscular contraction. Why does the body use active muscular pushing rather than relying on gravity?", a:"Muscular waves move urine in any body position, including lying down, when gravity would not suffice.", options:["Muscular waves move urine in any body position, including lying down, when gravity would not suffice.","Gravity alone moves urine perfectly in every position.","The ureters cannot contract and only let urine drip.","Muscle contraction pushes urine back toward the kidney."], correctIndex:0, explanation:"A person is not always upright, so urine cannot depend on gravity to reach the bladder. The ureters squeeze in rhythmic waves that propel urine onward regardless of position, even against gravity when lying down. Active transport ensures reliable one-way flow toward the bladder at all times." },
    { dok:3, q:"The bladder wall is lined with transitional epithelium and folds called rugae. Why is this stretchable lining important for the bladder's job?", a:"It lets the bladder expand to hold more urine and shrink when empty without tearing.", options:["It lets the bladder expand to hold more urine and shrink when empty without tearing.","It keeps the bladder a fixed size at all times.","It speeds urine diffusion back into the blood.","The folds prevent the bladder from filling."], correctIndex:0, explanation:"The bladder must change greatly in volume as it fills and empties. Transitional epithelium can flatten as the wall stretches, and the rugae unfold to allow expansion, so the bladder accommodates a large volume and then returns to a small size, all without damaging its lining. The stretchable design matches its storage role." },
    { dok:3, q:"Two sphincters guard the bladder outlet, one involuntary and one under conscious control. Why is having both an automatic and a voluntary sphincter useful?", a:"The automatic one prevents leaks while the voluntary one lets a person choose when to urinate.", options:["The automatic one prevents leaks while the voluntary one lets a person choose when to urinate.","Both sphincters are voluntary, so control is doubled needlessly.","Neither sphincter controls urine flow.","The sphincters force urination at random times."], correctIndex:0, explanation:"Continence requires both reliable closure and conscious timing. The involuntary internal sphincter keeps the outlet closed automatically so urine does not leak, while the voluntary external sphincter lets a person hold or release urine by choice. The two together provide both automatic security and deliberate control." },
    { dok:3, q:"The kidneys help regulate blood pressure and the amount of water in the body. Why does the organ that makes urine also influence blood pressure?", a:"By adjusting how much water and salt are kept or excreted, the kidney changes blood volume, which affects pressure.", options:["By adjusting how much water and salt are kept or excreted, the kidney changes blood volume, which affects pressure.","Urine production has no connection to blood volume.","The kidney raises blood pressure by removing all water.","Blood pressure is set only by the heart, never the kidney."], correctIndex:0, explanation:"Blood pressure depends partly on blood volume, and the kidney controls volume by deciding how much water and salt to reabsorb versus excrete in urine. Retaining more raises blood volume and pressure, and excreting more lowers it. So the urine-forming organ is also a key long-term regulator of blood pressure." }
  ],

  /* ---------- ALIMENTARY CANAL ---------- */
  "t-alimentary-canal": [
    { dok:3, q:"The small intestine is lined with finger-like villi, each covered in microscopic microvilli. Why does this folded, fuzzy lining suit the small intestine's main job?", a:"It vastly increases surface area for absorbing nutrients from digested food.", options:["It vastly increases surface area for absorbing nutrients from digested food.","It reduces surface area to slow absorption.","It makes the intestine secrete acid faster.","The villi block nutrients from being absorbed."], correctIndex:0, explanation:"Absorption depends on surface contact between food and the intestinal lining. Villi and the microvilli on them multiply that surface enormously, so the small intestine can absorb the bulk of nutrients efficiently as food passes. The elaborate folding is a direct adaptation to its role as the body's main absorptive organ." },
    { dok:3, q:"The stomach lining is folded into rugae and coated with a thick layer of mucus. Why are both features important to the stomach?", a:"The rugae let the stomach expand with a meal, and the mucus shields the wall from its own acid.", options:["The rugae let the stomach expand with a meal, and the mucus shields the wall from its own acid.","The mucus digests the stomach wall on purpose.","The rugae keep the stomach from ever stretching.","Neither feature protects or helps the stomach."], correctIndex:0, explanation:"The stomach must hold a large meal and produce strong acid. The rugae unfold so the stomach can expand to accommodate food, and the mucus layer coats the lining so the corrosive acid digests the meal rather than the stomach itself. Both features adapt the organ to storing and acid-digesting food safely." },
    { dok:3, q:"The walls of the alimentary canal contain layers of smooth muscle that contract in waves called peristalsis. Why is wave-like muscular movement essential to digestion?", a:"It propels food along the tract and mixes it with digestive juices regardless of body position.", options:["It propels food along the tract and mixes it with digestive juices regardless of body position.","It holds food still so it cannot be digested.","Gravity alone moves food, so the muscle is unnecessary.","Peristalsis pushes food backward out of the mouth."], correctIndex:0, explanation:"Food must move through a long tube and be mixed with enzymes, and the body is not always upright. Peristaltic waves of smooth muscle squeeze food onward and churn it with digestive juices, working in any position. This active, directed movement is what carries a meal through the entire digestive process." },
    { dok:3, q:"The large intestine absorbs water from the material passing through it, while the small intestine absorbs most nutrients. Why does the large intestine focus on water rather than nutrients?", a:"Most nutrients are already absorbed upstream, so the remaining task is to reclaim water and compact the waste.", options:["Most nutrients are already absorbed upstream, so the remaining task is to reclaim water and compact the waste.","The large intestine absorbs nutrients the small intestine cannot.","Water absorption has no effect on the stool.","The large intestine adds water to make waste more liquid."], correctIndex:0, explanation:"By the time material reaches the large intestine, the nutrient-absorbing small intestine has already taken up most of the usable food. What remains is largely indigestible waste plus water, so the large intestine recovers that water back into the body and compacts the leftover into a more solid stool. The roles are sequential." },
    { dok:3, q:"A muscular sphincter sits between the stomach and the small intestine. Why is controlling the release of stomach contents into the intestine important?", a:"Releasing food gradually lets the intestine handle and neutralize the acidic mixture a little at a time.", options:["Releasing food gradually lets the intestine handle and neutralize the acidic mixture a little at a time.","Dumping all the food at once digests it better.","The sphincter blocks food from ever leaving the stomach.","The sphincter speeds food through without any control."], correctIndex:0, explanation:"Stomach contents are highly acidic and partly digested. The sphincter meters them into the small intestine in small amounts so the intestine can neutralize the acid and digest the load without being overwhelmed. Controlled, gradual release protects the intestinal lining and allows thorough digestion, which a sudden dump would not." },
    { dok:3, q:"The inner lining of the digestive tract is replaced very frequently, every few days. Why does this lining need such rapid renewal?", a:"It is constantly exposed to abrasion, acid, and enzymes, so worn cells must be replaced quickly.", options:["It is constantly exposed to abrasion, acid, and enzymes, so worn cells must be replaced quickly.","The lining never wears out and renews for no reason.","Rapid renewal makes the lining weaker over time.","The lining is replaced to slow down digestion."], correctIndex:0, explanation:"The digestive lining endures a harsh environment of rough food, strong acid, and powerful enzymes that damage its cells. Renewing the lining every few days replaces worn and damaged cells before they fail, keeping the barrier intact and functional. The high turnover matches the constant wear the surface experiences." },
    { dok:3, q:"The esophagus passes food to the stomach but does not absorb nutrients, while the small intestine does. Why is the esophagus built as a simple muscular tube without absorptive folds?", a:"Its only job is rapid transport, so it needs muscle to push food, not surface area to absorb it.", options:["Its only job is rapid transport, so it needs muscle to push food, not surface area to absorb it.","The esophagus should absorb more nutrients than the intestine.","Absorptive folds would speed transport through the esophagus.","The esophagus stores food for days before swallowing."], correctIndex:0, explanation:"The esophagus simply conveys swallowed food quickly from throat to stomach, a task that calls for strong muscular walls to push the food along. It does not need the villi and large surface area that an absorptive organ requires. Its plain muscular structure matches a transport-only role, unlike the folded small intestine." }
  ],

  /* ---------- ACCESSORY DIGESTIVE ORGANS ---------- */
  "t-accessory-digestive-organs": [
    { dok:3, q:"The liver receives blood from the intestines before that blood reaches the rest of the body. Why is it positioned to screen intestinal blood first?", a:"It processes and detoxifies absorbed substances before they circulate to the rest of the body.", options:["It processes and detoxifies absorbed substances before they circulate to the rest of the body.","It blocks all nutrients from ever leaving the intestine.","It adds toxins to the blood before circulation.","Its position has nothing to do with processing blood."], correctIndex:0, explanation:"Blood leaving the intestines carries newly absorbed nutrients and possible toxins. Routing it through the liver first lets that organ store nutrients, convert substances, and neutralize harmful compounds before the blood spreads through the body. The liver's placement as the first stop makes it the body's screening and processing station." },
    { dok:3, q:"The gallbladder stores bile and releases it when fatty food enters the small intestine. Why is storing and concentrating bile useful rather than dribbling it out constantly?", a:"It lets a concentrated burst of bile be delivered exactly when fatty food needs to be emulsified.", options:["It lets a concentrated burst of bile be delivered exactly when fatty food needs to be emulsified.","Bile is needed equally at all times, so storage is pointless.","Storing bile makes it unable to digest fat.","The gallbladder produces bile rather than storing it."], correctIndex:0, explanation:"Bile breaks fat into small droplets, and fat arrives only with meals, not constantly. Storing and concentrating bile between meals means the gallbladder can release a strong, well-timed dose when fatty food reaches the intestine, matching supply to demand. Constant slow release would waste bile and provide too little when it is needed." },
    { dok:3, q:"Bile does not contain digestive enzymes, yet it is essential for digesting fats. Why can bile aid fat digestion without being an enzyme?", a:"It breaks large fat globules into small droplets, giving enzymes far more surface to work on.", options:["It breaks large fat globules into small droplets, giving enzymes far more surface to work on.","It chemically digests fat by itself without enzymes.","It blocks enzymes from reaching the fat.","Bile has no effect on fat digestion."], correctIndex:0, explanation:"Fat tends to clump into large globules that enzymes can only attack at the surface. Bile emulsifies the fat, breaking it into many tiny droplets and greatly increasing the total surface exposed to fat-digesting enzymes. So bile speeds digestion physically, by dispersing fat, even though the chemical breakdown is still done by enzymes." },
    { dok:3, q:"The pancreas releases digestive enzymes along with a bicarbonate-rich fluid into the small intestine. Why is the bicarbonate as important as the enzymes?", a:"It neutralizes the stomach acid arriving with food so the enzymes can work and the intestine is protected.", options:["It neutralizes the stomach acid arriving with food so the enzymes can work and the intestine is protected.","It makes the intestine more acidic to help enzymes.","It has no role and is simply waste fluid.","It digests fat directly without enzymes."], correctIndex:0, explanation:"Material entering the small intestine from the stomach is strongly acidic, which would damage the intestinal lining and disable the pancreatic enzymes, since they work best near neutral. The bicarbonate neutralizes that acid, creating the right conditions for the enzymes and shielding the intestine. The buffer and the enzymes work together." },
    { dok:3, q:"The pancreatic duct and the bile duct join and empty into the same part of the small intestine. Why is it efficient for these two secretions to arrive at the same place?", a:"Bile and pancreatic juice both act on food in the early small intestine, so delivering them together aids digestion there.", options:["Bile and pancreatic juice both act on food in the early small intestine, so delivering them together aids digestion there.","The two secretions cancel each other out and should stay apart.","They meet by accident with no digestive benefit.","Combining them stops digestion in the small intestine."], correctIndex:0, explanation:"Both bile, which emulsifies fat, and pancreatic juice, which supplies enzymes and neutralizing buffer, are needed right where food first enters the small intestine. Emptying them at the same site delivers all the digestive tools to the food together at the point of need, an efficient arrangement for breaking down a meal." },
    { dok:3, q:"The liver performs hundreds of different chemical functions and has a remarkable ability to regenerate after injury. Why is this regenerative capacity especially valuable for the liver?", a:"Because it handles so many vital tasks, recovering lost tissue lets it keep the body running after damage.", options:["Because it handles so many vital tasks, recovering lost tissue lets it keep the body running after damage.","The liver does little, so regeneration hardly matters.","Regeneration makes the liver stop working.","Other organs replace the liver, so it need not regenerate."], correctIndex:0, explanation:"The liver is central to metabolism, detoxification, and the production of many substances, so losing its function would be life-threatening. Its ability to regrow damaged tissue lets it restore those many essential functions after injury, which is why this unusual capacity is so important for an organ the body cannot do without." },
    { dok:3, q:"Salivary glands release saliva containing enzymes and mucus into the mouth before food is even swallowed. Why is beginning digestion in the mouth useful?", a:"It starts breaking down food and moistens it so it can be chewed, tasted, and swallowed easily.", options:["It starts breaking down food and moistens it so it can be chewed, tasted, and swallowed easily.","Saliva delays digestion until food reaches the stomach.","Saliva dries food out to make swallowing harder.","Saliva has no role until food returns from the stomach."], correctIndex:0, explanation:"Digestion is more efficient when it begins early. Saliva moistens and lubricates food so it can be chewed into a swallowable mass, its enzymes start breaking down starch, and dissolving food lets taste receptors work. Starting the process in the mouth eases swallowing and gives later organs a head start." }
  ],

  /* ---------- LYMPHATIC SYSTEM ---------- */
  "t-lymphatic-system": [
    { dok:3, q:"Lymphatic capillaries have overlapping cells that act as one-way flaps, letting fluid in but not back out. Why is this one-way design important?", a:"It lets excess tissue fluid enter the lymphatic vessels and keeps it from leaking back into the tissue.", options:["It lets excess tissue fluid enter the lymphatic vessels and keeps it from leaking back into the tissue.","It lets fluid flow freely both into and out of the vessel.","It blocks all fluid from entering the lymphatic system.","It pushes fluid back into the tissue on purpose."], correctIndex:0, explanation:"The lymphatic system collects fluid that leaks out of blood capillaries into tissues. The flap-like overlapping cells open inward to admit this fluid and close to stop it escaping, ensuring a one-way path that drains tissues and returns the fluid toward the bloodstream. Without one-way entry, the fluid could not be reliably collected." },
    { dok:3, q:"Lymph nodes are positioned along lymphatic vessels and are packed with immune cells. Why is placing immune cells along these drainage routes effective?", a:"Fluid from the tissues passes through the nodes, so invaders carried in it are filtered out and attacked.", options:["Fluid from the tissues passes through the nodes, so invaders carried in it are filtered out and attacked.","The nodes block lymph from moving at all.","Immune cells in nodes never contact the lymph.","Placing nodes there has no effect on infection."], correctIndex:0, explanation:"Because lymph drains from tissues and flows through the nodes on its way back to the blood, any bacteria or other invaders swept up in that fluid are forced past concentrated immune cells. The nodes act as checkpoints that filter and attack pathogens, which is why nodes swell during infection as the response ramps up." },
    { dok:3, q:"The lymphatic system has no pump like the heart, yet lymph still moves through it. Why does lymph flow depend on skeletal muscle movement and one-way valves?", a:"Muscle contractions squeeze the vessels and valves prevent backflow, pushing lymph forward without a central pump.", options:["Muscle contractions squeeze the vessels and valves prevent backflow, pushing lymph forward without a central pump.","Lymph flows only because the heart pumps it directly.","Lymph does not actually move through the vessels.","Valves push lymph backward away from the blood."], correctIndex:0, explanation:"Lacking its own pump, the lymphatic system relies on the squeezing of nearby skeletal muscles to compress the vessels, while valves ensure that each squeeze moves lymph in only one direction toward the bloodstream. This is why movement and exercise aid lymph flow, and why inactivity can let fluid pool." },
    { dok:3, q:"The spleen filters blood and removes old or damaged red blood cells. Why is it efficient for the spleen to combine blood filtering with immune defense?", a:"As blood passes through, the spleen can both clear worn cells and let immune cells screen it for invaders.", options:["As blood passes through, the spleen can both clear worn cells and let immune cells screen it for invaders.","Filtering blood prevents the spleen from any immune role.","The spleen filters air, not blood.","Combining the roles stops both from working."], correctIndex:0, explanation:"Routing blood through the spleen gives one organ the chance to perform two related jobs at once: removing aged or damaged red cells from circulation and exposing the blood to immune cells that detect and respond to pathogens. Handling cleanup and surveillance together as blood flows through is an efficient arrangement." },
    { dok:3, q:"The thymus is large and active in children but shrinks after puberty. Why does this gland do most of its work early in life?", a:"It matures immune cells, and the bulk of that training happens while the immune system is being established in youth.", options:["It matures immune cells, and the bulk of that training happens while the immune system is being established in youth.","It grows larger with age as immunity weakens.","The thymus has no role in the immune system.","It shrinks because it was never functional."], correctIndex:0, explanation:"The thymus trains certain immune cells to function and tells self from nonself, work that is most intense while the immune system is first developing in childhood. Once a broad repertoire of trained cells is established, the gland's job tapers off and it shrinks. Its activity matches the early-life period when immune education is greatest." },
    { dok:3, q:"Tonsils sit at the entrance of the throat where food and air pass. Why is this location well suited to their immune role?", a:"They guard a common entry point, sampling incoming pathogens early and mounting a defense.", options:["They guard a common entry point, sampling incoming pathogens early and mounting a defense.","They block food and air from entering the body.","Their location keeps them away from any pathogens.","Tonsils digest food that passes the throat."], correctIndex:0, explanation:"Many pathogens enter through the mouth and nose, and the throat is where those passages meet. Placing immune tissue there lets the tonsils encounter invaders early, sample them, and trigger a response before infection spreads. Guarding this gateway is why tonsils, though prone to infection themselves, are positioned where they are." },
    { dok:3, q:"When lymphatic drainage from a limb is blocked, the limb swells with retained fluid. Using the lymphatic system's normal job, why does blockage cause swelling?", a:"The lymphatics normally drain excess tissue fluid, so blocking them lets that fluid accumulate.", options:["The lymphatics normally drain excess tissue fluid, so blocking them lets that fluid accumulate.","Blockage causes the tissue to lose all its fluid.","Swelling happens because lymph is pumped in faster.","The lymphatic system has no role in tissue fluid."], correctIndex:0, explanation:"A steady trickle of fluid normally leaks from blood capillaries into tissues, and the lymphatic vessels collect and return it. If those vessels are blocked, the fluid the lymphatics would have carried away builds up in the tissue instead, producing the swelling seen in lymphedema. The swelling is the direct result of lost drainage." }
  ],

  /* ---------- CARDIAC CONDUCTION ---------- */
  "t-cardiac-conduction": [
    { dok:3, q:"The heart has its own pacemaker, the sinoatrial node, that fires on its own without nerve input. Why is it valuable that the heart can generate its own beat?", a:"The heart keeps beating reliably even if outside nervous signals are interrupted.", options:["The heart keeps beating reliably even if outside nervous signals are interrupted.","The heart can beat only when the brain commands each beat.","Self-generated beats make the heart stop frequently.","The pacemaker prevents the heart from ever beating."], correctIndex:0, explanation:"Because the sinoatrial node sets its own rhythm, the heart does not depend on a continuous command from the brain to beat. This built-in pacemaker keeps the heart pumping steadily and is why a transplanted or denervated heart still beats. Outside nerves adjust the rate, but the heart's independence makes its beating reliable." },
    { dok:3, q:"The electrical signal pauses briefly at the atrioventricular node before continuing to the ventricles. Why is this built-in delay necessary?", a:"It gives the atria time to finish emptying blood into the ventricles before the ventricles contract.", options:["It gives the atria time to finish emptying blood into the ventricles before the ventricles contract.","It makes the atria and ventricles contract at the same instant.","The delay stops the ventricles from ever contracting.","The pause serves no purpose in the heartbeat."], correctIndex:0, explanation:"For the pump to fill properly, the ventricles should receive the atria's blood before they squeeze. The brief hold at the atrioventricular node delays the signal just long enough for atrial contraction to top off the ventricles, so the following ventricular contraction ejects a full load. The timing makes each beat efficient." },
    { dok:3, q:"The conducting fibers carry the signal to the bottom of the ventricles first, so contraction begins at the apex and pushes upward. Why does starting the squeeze at the bottom help the heart pump?", a:"Contracting from the apex upward drives blood toward the vessels leaving at the top of the ventricles.", options:["Contracting from the apex upward drives blood toward the vessels leaving at the top of the ventricles.","Starting at the bottom pushes blood downward and out the apex.","The starting point has no effect on blood flow.","Contraction must start at the top to empty the ventricles."], correctIndex:0, explanation:"The great vessels that carry blood out of the ventricles leave from the upper part of the heart. By starting contraction at the apex and moving up, the ventricles squeeze blood upward toward those outlets, emptying efficiently like squeezing a tube from the bottom. The direction of the wave is matched to where blood must exit." },
    { dok:3, q:"Cardiac muscle cells are electrically linked so a signal spreads quickly from cell to cell. Why must the signal spread this way for the heart to pump effectively?", a:"Coordinated, near-simultaneous contraction of the linked cells produces one strong, unified squeeze.", options:["Coordinated, near-simultaneous contraction of the linked cells produces one strong, unified squeeze.","Cells contracting at random times pump blood better.","Electrical linking stops the cells from contracting.","The signal should reach only one cell at a time for a strong beat."], correctIndex:0, explanation:"An effective pump needs its muscle to contract together. Because cardiac cells are electrically connected, the signal sweeps rapidly through them so they contract almost as one, generating a single powerful, coordinated squeeze. If the cells fired independently, the chamber would quiver rather than pump, as happens in fibrillation." },
    { dok:3, q:"The atria and ventricles are separated by a layer of fibrous tissue that the signal can cross only through the atrioventricular node. Why is this insulating barrier with a single gateway important?", a:"It forces the signal through the delaying node, ensuring the atria contract before the ventricles in proper order.", options:["It forces the signal through the delaying node, ensuring the atria contract before the ventricles in proper order.","It lets the signal cross anywhere, so timing does not matter.","It stops the signal from ever reaching the ventricles.","The barrier makes all four chambers contract at once."], correctIndex:0, explanation:"If the signal could pass directly from atria to ventricles anywhere, the chambers might contract together and pump poorly. The fibrous layer blocks every path except through the atrioventricular node, channeling the signal through its delay so the atria always contract first and the ventricles follow in the correct sequence." },
    { dok:3, q:"Nerves from outside the heart can speed up or slow down the heart rate but do not create the beat. Why is it useful to separate setting the basic rhythm from adjusting the rate?", a:"The heart keeps a steady beat on its own while the nerves fine-tune the rate to match the body's needs.", options:["The heart keeps a steady beat on its own while the nerves fine-tune the rate to match the body's needs.","The nerves must create every beat from scratch.","Separating the two stops the heart from changing rate.","Without nerves the heart could not beat at all."], correctIndex:0, explanation:"The heart's own pacemaker guarantees a reliable baseline rhythm, while the outside nerves act like a volume knob, raising the rate during exercise or stress and lowering it at rest. Splitting these roles gives both dependable, automatic beating and the flexibility to match output to demand, the best of both arrangements." }
  ],

  /* ---------- CNS: BRAIN ---------- */
  "t-cns-brain": [
    { dok:3, q:"The surface of the cerebrum is deeply folded into ridges and grooves rather than smooth. Why is this folding advantageous?", a:"Folding fits far more cortical surface area, and thus more neurons, inside the limited space of the skull.", options:["Folding fits far more cortical surface area, and thus more neurons, inside the limited space of the skull.","Folding reduces the amount of brain tissue present.","A smooth brain would fit more neurons than a folded one.","The folds exist only to make the brain look complex."], correctIndex:0, explanation:"Higher functions depend on a large area of cortex, but the skull is a fixed size. Folding the cortex into ridges and grooves packs much more surface, and the neurons it holds, into that limited volume, like crumpling a sheet to fit a small box. The folding maximizes processing capacity within the skull." },
    { dok:3, q:"The brain is cushioned by cerebrospinal fluid that surrounds and floats it. Why does suspending the brain in fluid protect it?", a:"The fluid buoys the brain and absorbs shocks, reducing the force of impacts against the skull.", options:["The fluid buoys the brain and absorbs shocks, reducing the force of impacts against the skull.","The fluid makes the brain heavier and easier to injure.","The fluid pushes the brain hard against the skull.","The fluid has no protective effect."], correctIndex:0, explanation:"Floating the brain in cerebrospinal fluid greatly reduces its effective weight and provides a liquid cushion that dampens sudden movements and blows. Instead of the soft brain slamming directly into bone, the fluid absorbs much of the force. This buoyant cushioning is a key defense for such a delicate organ." },
    { dok:3, q:"Different regions of the cerebral cortex handle different jobs, such as vision at the back and movement control in a strip near the top. Why is this localization of function useful?", a:"Grouping related processing in dedicated areas lets each region specialize and work efficiently.", options:["Grouping related processing in dedicated areas lets each region specialize and work efficiently.","Localization means damage anywhere destroys all functions equally.","Every region does every job identically.","Specialized areas make the brain slower at everything."], correctIndex:0, explanation:"Concentrating a given task, like processing vision or commanding movement, in a specialized region allows efficient, organized processing and tight connections among the neurons doing related work. It also means a clinician can predict deficits from the site of damage. Functional localization is a hallmark of how the cortex is organized." },
    { dok:3, q:"The cerebellum at the back of the brain coordinates movement and balance. Why does damage to it cause clumsy, uncoordinated movements rather than total paralysis?", a:"The cerebellum fine-tunes and coordinates movement rather than initiating it, so damage disrupts smoothness, not the ability to move.", options:["The cerebellum fine-tunes and coordinates movement rather than initiating it, so damage disrupts smoothness, not the ability to move.","The cerebellum starts all movement, so damage stops movement entirely.","The cerebellum has no role in movement.","Damage to it improves coordination."], correctIndex:0, explanation:"Movement is commanded by other regions, while the cerebellum refines those commands, smoothing and coordinating them and maintaining balance. So when it is damaged, the person can still move but the movements become jerky and poorly coordinated. The pattern of deficit reflects the cerebellum's role as a coordinator, not an initiator." },
    { dok:3, q:"The brainstem controls basic functions such as breathing and heart rate, and damage to it is often fatal. Why is injury here more immediately dangerous than damage to the cerebral cortex?", a:"The brainstem runs vital automatic functions that keep the body alive, which the cortex does not.", options:["The brainstem runs vital automatic functions that keep the body alive, which the cortex does not.","The cortex controls breathing, so brainstem damage is harmless.","The brainstem has no important functions.","Cortex damage is always more immediately fatal."], correctIndex:0, explanation:"The brainstem governs the automatic processes essential for life, such as breathing and heartbeat. Damage there can halt these functions and cause death quickly. The cortex handles thought, sensation, and voluntary movement, whose loss is serious but not instantly fatal. The brainstem's control of survival functions makes its injury especially dangerous." },
    { dok:3, q:"The two cerebral hemispheres are connected by a thick band of fibers. Why is this connecting bridge important for brain function?", a:"It lets the two halves share information and coordinate, so they work as an integrated whole.", options:["It lets the two halves share information and coordinate, so they work as an integrated whole.","It keeps the two halves completely isolated from each other.","It prevents the hemispheres from communicating.","The band has no function and only adds weight."], correctIndex:0, explanation:"The cerebral hemispheres each handle somewhat different tasks and each side of the body, so they must exchange information to act in concert. The broad band of fibers carries signals between them, integrating their activity into unified perception and behavior. Cutting it leaves the halves unable to readily share what each one knows." },
    { dok:3, q:"The blood vessels feeding the brain have especially tight walls that strictly limit what can pass from blood into brain tissue. Why is this selective barrier important for the brain?", a:"It protects sensitive neurons from harmful substances and stabilizes the brain's chemical environment.", options:["It protects sensitive neurons from harmful substances and stabilizes the brain's chemical environment.","It blocks all oxygen and nutrients from reaching the brain.","It lets every substance in the blood enter the brain freely.","The barrier weakens the brain's defenses."], correctIndex:0, explanation:"Neurons are highly sensitive and need a stable, protected environment. The tight-walled vessels form a barrier that admits needed nutrients while excluding many toxins, pathogens, and fluctuating substances from the blood, keeping the brain's chemistry steady and shielding it from harm. This protection is vital for an organ so easily disrupted." }
  ],

  /* ---------- CNS: SPINAL CORD ---------- */
  "t-cns-spinal-cord": [
    { dok:3, q:"A reflex such as pulling your hand off a hot stove happens through the spinal cord before the brain is even aware of the pain. Why is routing the response through the spinal cord advantageous?", a:"A shorter path through the cord produces a faster response, limiting injury.", options:["A shorter path through the cord produces a faster response, limiting injury.","Routing through the brain first would be faster.","The spinal cord delays the response to protect the brain.","The reflex cannot work without conscious thought."], correctIndex:0, explanation:"Waiting for the signal to travel to the brain, be processed consciously, and return would cost precious time during which tissue burns. By handling the protective response in the spinal cord, the body reacts in a fraction of the time, pulling away before the brain registers pain. The short reflex path minimizes harm." },
    { dok:3, q:"In a cross section of the spinal cord, gray matter sits in the center and white matter surrounds it, the reverse of the brain's arrangement. Given that white matter is mainly myelinated axons, why does this layout suit the cord?", a:"The outer white matter forms tracts carrying signals up and down between the brain and body.", options:["The outer white matter forms tracts carrying signals up and down between the brain and body.","The white matter stores cerebrospinal fluid.","The arrangement blocks signals from passing through the cord.","White matter on the outside prevents any communication."], correctIndex:0, explanation:"The spinal cord's main job is to relay signals between the brain and the rest of the body, work done by long myelinated axons, which are white matter. Placing those conducting tracts on the outside forms efficient highways running the length of the cord, while the central gray matter handles local processing and reflex connections." },
    { dok:3, q:"Spinal nerves attach to the cord by two roots, one carrying sensory information in and one carrying motor commands out. Why is separating incoming and outgoing fibers into different roots useful?", a:"It keeps sensory input and motor output organized in distinct pathways, so signals do not get crossed.", options:["It keeps sensory input and motor output organized in distinct pathways, so signals do not get crossed.","It mixes sensory and motor signals into one confused channel.","The two roots both carry only sensory signals.","Separating the roots stops the nerve from working."], correctIndex:0, explanation:"By dedicating one root to sensory fibers entering the cord and another to motor fibers leaving it, the nervous system keeps the two directions of traffic cleanly separated and orderly. This organization lets clinicians localize damage and ensures incoming and outgoing signals travel their own routes without interference." },
    { dok:3, q:"An injury high in the spinal cord, in the neck, causes far more widespread paralysis than an injury low in the back. Why does the level of injury determine how much of the body is affected?", a:"The cord carries signals for everything below the injury, so a higher cut disconnects more of the body.", options:["The cord carries signals for everything below the injury, so a higher cut disconnects more of the body.","Lower injuries always paralyze more of the body.","The level of injury has no effect on what is paralyzed.","A neck injury affects only the neck itself."], correctIndex:0, explanation:"Signals to and from a body part must pass the point of injury to reach the brain. An injury in the neck blocks communication with everything below it, including the arms, trunk, and legs, while a low-back injury spares the regions above it. The higher the damage, the more of the body is cut off." },
    { dok:3, q:"The spinal cord is protected by the bony vertebral canal, layers of membranes, and cerebrospinal fluid. Why does such delicate tissue warrant so many protective layers?", a:"Like the brain, the cord cannot readily regenerate, so multiple layers guard against irreparable damage.", options:["Like the brain, the cord cannot readily regenerate, so multiple layers guard against irreparable damage.","The cord regenerates easily, so protection is unnecessary.","The layers exist to slow signals in the cord.","The protection makes the cord more fragile."], correctIndex:0, explanation:"Spinal cord neurons largely do not regrow, so damage can cause permanent loss of function below the injury. Surrounding the cord with bone, protective membranes, and a fluid cushion provides layered defense against the impacts and forces that could cause such irreversible harm, reflecting how precious and vulnerable the tissue is." },
    { dok:3, q:"The spinal cord ends around the upper lumbar region, but spinal nerves continue downward as a bundle before exiting. Why does this arrangement make a lower-back tap to sample cerebrospinal fluid relatively safe?", a:"Below where the cord ends, a needle meets only the more movable nerve bundle, reducing the risk of cord injury.", options:["Below where the cord ends, a needle meets only the more movable nerve bundle, reducing the risk of cord injury.","The cord extends to the tailbone, so any tap is dangerous.","There are no nerves in the lower back to avoid.","A tap there is risky because it always hits the cord."], correctIndex:0, explanation:"Since the spinal cord itself ends higher up, a needle placed in the lower lumbar region enters a space containing only the loose, floating bundle of nerve roots, which tend to drift aside rather than be pierced. This is why clinicians sample cerebrospinal fluid there, below the cord's end, to avoid damaging the cord." }
  ],

  /* ---------- AUTONOMIC NERVOUS SYSTEM ---------- */
  "t-ans": [
    { dok:3, q:"The autonomic nervous system controls functions like heart rate and digestion without conscious effort. Why is automatic, unconscious control of these functions advantageous?", a:"Vital processes continue reliably without demanding attention, even during sleep.", options:["Vital processes continue reliably without demanding attention, even during sleep.","Conscious control of the heartbeat would be more reliable.","Automatic control stops these functions during sleep.","Unconscious control means these functions never work."], correctIndex:0, explanation:"Processes like heartbeat, breathing, and digestion must run continuously, including when a person is asleep or focused elsewhere. Automatic control by the autonomic system keeps them going reliably without requiring conscious thought. Having to consciously manage each heartbeat would be impossible and dangerous, so unconscious regulation is essential." },
    { dok:3, q:"The sympathetic division triggers a coordinated fight-or-flight response, speeding the heart, widening airways, and redirecting blood to muscles all at once. Why is a coordinated, whole-body response useful in an emergency?", a:"Preparing many organs together readies the body to act quickly against a threat.", options:["Preparing many organs together readies the body to act quickly against a threat.","Activating organs one at a time would respond faster.","The response slows the body down in emergencies.","Coordinating organs prevents any of them from responding."], correctIndex:0, explanation:"An emergency demands the whole body shift toward exertion at once: more blood flow, more oxygen, more fuel to the muscles. By activating these changes together, the sympathetic division prepares the entire body to fight or flee within seconds. A piecemeal response would leave the body only partly ready when speed matters most." },
    { dok:3, q:"The parasympathetic division promotes rest-and-digest activities, slowing the heart and stimulating digestion. Why is it useful to have a division opposing the sympathetic one?", a:"It restores and conserves the body after activity and balances the stimulating effects of the sympathetic division.", options:["It restores and conserves the body after activity and balances the stimulating effects of the sympathetic division.","It does exactly the same thing as the sympathetic division.","It keeps the body in constant emergency mode.","Opposing divisions cancel out, leaving no control."], correctIndex:0, explanation:"After a stress response, the body must recover, digest food, and conserve energy. The parasympathetic division drives these restorative functions, counterbalancing the sympathetic system. Having two opposing divisions lets the body shift smoothly between action and recovery and fine-tune each organ by adjusting the balance between them." },
    { dok:3, q:"Many organs receive input from both the sympathetic and parasympathetic divisions, which push them in opposite directions. Why is dual, opposing control of an organ useful?", a:"It allows precise, two-way adjustment, speeding up or slowing down the organ as needed.", options:["It allows precise, two-way adjustment, speeding up or slowing down the organ as needed.","It means the organ can never change its activity.","Opposing inputs always cancel, so the organ does nothing.","Only one input ever reaches the organ at a time."], correctIndex:0, explanation:"With one division able to increase an organ's activity and the other to decrease it, the body can finely tune that organ in both directions, like having both an accelerator and a brake. Adjusting the balance between the two inputs gives smooth, precise control over functions such as heart rate, far better than a single one-way input." },
    { dok:3, q:"During the fight-or-flight response, blood is shifted away from the digestive organs toward the skeletal muscles. Why does this redirection make sense in an emergency?", a:"Muscles need extra blood for action, while digestion can safely wait until the threat passes.", options:["Muscles need extra blood for action, while digestion can safely wait until the threat passes.","Digestion is more urgent than escaping a threat.","Muscles need less blood during emergencies.","Redirecting blood harms the body's response to danger."], correctIndex:0, explanation:"In a crisis the priority is to run or fight, which demands a surge of blood, oxygen, and fuel to the skeletal muscles. Digestion is not urgent in that moment and can be paused, so the body diverts blood from the gut to the muscles. Allocating resources to the immediate need is what makes the redirection adaptive." },
    { dok:3, q:"The pupils widen under sympathetic activation and narrow under parasympathetic activation. Why does the body widen the pupils during a stress response?", a:"Wider pupils let in more light, improving vision to detect threats.", options:["Wider pupils let in more light, improving vision to detect threats.","Wider pupils block light to rest the eyes.","Pupil size has no connection to the stress response.","Narrow pupils would help more in an emergency."], correctIndex:0, explanation:"During fight-or-flight, taking in more visual information helps detect and respond to danger. Widening the pupils admits more light to the eye, enhancing vision. This dovetails with the rest of the sympathetic response, all of which prepares the body to perceive and react to a threat, so dilated pupils fit the emergency setting." }
  ],

  /* ---------- REPRODUCTIVE: MALE ---------- */
  "t-reproductive-male": [
    { dok:3, q:"The testes are housed in the scrotum, outside the main body cavity, where the temperature is slightly cooler. Why is this external position important?", a:"Sperm production requires a temperature below core body temperature, which the cooler scrotum provides.", options:["Sperm production requires a temperature below core body temperature, which the cooler scrotum provides.","The testes need to be warmer than the body to make sperm.","External position protects the testes from all injury.","Location has no effect on sperm production."], correctIndex:0, explanation:"Sperm form properly only at a temperature a few degrees below the body's core. Suspending the testes in the scrotum outside the body keeps them cooler than the abdomen, creating the right conditions for sperm production. This is why the position is external, despite the greater exposure it brings." },
    { dok:3, q:"The seminiferous tubules where sperm are made are extremely long and tightly coiled within each testis. Why is this coiled, lengthy design useful?", a:"Packing great length into a small space provides a large surface for producing huge numbers of sperm.", options:["Packing great length into a small space provides a large surface for producing huge numbers of sperm.","The coiling reduces the number of sperm produced.","Short straight tubules would produce more sperm.","The tubules store urine rather than make sperm."], correctIndex:0, explanation:"Producing the vast quantity of sperm the body makes requires a large amount of sperm-forming tissue. Coiling very long tubules into the compact testis fits an enormous total length, and thus production surface, into a small organ. The tight coiling is what allows such high output from a limited space." },
    { dok:3, q:"Sperm leaving the testis are not yet able to swim and must pass through the epididymis, where they mature, before ejaculation. Why is a maturation and storage site useful before release?", a:"It lets sperm gain motility and be stored ready, so functional sperm are available when needed.", options:["It lets sperm gain motility and be stored ready, so functional sperm are available when needed.","Sperm are fully functional immediately and need no maturation.","The epididymis destroys the sperm before release.","Storing sperm prevents them from ever maturing."], correctIndex:0, explanation:"Freshly produced sperm cannot yet swim. Passing through and being stored in the epididymis gives them time to mature and gain the ability to move, and keeps a reserve of ready sperm on hand. So functional, motile sperm are available at ejaculation, which immediate release of immature sperm could not provide." },
    { dok:3, q:"Several glands add fluid to sperm to form semen, including a sugar-rich secretion. Why is adding this nutrient-containing fluid important?", a:"The fluid nourishes and activates the sperm and provides a medium for them to swim in.", options:["The fluid nourishes and activates the sperm and provides a medium for them to swim in.","The fluid kills the sperm before they leave the body.","Sperm need no fluid and travel better dry.","The fluid only adds volume with no benefit."], correctIndex:0, explanation:"Sperm need energy to swim and a liquid medium to travel through. The glandular secretions supply sugar as fuel, activate the sperm, and create the fluid in which they move. This support greatly improves the sperm's ability to reach and fertilize an egg, which bare sperm without nourishing fluid could not do as well." },
    { dok:3, q:"The male urethra carries both urine and semen, but never both at the same time. Why is it important that these cannot pass together?", a:"A mechanism closes off the bladder during ejaculation, protecting sperm from acidic urine and keeping the functions separate.", options:["A mechanism closes off the bladder during ejaculation, protecting sperm from acidic urine and keeping the functions separate.","Mixing urine and semen improves fertility.","Urine and semen always flow together through the urethra.","The two must mix for either to leave the body."], correctIndex:0, explanation:"Urine is acidic and would harm sperm, so the two should not mix. During ejaculation the passage from the bladder is closed off, so only semen travels through the shared urethra. Keeping urine and semen separate in time protects the sperm and lets one tube serve both systems without conflict." },
    { dok:3, q:"Sperm cells are stripped down to little more than genetic material, a midpiece full of mitochondria, and a tail. Why is this minimalist design suited to the sperm's job?", a:"Shedding extra material makes the cell light and fast, with mitochondria powering the tail to reach the egg.", options:["Shedding extra material makes the cell light and fast, with mitochondria powering the tail to reach the egg.","The stripped design makes the sperm too heavy to move.","Sperm need lots of cytoplasm to swim well.","The minimal design prevents the sperm from carrying genes."], correctIndex:0, explanation:"A sperm's task is to deliver its genetic payload to the egg by swimming there quickly. Discarding most cytoplasm keeps it small and light, the tail provides propulsion, and the midpiece's mitochondria supply the energy to drive it. Every part of the streamlined design serves fast, efficient travel to the egg." }
  ],

  /* ---------- REPRODUCTIVE: FEMALE ---------- */
  "t-reproductive-female": [
    { dok:3, q:"The uterine (fallopian) tubes are lined with cilia and sweep the egg from the ovary toward the uterus. Why are the cilia important even though the egg cannot swim?", a:"The egg cannot move on its own, so the cilia transport it toward the uterus.", options:["The egg cannot move on its own, so the cilia transport it toward the uterus.","The egg swims using its own tail, so cilia are unnecessary.","The cilia push the egg back into the ovary.","The cilia digest the egg before fertilization."], correctIndex:0, explanation:"Unlike sperm, the egg has no means of moving itself. The cilia lining the uterine tube create a current that sweeps the released egg along toward the uterus, and toward any sperm. Without this ciliary transport, the immobile egg could not travel from the ovary, so the cilia are essential to bring egg and sperm together." },
    { dok:3, q:"The lining of the uterus thickens with blood vessels each month and is shed if no pregnancy occurs. Why does the body rebuild this rich lining cyclically?", a:"A thick, blood-rich lining is prepared to nourish an embryo, and it is renewed each cycle to stay ready.", options:["A thick, blood-rich lining is prepared to nourish an embryo, and it is renewed each cycle to stay ready.","The lining thickens to block any embryo from implanting.","A thin lining would support a pregnancy better.","The lining has no role in pregnancy."], correctIndex:0, explanation:"If fertilization occurs, an embryo must implant in and be nourished by the uterine lining, which needs a thick, well-supplied bed of tissue. The body builds this up each cycle in preparation, and if no pregnancy occurs, sheds it and starts fresh so a suitable lining is ready the next cycle. The cycle keeps the uterus prepared." },
    { dok:3, q:"At ovulation a single egg is usually released, while a male releases millions of sperm. Why does this large difference in numbers make biological sense?", a:"The egg is a large, resource-rich cell produced sparingly, while many sperm are needed to improve the odds one reaches it.", options:["The egg is a large, resource-rich cell produced sparingly, while many sperm are needed to improve the odds one reaches it.","Eggs and sperm should be produced in equal numbers.","Releasing many eggs at once would be more efficient.","The numbers are random and carry no meaning."], correctIndex:0, explanation:"The egg is large and stocked with nutrients for a potential embryo, so it is costly and produced one at a time. Sperm face a long, hazardous journey with heavy losses, so vast numbers raise the chance that at least one survives to reach the egg. The contrasting numbers reflect each cell's different size, cost, and task." },
    { dok:3, q:"The egg is a very large cell stocked with nutrients, while the sperm is tiny. Why does the egg carry so many resources?", a:"It supplies the nutrients and materials a new embryo needs in its earliest development.", options:["It supplies the nutrients and materials a new embryo needs in its earliest development.","The egg's size makes it travel faster than sperm.","The resources are unused and serve no purpose.","The egg needs the resources only to swim to the sperm."], correctIndex:0, explanation:"After fertilization the new embryo begins dividing and developing before it can draw nourishment from the mother, so it relies at first on supplies already in the egg. The egg's large size and stockpile of nutrients provide that early support. The sperm contributes mainly genetic material, so it can be small." },
    { dok:3, q:"The ovaries both produce eggs and secrete hormones that regulate the reproductive cycle. Why is it efficient for the same organ to do both?", a:"Coordinating egg release with hormone signals in one organ keeps the cycle timed and integrated.", options:["Coordinating egg release with hormone signals in one organ keeps the cycle timed and integrated.","The two roles interfere, so they should be in separate organs.","Hormones have nothing to do with egg release.","Combining the roles stops both from working."], correctIndex:0, explanation:"The release of an egg and the hormonal changes that prepare the uterus must be tightly synchronized for reproduction to succeed. Having the ovary both produce the egg and secrete the hormones that regulate the cycle lets these events be coordinated together, keeping ovulation and the uterine lining in step with each other." },
    { dok:3, q:"During pregnancy the uterus, a muscular organ, expands enormously to hold the growing fetus. Why is a muscular wall important both during pregnancy and at birth?", a:"Muscle lets the uterus stretch to accommodate the fetus and then contract powerfully to push the baby out at birth.", options:["Muscle lets the uterus stretch to accommodate the fetus and then contract powerfully to push the baby out at birth.","A rigid, non-muscular uterus would deliver the baby better.","The muscle prevents the uterus from expanding.","Uterine muscle has no role in childbirth."], correctIndex:0, explanation:"The uterus must grow with the developing fetus and later generate the force to deliver it. Its muscular wall stretches greatly to hold the pregnancy and then contracts strongly during labor to push the baby out. Both the accommodation and the delivery depend on having a powerful, stretchable muscular organ." }
  ],

  /* ---------- CNS: BRAINSTEM ---------- */
  "t-cns-brainstem": [
    { dok:3, q:"The brainstem connects the brain to the spinal cord, and all signals between the brain and body pass through it. Why does its position make even a small brainstem injury serious?", a:"Because every pathway funnels through this narrow region, damage there can disrupt many functions at once.", options:["Because every pathway funnels through this narrow region, damage there can disrupt many functions at once.","Signals bypass the brainstem, so injury there is harmless.","The brainstem handles only one minor function.","A small injury anywhere in the brain has identical effects."], correctIndex:0, explanation:"The brainstem is the bottleneck through which the ascending and descending pathways between brain and body must travel, alongside centers for vital functions. A small lesion here can therefore interrupt many tracts and functions simultaneously, which is why brainstem injuries are often far more devastating than similar-sized damage elsewhere." },
    { dok:3, q:"The brainstem contains centers that automatically control breathing rate and heart rate. Why is it advantageous to place these life-sustaining centers in the brainstem rather than the conscious cortex?", a:"Automatic control there keeps vital functions running without conscious effort, even during sleep or unconsciousness.", options:["Automatic control there keeps vital functions running without conscious effort, even during sleep or unconsciousness.","Conscious control of breathing would be more reliable.","These centers stop working when a person sleeps.","The cortex already controls breathing, making the brainstem redundant."], correctIndex:0, explanation:"Breathing and heartbeat must continue at all times, including during sleep and unconsciousness, when conscious control is absent. Housing their control centers in the brainstem, below conscious awareness, ensures these functions run automatically and uninterrupted. Relying on the conscious cortex would make survival depend on remembering to breathe." },
    { dok:3, q:"Many reflexes such as coughing, swallowing, and vomiting are coordinated by the brainstem. Why is it useful for these protective reflexes to be handled below conscious control?", a:"Automatic, rapid reflexes protect the airway and body faster than conscious decisions could.", options:["Automatic, rapid reflexes protect the airway and body faster than conscious decisions could.","Conscious control would make these reflexes faster.","These reflexes serve no protective purpose.","Handling them consciously prevents choking."], correctIndex:0, explanation:"Coughing, swallowing, and vomiting guard the airway and digestive tract and must happen quickly and reliably. Coordinating them in the brainstem lets them fire automatically the instant they are needed, faster than conscious thought, and without depending on attention. The protective value comes from their speed and automaticity." },
    { dok:3, q:"Most nerve pathways cross from one side to the other within the brainstem, so the left brain controls the right body. Knowing this, why does a stroke in the right brainstem or brain often affect the left side of the body?", a:"Because the pathways cross in the brainstem, one side of the brain controls the opposite side of the body.", options:["Because the pathways cross in the brainstem, one side of the brain controls the opposite side of the body.","Pathways stay on the same side, so the same side is affected.","The crossing has no effect on which side is affected.","Both sides of the body are always affected equally."], correctIndex:0, explanation:"Because major motor pathways cross to the opposite side as they pass through the brainstem, each half of the brain governs the contralateral half of the body. So damage on the right typically produces symptoms on the left. Understanding the crossing point explains the characteristic opposite-side pattern of many strokes." },
    { dok:3, q:"The brainstem helps regulate consciousness and alertness, and severe brainstem injury can cause coma. Why does this small region have such power over the whole brain's wakefulness?", a:"It contains a network that activates and arouses the rest of the brain, so losing it withdraws that arousal.", options:["It contains a network that activates and arouses the rest of the brain, so losing it withdraws that arousal.","The brainstem has no influence on consciousness.","Consciousness comes only from the cortex acting alone.","Brainstem injury makes a person more alert."], correctIndex:0, explanation:"The brainstem houses an arousal network that sends activating signals upward to keep the cortex awake and alert. When this system is badly damaged, that arousing drive is lost and the brain cannot maintain wakefulness, producing coma. Its control over the brain's overall activation gives this small region outsized influence on consciousness." }
  ],

  /* ---------- CNS: MENINGES AND CSF ---------- */
  "t-cns-meninges-csf": [
    { dok:3, q:"The brain and spinal cord are wrapped in three layers of meninges. Why are multiple membrane layers, rather than a single covering, used to protect the central nervous system?", a:"Layered membranes provide stronger, redundant protection and create spaces for cushioning fluid and blood vessels.", options:["Layered membranes provide stronger, redundant protection and create spaces for cushioning fluid and blood vessels.","A single layer would protect the brain better than three.","The layers serve no protective purpose.","The membranes block blood vessels from reaching the brain."], correctIndex:0, explanation:"Three meningeal layers give the central nervous system tough outer protection, a delicate inner wrapping, and a middle arrangement that, with the spaces between layers, holds cushioning cerebrospinal fluid and routes blood vessels. The layered design protects, cushions, and supplies the brain better than any single membrane could." },
    { dok:3, q:"Cerebrospinal fluid circulates through spaces in and around the brain and is continuously produced and reabsorbed. Why is constant turnover of this fluid important?", a:"Fresh fluid removes wastes and maintains a stable environment, while balanced reabsorption keeps pressure normal.", options:["Fresh fluid removes wastes and maintains a stable environment, while balanced reabsorption keeps pressure normal.","Stagnant fluid would clean the brain better.","The fluid is never reabsorbed and simply accumulates.","Turnover has no effect on the brain's environment."], correctIndex:0, explanation:"Continuously making and reabsorbing cerebrospinal fluid lets it carry away metabolic wastes and keep the brain's surroundings stable and clean, while matching production to reabsorption holds the fluid volume and pressure steady. If reabsorption fails and fluid builds up, pressure rises dangerously, showing why balanced turnover matters." },
    { dok:3, q:"Cerebrospinal fluid fills spaces inside and around the brain, and the brain essentially floats in it. Why does this flotation reduce the effective weight of the brain?", a:"Buoyancy from the surrounding fluid supports the brain, so it does not crush itself or the structures below it.", options:["Buoyancy from the surrounding fluid supports the brain, so it does not crush itself or the structures below it.","The fluid adds weight that the brain must support.","Flotation makes the brain press harder on the skull base.","The fluid has no effect on the brain's weight."], correctIndex:0, explanation:"A brain resting unsupported would compress its own lower structures and blood vessels under its weight. Floating it in cerebrospinal fluid provides buoyant support that dramatically reduces its effective weight, so it is gently suspended rather than crushed. This flotation, alongside shock absorption, is a key role of the fluid." },
    { dok:3, q:"An infection of the meninges, called meningitis, can cause dangerous swelling within the skull. Using the skull's structure, why is swelling there especially threatening?", a:"The rigid skull cannot expand, so swelling raises pressure that compresses the brain.", options:["The rigid skull cannot expand, so swelling raises pressure that compresses the brain.","The skull expands easily, so swelling is harmless.","Swelling lowers the pressure inside the skull.","The meninges are outside the skull, so swelling does not matter."], correctIndex:0, explanation:"The skull is a fixed, unyielding box, so anything that swells inside it has nowhere to go and drives up the internal pressure. Meningeal inflammation and the resulting swelling therefore compress the brain against the rigid bone, which can damage it. The skull's inability to expand is what makes intracranial swelling so dangerous." },
    { dok:3, q:"Cerebrospinal fluid can be sampled from the space around the spinal cord to check for infection or bleeding. Why does testing this fluid reveal problems in the brain as well as the cord?", a:"The fluid circulates around both the brain and cord, so it reflects conditions throughout the central nervous system.", options:["The fluid circulates around both the brain and cord, so it reflects conditions throughout the central nervous system.","The fluid around the cord never contacts the brain.","Brain conditions cannot affect the fluid at all.","The fluid is separate in the brain and the spinal cord."], correctIndex:0, explanation:"Cerebrospinal fluid forms a continuous bath surrounding both the brain and the spinal cord. Because the same fluid circulates around the whole central nervous system, a sample drawn near the spinal cord carries signs of infection or bleeding from the brain too. This shared circulation is why a spinal sample is diagnostic for both." }
  ],

  /* ---------- CRANIAL NERVES ---------- */
  "t-cranial-nerves": [
    { dok:3, q:"Most cranial nerves serve structures of the head and neck rather than the rest of the body. Why does this localization make sense given where the nerves originate?", a:"They arise directly from the brain, so they conveniently serve the nearby head and neck.", options:["They arise directly from the brain, so they conveniently serve the nearby head and neck.","They arise from the legs and travel up to the head.","Their origin has nothing to do with what they serve.","Cranial nerves serve only the feet."], correctIndex:0, explanation:"Cranial nerves emerge straight from the brain and brainstem, so the structures closest to that origin, the eyes, ears, face, tongue, and other head and neck regions, are the most direct and efficient to supply. Their localization to the head reflects their origin, in contrast to spinal nerves that serve the trunk and limbs." },
    { dok:3, q:"The vagus nerve is a striking exception, extending from the head down into the chest and abdomen to influence the heart and digestion. Why is one cranial nerve given such a far reach?", a:"It carries parasympathetic signals to many internal organs, coordinating rest-and-digest functions from a single nerve.", options:["It carries parasympathetic signals to many internal organs, coordinating rest-and-digest functions from a single nerve.","It reaches the abdomen only by accident and does nothing there.","Its long path prevents it from affecting any organs.","It controls only muscles of the face despite its length."], correctIndex:0, explanation:"The vagus nerve provides parasympathetic, rest-and-digest input to the heart, lungs, and much of the digestive tract. Extending one nerve from the brainstem down through the body lets it coordinate these widespread internal functions together, which is why this cranial nerve, unlike its neighbors, reaches far beyond the head." },
    { dok:3, q:"Some cranial nerves carry only sensory fibers, some only motor, and some both. Why is it useful that cranial nerves vary in this way?", a:"Each nerve is matched to its job, carrying just sensation, just movement, or both as its target requires.", options:["Each nerve is matched to its job, carrying just sensation, just movement, or both as its target requires.","All nerves should carry identical fibers regardless of function.","Mixed nerves cannot carry sensation or movement.","The variation prevents the nerves from functioning."], correctIndex:0, explanation:"A nerve serving a pure sense like smell or vision needs only sensory fibers, one moving an eye muscle needs only motor fibers, and one serving the face needs both to feel and to move it. Tailoring each cranial nerve's fiber composition to its specific role makes the system efficient, matching structure to function." },
    { dok:3, q:"Damage to the cranial nerve that controls most eye movements causes the eye to drift and double vision. Why does losing one nerve's control of several eye muscles produce these specific signs?", a:"Without coordinated pull on those muscles, the eye cannot aim properly and the two eyes no longer point together.", options:["Without coordinated pull on those muscles, the eye cannot aim properly and the two eyes no longer point together.","The eye continues moving normally without the nerve.","The nerve controls hearing, not eye movement.","Double vision comes from too much nerve control, not too little."], correctIndex:0, explanation:"Precise eye aiming requires balanced contraction of several muscles, several of which this nerve controls. When it is damaged, those muscles cannot pull correctly, so the affected eye drifts out of alignment. With the two eyes no longer pointing at the same spot, the brain receives two images, producing double vision." },
    { dok:3, q:"The cranial nerves for smell and vision are considered extensions of the brain itself rather than ordinary peripheral nerves. Why might this distinction matter for their ability to recover after damage?", a:"As central nervous tissue, they share the brain's poor capacity to regenerate, so damage tends to be permanent.", options:["As central nervous tissue, they share the brain's poor capacity to regenerate, so damage tends to be permanent.","As brain extensions, they regenerate faster than other nerves.","The distinction has no effect on recovery.","They are not nervous tissue, so they always heal completely."], correctIndex:0, explanation:"Because these nerves are essentially outgrowths of the central nervous system rather than typical peripheral nerves, they share the central nervous system's limited ability to regenerate. Damage to them therefore tends to cause lasting loss, unlike many peripheral nerves that can regrow, which is why the classification matters clinically." }
  ],

  /* ---------- NERVE PLEXUSES ---------- */
  "t-nerve-plexuses": [
    { dok:3, q:"Spinal nerves serving the limbs first mingle and regroup in networks called plexuses before continuing as named nerves. Why is this interweaving useful?", a:"Mixing fibers from several spinal levels into each outgoing nerve lets one muscle receive input from more than one level.", options:["Mixing fibers from several spinal levels into each outgoing nerve lets one muscle receive input from more than one level.","The mixing serves no purpose and only tangles the nerves.","Plexuses keep each spinal level completely separate.","The interweaving stops nerves from reaching the limbs."], correctIndex:0, explanation:"In a plexus, fibers from several spinal levels are combined and redistributed so that each peripheral nerve, and the muscle it serves, draws on multiple spinal segments. This blending provides a more robust supply, so damage to a single spinal nerve does not entirely paralyze a muscle. The regrouping builds redundancy into limb innervation." },
    { dok:3, q:"Because of how a plexus blends fibers, injury to a single spinal nerve root often causes only partial weakness in a limb muscle rather than complete paralysis. Why does this happen?", a:"The muscle still receives fibers from other spinal levels through the plexus, so some function remains.", options:["The muscle still receives fibers from other spinal levels through the plexus, so some function remains.","Each muscle depends on exactly one spinal nerve, so it is fully paralyzed.","The plexus sends no fibers to the muscle.","Partial weakness means the plexus has failed entirely."], correctIndex:0, explanation:"Since a plexus distributes fibers from several spinal levels to each muscle, losing one root removes only part of that muscle's supply. The remaining levels still reach it through the plexus, so the muscle is weakened but not completely paralyzed. This overlapping supply is a direct protective consequence of the plexus design." },
    { dok:3, q:"The network supplying the arm gives rise to nerves controlling the shoulder, forearm, and hand. Why is it efficient to organize the arm's nerve supply through one large network?", a:"A single organized network can sort and route fibers precisely to each part of the limb.", options:["A single organized network can sort and route fibers precisely to each part of the limb.","One network makes the arm impossible to control.","Separate unconnected nerves would route fibers more precisely.","The network sends all fibers to a single finger."], correctIndex:0, explanation:"Bringing the spinal contributions for the whole arm into one network allows the fibers to be systematically sorted and recombined, then sent out as well-organized nerves each aimed at the shoulder, forearm, or hand. Centralizing this routing in one plexus makes the complex job of supplying an entire limb orderly and efficient." },
    { dok:3, q:"An injury to the network of nerves in the armpit region can affect movement and sensation across much of the arm at once. Why can one localized injury have such widespread effects on the limb?", a:"Many of the arm's nerves pass through that network, so damage there disrupts several of them together.", options:["Many of the arm's nerves pass through that network, so damage there disrupts several of them together.","Only one tiny muscle depends on that region.","The network has no connection to the arm's nerves.","Widespread effects mean the injury must be in the leg."], correctIndex:0, explanation:"The nerves for much of the arm are gathered together as they pass through the network in the armpit region. A single injury there can damage many of these fibers at once, before they have separated into their individual nerves, so a localized trauma produces widespread loss across the limb. The convergence point is a vulnerability." },
    { dok:3, q:"The nerve supply to the legs arises from plexuses in the lower trunk, separate from those supplying the arms. Why does the body organize limb nerves into separate regional networks?", a:"Each network gathers the spinal levels relevant to its own limb, keeping the supply organized by region.", options:["Each network gathers the spinal levels relevant to its own limb, keeping the supply organized by region.","One network for the whole body would be more precise.","The legs and arms share a single plexus.","Regional networks prevent the limbs from being supplied."], correctIndex:0, explanation:"The arms draw from upper spinal levels and the legs from lower ones, so the body forms separate plexuses in the regions where each limb's spinal contributions emerge. Organizing the supply into regional networks keeps each limb's innervation grouped logically with the spinal levels that serve it, an orderly arrangement matched to anatomy." }
  ],

  /* ---------- PERIPHERAL NERVOUS SYSTEM ---------- */
  "t-pns": [
    { dok:3, q:"Unlike neurons of the brain and spinal cord, many peripheral nerves can regrow after being cut, especially if the sheath around them stays intact. Why does the intact sheath aid regrowth?", a:"The surviving sheath forms a guiding tube that directs the regrowing fiber back toward its target.", options:["The surviving sheath forms a guiding tube that directs the regrowing fiber back toward its target.","The sheath blocks the fiber from regrowing at all.","Regrowth happens only when the sheath is destroyed.","The sheath has no effect on regrowth."], correctIndex:0, explanation:"A regenerating peripheral axon needs guidance to reach the muscle or skin it once served. When the surrounding sheath survives the injury, it acts as a tube channeling the regrowing fiber along the original path to its target. This guiding structure is a key reason peripheral nerves can recover where central neurons usually cannot." },
    { dok:3, q:"Peripheral nerves carry both signals from the body to the central nervous system and signals from it to the muscles. Why is it efficient to bundle these opposite-direction fibers together in one nerve?", a:"Bundling them lets a single nerve serve a region for both sensation and movement.", options:["Bundling them lets a single nerve serve a region for both sensation and movement.","Mixed nerves cannot carry signals in either direction.","Separate nerves for each direction would reach the region.","The fibers cancel each other when bundled."], correctIndex:0, explanation:"A region of the body typically needs both to feel and to move, requiring sensory fibers running inward and motor fibers running outward. Combining both in one nerve lets a single structure fully serve that region for both functions, an efficient arrangement that avoids running entirely separate sensory and motor nerves to every area." },
    { dok:3, q:"A long peripheral nerve, such as the one running down the leg, is wrapped in tough connective tissue along its length. Why is this protective wrapping important for such a nerve?", a:"It shields the delicate fibers from stretching and pressure as the limb moves and bears weight.", options:["It shields the delicate fibers from stretching and pressure as the limb moves and bears weight.","The wrapping speeds the signal but offers no protection.","Nerve fibers need no protection in the limbs.","The wrapping prevents the nerve from carrying signals."], correctIndex:0, explanation:"A nerve traveling the length of a moving, weight-bearing limb is exposed to stretching, bending, and compression. The tough connective tissue sheath protects the fragile nerve fibers inside from these mechanical stresses so they keep conducting reliably. The wrapping is what lets long peripheral nerves survive the demands of an active limb." },
    { dok:3, q:"When a peripheral nerve to a muscle is severed, the muscle it served becomes paralyzed and gradually shrinks. Why does the muscle waste away after losing its nerve?", a:"Muscles depend on nerve signals both to contract and to maintain their bulk, so without input they atrophy.", options:["Muscles depend on nerve signals both to contract and to maintain their bulk, so without input they atrophy.","The muscle grows larger after losing its nerve.","Nerves have no influence on muscle size.","The muscle is unaffected by losing its nerve."], correctIndex:0, explanation:"Beyond triggering contraction, ongoing nerve input helps maintain a muscle's mass. When the nerve is cut, the muscle can neither contract nor receive that maintaining stimulation, so it weakens and progressively wastes away. The atrophy shows how dependent muscle is on its nerve supply for both movement and upkeep." },
    { dok:3, q:"Sensory receptors in the skin connect through peripheral nerves to the central nervous system. Why is it important that these receptors are spread densely in some areas, like the fingertips, and sparsely in others, like the back?", a:"Dense receptors where fine touch matters give high sensitivity, while sparse coverage suffices where detail is less needed.", options:["Dense receptors where fine touch matters give high sensitivity, while sparse coverage suffices where detail is less needed.","Receptor density is random and unrelated to sensitivity.","More receptors on the back would improve fingertip touch.","Sparse fingertip receptors would improve fine touch."], correctIndex:0, explanation:"Fine discrimination, as the fingertips need for exploring textures and shapes, requires many closely spaced receptors, while regions like the back, where such detail is unnecessary, manage with far fewer. Matching receptor density to how much sensory detail each area needs gives high acuity where it counts without wasteful coverage elsewhere." }
  ],

  /* ---------- NEURONAL INTEGRATION ---------- */
  "t-neuronal-integration": [
    { dok:3, q:"A single neuron may receive thousands of incoming signals, some excitatory and some inhibitory, before deciding whether to fire. Why is this summing of many inputs valuable?", a:"Weighing many signals together lets the neuron make a balanced decision rather than reacting to any single input.", options:["Weighing many signals together lets the neuron make a balanced decision rather than reacting to any single input.","The neuron should fire from any one signal regardless of the others.","Combining inputs prevents the neuron from ever firing.","Inhibitory signals have no effect on the decision."], correctIndex:0, explanation:"By adding up excitatory and inhibitory inputs, a neuron only fires when the overall balance crosses a threshold, so its output reflects the combined message of many sources rather than a single chance signal. This integration lets the nervous system make considered, context-sensitive decisions instead of reacting reflexively to every input." },
    { dok:3, q:"Inhibitory signals make a neuron less likely to fire, opposing excitatory ones. Why is having signals that suppress firing just as important as signals that trigger it?", a:"Inhibition lets the system turn activity down and filter signals, preventing runaway or unwanted firing.", options:["Inhibition lets the system turn activity down and filter signals, preventing runaway or unwanted firing.","Suppressing signals serves no purpose in the nervous system.","Only excitatory signals are needed for control.","Inhibition makes neurons fire more often."], correctIndex:0, explanation:"Control requires both an accelerator and a brake. Inhibitory signals let the nervous system dampen activity, sharpen which signals get through, and prevent excessive or uncontrolled firing, as seen when loss of inhibition causes seizures. Suppression is therefore as essential as excitation for balanced, precise neural function." },
    { dok:3, q:"When a stimulus is stronger, sensory neurons fire more frequently rather than producing a bigger individual signal. Why does the nervous system encode intensity as firing frequency?", a:"Each nerve impulse is all-or-nothing and the same size, so strength must be conveyed by how often impulses fire.", options:["Each nerve impulse is all-or-nothing and the same size, so strength must be conveyed by how often impulses fire.","Stronger stimuli produce larger individual impulses.","Firing frequency has no relation to stimulus strength.","Intensity is encoded by changing the impulse color."], correctIndex:0, explanation:"Because a nerve impulse is all-or-nothing and always the same magnitude, a single impulse cannot signal how strong a stimulus is. Instead, a stronger stimulus makes the neuron fire more impulses per second. Encoding intensity as frequency lets a uniform-size signal still convey a wide range of stimulus strengths." },
    { dok:3, q:"Repeated use of a particular neural pathway can strengthen the connections within it, making future signaling easier. Why is this strengthening important for learning?", a:"Reinforcing frequently used connections is how the nervous system stores experience and forms memories.", options:["Reinforcing frequently used connections is how the nervous system stores experience and forms memories.","Strengthening connections erases all learning.","Connections never change, so learning is impossible.","Weakening used pathways is how memory forms."], correctIndex:0, explanation:"When a pathway is used repeatedly, its synaptic connections become more effective, so the same activity is triggered more readily later. This use-dependent strengthening is a physical basis for learning and memory, letting practice and experience reshape the nervous system so that repeated patterns become easier to reproduce." },
    { dok:3, q:"Pain signals can be dampened by other inputs, which is why rubbing a bumped elbow eases the ache. Using the idea of competing signals, why does rubbing reduce the pain?", a:"The touch signals compete with and partly block the pain signals on their way to the brain.", options:["The touch signals compete with and partly block the pain signals on their way to the brain.","Rubbing adds more pain signals to the brain.","Touch and pain signals never interact.","Rubbing speeds the pain signal to the brain."], correctIndex:0, explanation:"Incoming touch signals from rubbing can interfere with the transmission of pain signals along shared pathways, effectively reducing how much pain reaches the brain. This competition between sensory inputs is why a natural response to a knock is to rub the area, illustrating how integration can suppress one signal with another." }
  ],

  /* ---------- BLOOD VESSEL DISORDERS AND FETAL CIRCULATION ---------- */
  "t-blood-vessel-disorders": [
    { dok:3, q:"Before birth, a vessel called the ductus arteriosus shunts blood away from the lungs, and it normally closes after birth. Why is bypassing the lungs appropriate before birth but not after?", a:"The fetal lungs are not yet used for breathing, so blood is shunted past them until birth, when they take over gas exchange.", options:["The fetal lungs are not yet used for breathing, so blood is shunted past them until birth, when they take over gas exchange.","The fetal lungs do all the breathing, so blood must reach them.","The shunt should stay open for life.","The lungs never receive blood before or after birth."], correctIndex:0, explanation:"In the womb the fetus gets oxygen from the placenta, not the collapsed, nonfunctional lungs, so it makes sense to divert blood past them through the ductus arteriosus. At birth the lungs inflate and take over gas exchange, so the shunt is no longer needed and normally closes. Timing the closure to birth matches the lungs coming online." },
    { dok:3, q:"In fetal circulation, the umbilical vein carries oxygen-rich blood from the placenta to the fetus. Why does the fetus depend on the placenta rather than its own lungs for oxygen?", a:"The fetal lungs are filled with fluid and not breathing, so the placenta supplies oxygen from the mother's blood.", options:["The fetal lungs are filled with fluid and not breathing, so the placenta supplies oxygen from the mother's blood.","The fetal lungs breathe air inside the womb.","The placenta removes oxygen from the fetus.","The fetus makes its own oxygen without the placenta."], correctIndex:0, explanation:"Inside the womb there is no air to breathe and the lungs are fluid-filled and inactive, so the fetus cannot oxygenate its own blood. The placenta instead transfers oxygen from the mother's blood to the fetal blood, and the umbilical vein carries that oxygen-rich blood to the fetus. The placenta substitutes for the unusable lungs." },
    { dok:3, q:"In atherosclerosis, fatty plaque builds up and stiffens and narrows an artery. Why does this narrowing raise the risk of a blockage that starves tissue downstream?", a:"A narrowed, roughened artery slows flow and can become fully blocked, cutting off oxygen to the tissue it feeds.", options:["A narrowed, roughened artery slows flow and can become fully blocked, cutting off oxygen to the tissue it feeds.","Narrowing increases blood flow to the tissue.","Plaque widens the artery, improving flow.","Narrowing has no effect on the tissue downstream."], correctIndex:0, explanation:"As plaque narrows and roughens the channel, less blood gets through and a clot can lodge there and block it completely. The tissue beyond, which depends on that artery for oxygen, is then starved, causing damage such as a heart attack when a coronary artery is involved. The narrowing sets up the blockage and the downstream injury." },
    { dok:3, q:"A weakened, bulging area in an artery wall is called an aneurysm, and it can rupture dangerously. Using the pressure inside arteries, why is a weak spot in an arterial wall so risky?", a:"Arteries carry blood under high pressure, so a weakened wall can balloon and burst, causing severe bleeding.", options:["Arteries carry blood under high pressure, so a weakened wall can balloon and burst, causing severe bleeding.","Arteries carry no pressure, so a weak spot is harmless.","A weak spot strengthens the artery wall.","Veins, not arteries, are under the pressure that causes this."], correctIndex:0, explanation:"Arterial blood is under high pressure from the heart's pumping. A weakened region of the wall cannot withstand that pressure as well, so it bulges outward and may eventually rupture, releasing blood rapidly. The combination of high internal pressure and a compromised wall is what makes an arterial aneurysm so dangerous." },
    { dok:3, q:"Varicose veins develop when the one-way valves in leg veins fail, allowing blood to pool. Using the valves' normal role, why does their failure cause blood to pool?", a:"The valves normally prevent backflow against gravity, so when they fail blood flows backward and collects.", options:["The valves normally prevent backflow against gravity, so when they fail blood flows backward and collects.","The valves normally push blood backward, so failure speeds return.","Valves have no role in leg veins.","Failed valves move blood to the heart faster."], correctIndex:0, explanation:"Leg veins must move blood upward against gravity, and their one-way valves keep it from sliding back down between muscle contractions. If those valves fail, blood is no longer held in place and falls backward, pooling in the veins and stretching them into the bulging, twisted varicose veins. The pooling follows directly from lost valve function." }
  ],

  /* ---------- PREGNANCY AND BIRTH ---------- */
  "t-pregnancy-and-birth": [
    { dok:3, q:"The placenta allows the mother's blood and the fetal blood to exchange materials while keeping the two blood supplies from actually mixing. Why is keeping the two bloodstreams separate important?", a:"It lets oxygen and nutrients cross while protecting the fetus from pressure and immune differences in the mother's blood.", options:["It lets oxygen and nutrients cross while protecting the fetus from pressure and immune differences in the mother's blood.","Mixing the bloodstreams would improve the exchange.","The separation blocks all exchange between mother and fetus.","The two bloods must mix for the fetus to survive."], correctIndex:0, explanation:"The placenta is built so substances diffuse across a thin barrier between the two circulations without the blood actually combining. This allows oxygen and nutrients to pass to the fetus and wastes to pass back, while shielding the fetus from the mother's higher blood pressure and from immune and blood-type differences that direct mixing could make dangerous." },
    { dok:3, q:"During labor, contractions of the uterus grow stronger and more frequent in a self-reinforcing cycle until birth. Why is a self-amplifying cycle appropriate for childbirth specifically?", a:"Birth is a process that must build to completion, so amplification drives it forward to deliver the baby.", options:["Birth is a process that must build to completion, so amplification drives it forward to deliver the baby.","Childbirth should be kept steady and never intensify.","Amplifying contractions would stop labor.","A self-reinforcing cycle is dangerous in every body process."], correctIndex:0, explanation:"Most body processes are kept steady, but childbirth needs to progress decisively to its end. A self-reinforcing cycle, where contractions stretch the uterus and trigger still stronger contractions, builds the force needed to push the baby out and then stops once birth is complete. Amplification suits a one-time event that must run to completion." },
    { dok:3, q:"The umbilical cord connects the fetus to the placenta and is cut at birth. Why can the cord be cut without harming the newborn, when before birth it was essential?", a:"At birth the newborn's own lungs and digestion take over, so it no longer needs the cord's connection to the placenta.", options:["At birth the newborn's own lungs and digestion take over, so it no longer needs the cord's connection to the placenta.","The cord remains essential after birth and should not be cut.","The cord never had any function for the fetus.","Cutting the cord starts the fetal heartbeat for the first time."], correctIndex:0, explanation:"Before birth the cord carried oxygen and nutrients from the placenta because the fetus could not breathe or eat. At birth the baby begins breathing with its own lungs and will feed and digest on its own, so the placental connection is no longer needed and the cord can be safely cut. The newborn's systems replace the cord's role." },
    { dok:3, q:"A newborn's first breath helps close the fetal heart shunt and redirects blood to the lungs. Why does breathing trigger this change in blood flow?", a:"Inflating the lungs lowers their resistance, so blood now flows into them and the fetal bypass is no longer favored.", options:["Inflating the lungs lowers their resistance, so blood now flows into them and the fetal bypass is no longer favored.","Breathing blocks blood from entering the lungs.","The first breath has no effect on blood flow.","Breathing reopens the fetal shunts permanently."], correctIndex:0, explanation:"Before birth the collapsed lungs resist blood flow, so blood bypasses them. The first breaths inflate the lungs and drop their resistance, so blood is drawn into them for gas exchange and the pressures shift in a way that helps close the fetal shunts. Breathing thus drives the switch from fetal to newborn circulation." },
    { dok:3, q:"After birth, the mother's breasts produce milk in response to the infant's suckling, and more suckling brings more milk. Why is matching milk production to suckling useful?", a:"Production rises and falls with the infant's demand, so supply matches the baby's needs.", options:["Production rises and falls with the infant's demand, so supply matches the baby's needs.","Milk production is fixed and ignores the infant entirely.","More suckling reduces milk supply.","Suckling has no effect on milk production."], correctIndex:0, explanation:"Because suckling stimulates milk production, a hungrier infant that nurses more triggers more milk, while reduced nursing lowers production. This demand-driven system keeps the milk supply matched to how much the baby actually needs as it grows, an efficient self-adjusting arrangement that links production directly to the infant's feeding." }
  ]

  };

  // Supplemental set, bringing every topic to a full eight DOK 3 items.
  var DOK3_EXTRA = {
    "t-muscle-fascicles": [
      { dok:3, q:"A fusiform muscle, such as the biceps, has a thick belly that tapers to tendons at each end. Why does this spindle shape balance force and range?", a:"Parallel fibers in the belly allow good shortening, while the bulk provides moderate force, giving a balance of both.", options:["Parallel fibers in the belly allow good shortening, while the bulk provides moderate force, giving a balance of both.","The taper removes all force from the muscle.","The shape prevents the muscle from shortening.","Fusiform muscles produce neither force nor movement."], correctIndex:0, explanation:"A fusiform muscle runs its fibers roughly parallel along a thick central belly, so it shortens a useful amount for good range while its bulk supplies reasonable force. The tapering tendons concentrate that pull onto the bone. The spindle shape is a middle ground between pure range and pure power designs." }
    ],
    "t-endocrine": [
      { dok:3, q:"Hormones act in tiny amounts yet produce large, lasting effects on the body. Why can such small quantities have such powerful results?", a:"Each hormone binds receptors that trigger amplified chains of events inside target cells.", options:["Each hormone binds receptors that trigger amplified chains of events inside target cells.","Hormones must be present in huge amounts to act at all.","Small amounts mean the effects are always tiny and brief.","Hormones act directly without involving the target cell."], correctIndex:0, explanation:"A hormone does not do the work itself; it binds a receptor that sets off an internal cascade in which each step activates many more molecules. This amplification lets a few hormone molecules produce a large cellular response, which is why minute hormone concentrations can drive major, sustained changes in the body." }
    ],
    "t-cardiac-conduction": [
      { dok:3, q:"If the main pacemaker fails, a slower backup region of the heart can take over and keep it beating. Why is having backup pacemakers valuable?", a:"They keep the heart beating, though more slowly, if the primary pacemaker stops.", options:["They keep the heart beating, though more slowly, if the primary pacemaker stops.","They speed the heart far beyond a safe rate.","Backup regions stop the heart entirely.","They serve no purpose since the main pacemaker never fails."], correctIndex:0, explanation:"Other parts of the conduction system can generate their own slower rhythm. If the primary pacemaker fails, one of these takes over so the heart keeps pumping, just at a lower rate. This built-in redundancy is a safety feature that can prevent the heart from stopping if its fastest pacemaker is lost." },
      { dok:3, q:"An electrocardiogram records the heart's electrical activity from the body surface. Why can electrodes on the skin detect signals generated deep in the heart?", a:"The heart's electrical currents spread through the body's fluids to the skin, where they can be measured.", options:["The heart's electrical currents spread through the body's fluids to the skin, where they can be measured.","The electrodes generate the heart's signals themselves.","Skin electrodes cannot detect anything from the heart.","The signal travels only if the skin is cut open."], correctIndex:0, explanation:"Body tissues and fluids conduct electricity, so the currents produced by the heart's contractions spread outward and reach the skin. Surface electrodes pick up these voltage changes, letting clinicians record the heart's rhythm noninvasively. The conductive body is what makes detecting deep cardiac signals from the surface possible." }
    ],
    "t-blood": [
      { dok:3, q:"A person with too few red blood cells, a condition called anemia, often feels tired and short of breath. Why do these symptoms follow from a low red cell count?", a:"Fewer red cells carry less oxygen, so tissues including muscles get less than they need.", options:["Fewer red cells carry less oxygen, so tissues including muscles get less than they need.","Fewer red cells deliver too much oxygen to tissues.","Red cell count has no effect on oxygen delivery.","Low red cells make tissues need less oxygen."], correctIndex:0, explanation:"Red blood cells carry oxygen to the tissues, so with fewer of them the blood delivers less oxygen. Muscles and other tissues, starved of the oxygen they need to make energy, tire easily, and the body breathes harder trying to compensate. The fatigue and breathlessness trace directly to reduced oxygen-carrying capacity." }
    ],
    "t-blood-vessel-disorders": [
      { dok:3, q:"A blood clot that forms in a deep leg vein can break loose and lodge in the lungs. Why does a clot from the leg travel to the lungs rather than elsewhere?", a:"Veins carry blood back to the heart, which then pumps it to the lungs, so a loose clot follows that path.", options:["Veins carry blood back to the heart, which then pumps it to the lungs, so a loose clot follows that path.","Leg veins carry blood directly to the brain.","Clots move against the bloodstream toward the feet.","A clot cannot travel through the bloodstream at all."], correctIndex:0, explanation:"Blood from the legs returns through veins to the right side of the heart, which pumps it next into the lungs. A clot that breaks free is swept along this route and becomes stuck in the lung vessels, causing a pulmonary embolism. Knowing the direction of venous return explains why leg clots end up in the lungs." },
      { dok:3, q:"In high blood pressure, the heart must pump against greater resistance over time, and its wall can thicken. Why does chronic high pressure lead to a thicker heart muscle?", a:"Like any muscle worked harder, the heart enlarges to generate the greater force required.", options:["Like any muscle worked harder, the heart enlarges to generate the greater force required.","High pressure shrinks the heart muscle.","Pressure has no effect on the heart wall.","The heart thins out to pump against more pressure."], correctIndex:0, explanation:"When pressure in the arteries is persistently high, the heart must work harder with each beat to eject blood. Muscle responds to sustained extra load by enlarging, so the heart wall thickens, much as exercised skeletal muscle grows. Over time this overworked, thickened heart can stiffen and fail, linking the structural change to the pressure." },
      { dok:3, q:"Capillaries can be damaged by chronically high blood sugar, harming tissues like the retina and kidney that are rich in them. Why are capillary-dense organs especially vulnerable?", a:"These organs depend on their many delicate capillaries, so widespread capillary damage impairs their function.", options:["These organs depend on their many delicate capillaries, so widespread capillary damage impairs their function.","These organs have no capillaries to damage.","Capillary damage improves these organs' function.","Dense capillaries protect organs from any harm."], correctIndex:0, explanation:"Organs like the retina and kidney rely on extensive networks of fine capillaries to do their work. When high blood sugar damages those thin-walled vessels throughout the organ, its blood supply and function deteriorate. Tissues built around many delicate capillaries are therefore hit hardest by conditions that injure capillaries." }
    ],
    "t-lymphatic-system": [
      { dok:3, q:"Most absorbed nutrients enter the blood, but absorbed dietary fats first enter lymphatic vessels in the intestine. Why might fats take the lymphatic route?", a:"Fat is packaged into particles too large for blood capillaries but able to enter the more permeable lymphatics.", options:["Fat is packaged into particles too large for blood capillaries but able to enter the more permeable lymphatics.","Fats cannot be absorbed by the body at all.","Fats enter lymph because they dissolve easily in blood.","The lymphatic route destroys absorbed fat."], correctIndex:0, explanation:"Absorbed fats are bundled into particles too big to pass readily into the tight blood capillaries of the intestine, but the more open lymphatic capillaries can take them up. The lymph then carries the fat and eventually empties it into the bloodstream. The packaging size of fat explains its detour through the lymphatic system." }
    ],
    "t-alimentary-canal": [
      { dok:3, q:"The four layers of the digestive tract wall include an inner lining, connective tissue, muscle, and an outer covering. Why is a layered wall well suited to the tract's many jobs?", a:"Each layer handles a different task, secretion and absorption, support, movement, and protection, so all the tract's functions are covered.", options:["Each layer handles a different task, secretion and absorption, support, movement, and protection, so all the tract's functions are covered.","All four layers do the identical job, making three redundant.","The layers prevent the tract from functioning.","A single layer would perform all jobs better."], correctIndex:0, explanation:"Digestion requires secreting and absorbing at the surface, structural support and blood supply, muscular movement of food, and an outer protective boundary. The tract's wall divides these among its layers, the lining, the connective tissue, the muscle, and the outer covering, so one organized wall accomplishes all of digestion's varied demands." }
    ],
    "t-accessory-digestive-organs": [
      { dok:3, q:"The teeth come in different shapes, with flat front teeth and broad back teeth. Why does having varied tooth shapes aid digestion?", a:"Different shapes cut, tear, and grind food, breaking it down mechanically for easier chemical digestion.", options:["Different shapes cut, tear, and grind food, breaking it down mechanically for easier chemical digestion.","All teeth do the same job, so their shapes are meaningless.","Varied teeth prevent food from being chewed.","Tooth shape only matters for appearance, not digestion."], correctIndex:0, explanation:"Front teeth are shaped to cut and tear, while flatter back teeth grind. Together they break food into smaller pieces, increasing its surface area so digestive enzymes can act on it more effectively. The variety of tooth shapes equips the mouth to mechanically process many kinds of food before swallowing." }
    ],
    "t-urinary-system": [
      { dok:3, q:"Healthy urine normally contains little or no glucose or protein, even though blood is full of both. Why are these substances kept out of normal urine?", a:"Glucose is reabsorbed back into the blood, and protein is too large to be filtered out in the first place.", options:["Glucose is reabsorbed back into the blood, and protein is too large to be filtered out in the first place.","Both are deliberately dumped into the urine.","The kidney destroys glucose and protein.","Urine should normally be full of glucose and protein."], correctIndex:0, explanation:"The filter holds back large molecules like proteins, so they stay in the blood, while glucose that is filtered is normally reabsorbed entirely back into the body. As a result, normal urine has little of either. Finding glucose or protein in urine signals a problem, which is why their normal absence is meaningful." }
    ],
    "t-reproductive-male": [
      { dok:3, q:"A muscle in the scrotal wall pulls the testes closer to the body when it is cold and lets them hang lower when warm. Why is this adjustment useful?", a:"It keeps the testes near the cooler temperature needed for sperm production despite changes in surroundings.", options:["It keeps the testes near the cooler temperature needed for sperm production despite changes in surroundings.","It keeps the testes at the body's hottest temperature.","It moves the testes only for appearance.","Temperature has no effect on the testes."], correctIndex:0, explanation:"Sperm form best at a temperature below the body's core, so the testes must stay slightly cool. When it is cold, drawing them close to the warm body prevents them from getting too cold, and when warm, letting them hang keeps them from overheating. The adjustment holds them near the ideal temperature for sperm production." },
      { dok:3, q:"The prostate sits surrounding the urethra just below the bladder. Why can enlargement of the prostate make urination difficult?", a:"Because it encircles the urethra, an enlarged prostate squeezes that tube and obstructs urine flow.", options:["Because it encircles the urethra, an enlarged prostate squeezes that tube and obstructs urine flow.","The prostate is far from the urethra and cannot affect it.","Enlargement widens the urethra and speeds urination.","The prostate blocks the bladder from filling."], correctIndex:0, explanation:"The urethra passes directly through the prostate, so when the prostate enlarges it presses inward on that tube and narrows it. This obstructs the flow of urine, producing the difficulty common with prostate enlargement. The gland's wrap-around position relative to the urethra is exactly why its growth interferes with urination." }
    ],
    "t-reproductive-female": [
      { dok:3, q:"After ovulation, the structure left behind in the ovary secretes hormones that maintain the uterine lining. Why is this temporary hormone source important?", a:"It sustains the prepared lining so that a fertilized egg can implant and be supported.", options:["It sustains the prepared lining so that a fertilized egg can implant and be supported.","It immediately sheds the lining after ovulation.","It prevents any egg from being released.","It has no effect on the uterus."], correctIndex:0, explanation:"Once the egg is released, the remaining ovarian structure secretes hormones that keep the thickened uterine lining intact and ready. This maintains a hospitable environment in case the egg is fertilized and needs to implant. If no pregnancy occurs, this source fades, the support is withdrawn, and the lining is shed." },
      { dok:3, q:"The ovaries release eggs that have been present since before birth, while the testes continually produce new sperm. Why does this difference matter for the timing of reproduction?", a:"A finite, aging egg supply means female fertility has a limited span, unlike the ongoing sperm production in males.", options:["A finite, aging egg supply means female fertility has a limited span, unlike the ongoing sperm production in males.","Eggs are made fresh daily, so supply never runs out.","Sperm are present from birth and never renewed.","The difference has no effect on fertility."], correctIndex:0, explanation:"Females are born with a set number of eggs that are not replenished and age over time, so fertility declines and eventually ends. Males instead make new sperm continuously. This basic difference in whether the gametes are a fixed early stock or a renewing supply shapes the very different fertility timelines of the two sexes." }
    ],
    "t-pregnancy-and-birth": [
      { dok:3, q:"In the first weeks of development, the embryo forms three primary tissue layers from which all organs arise. Why is establishing these layers a critical early step?", a:"Each layer gives rise to specific tissues and organs, so forming them sets the foundation for the whole body.", options:["Each layer gives rise to specific tissues and organs, so forming them sets the foundation for the whole body.","The layers are discarded and never form organs.","All three layers form the same single organ.","The layers prevent organs from forming."], correctIndex:0, explanation:"The three primary germ layers each become particular tissues and organs, for example skin and nervous system, muscle and bone, or the linings of internal organs. Establishing them early lays out the basic body plan from which every organ develops, which is why this step is a foundational milestone of development." },
      { dok:3, q:"The developing fetus is cushioned within a fluid-filled sac. Why is this fluid environment important for development?", a:"The fluid cushions the fetus from pressure and shock and lets it move and grow freely.", options:["The fluid cushions the fetus from pressure and shock and lets it move and grow freely.","The fluid crushes the fetus to shape it.","The fluid prevents the fetus from moving at all.","The fluid has no role in development."], correctIndex:0, explanation:"Surrounding the fetus in fluid protects it from external pressure and bumps, maintains an even temperature, and gives it room to move, which supports normal muscle and skeletal development. The cushioning fluid environment is important both for protecting the fetus and for allowing the free movement that healthy growth requires." },
      { dok:3, q:"A pregnant person's blood volume increases substantially during pregnancy. Why is this increase necessary?", a:"More blood is needed to supply the placenta and growing fetus and to prepare for blood loss at birth.", options:["More blood is needed to supply the placenta and growing fetus and to prepare for blood loss at birth.","The extra blood serves no purpose.","Blood volume should drop during pregnancy.","The increase prevents oxygen from reaching the fetus."], correctIndex:0, explanation:"Pregnancy adds the demands of the placenta and fetus, which need a generous blood supply for exchange of oxygen and nutrients, and childbirth involves blood loss. Increasing blood volume meets the added circulatory load and provides a reserve against delivery blood loss, so the rise supports both the pregnancy and the birth." }
    ],
    "t-nervous-tissue": [
      { dok:3, q:"After a peripheral nerve is cut, regrowth proceeds very slowly, only a small distance per day. Why can slow regrowth still leave a person without function for months?", a:"A nerve may have to regrow a long distance to reach its target, so even steady slow growth takes a long time.", options:["A nerve may have to regrow a long distance to reach its target, so even steady slow growth takes a long time.","Slow regrowth means the nerve never reaches its target.","Nerves regrow instantly, so months are unnecessary.","The distance a nerve must regrow does not affect recovery time."], correctIndex:0, explanation:"When a nerve to a hand or foot is cut, the fiber may need to regrow across a long stretch of the limb to reach the muscle or skin it served. At a slow growth rate, covering that distance takes many months, during which function is absent. The combination of slow growth and long distance explains the lengthy recovery." }
    ],
    "t-neuronal-integration": [
      { dok:3, q:"A weak stimulus may fail to make a neuron fire, but several weak stimuli arriving close together can succeed. Why do multiple small inputs combine to trigger firing?", a:"Their effects add together, and once the total crosses the threshold the neuron fires.", options:["Their effects add together, and once the total crosses the threshold the neuron fires.","Each weak input cancels the others out.","A neuron fires only from a single input, never several.","Combining inputs prevents the neuron from firing."], correctIndex:0, explanation:"A neuron sums the inputs it receives, and a single weak signal may not reach the firing threshold. But several weak signals arriving together can add up to cross that threshold, triggering an impulse. This summation lets a neuron respond to the combined weight of many small inputs rather than requiring one strong one." },
      { dok:3, q:"A neuron cannot fire again during a brief period right after each impulse. Why is this short enforced pause useful?", a:"It ensures impulses stay separate and travel in one direction down the axon.", options:["It ensures impulses stay separate and travel in one direction down the axon.","It lets impulses travel backward up the axon.","It allows the neuron to fire continuously without limit.","The pause stops the neuron from ever firing again."], correctIndex:0, explanation:"For a brief moment after firing, the neuron cannot fire again. This keeps each impulse a distinct event and prevents a new impulse from running backward into the region just active, so signals march in one direction along the axon. The short pause also caps how rapidly a neuron can fire, keeping signaling orderly." },
      { dok:3, q:"After signaling, the chemical messenger in a synapse is quickly removed or broken down. Why is rapid clearance of the messenger important?", a:"It ends the signal promptly so the synapse is ready for the next message and does not fire continuously.", options:["It ends the signal promptly so the synapse is ready for the next message and does not fire continuously.","It makes the signal last forever.","Clearing the messenger prevents any signaling at all.","The messenger is never removed from the synapse."], correctIndex:0, explanation:"If the messenger lingered, it would keep stimulating the next neuron and blur one signal into the next. Quickly removing or breaking it down sharply ends each signal, resets the synapse, and lets it respond accurately to the next impulse. Prompt clearance is what keeps synaptic signaling crisp and well-timed." }
    ],
    "t-cns-brain": [
      { dok:3, q:"The left and right hemispheres tend to specialize, with language concentrated on one side in most people. Why might concentrating a complex function on one side be efficient?", a:"Housing the circuitry for a complex task in one place allows tight, fast connections rather than splitting it across both sides.", options:["Housing the circuitry for a complex task in one place allows tight, fast connections rather than splitting it across both sides.","Splitting a function across both sides is always faster.","Specialization means the function works in neither hemisphere.","Language uses no brain tissue at all."], correctIndex:0, explanation:"A demanding function like language involves many interconnected areas. Concentrating that circuitry within one hemisphere keeps the connections short and fast and avoids duplicating the machinery on both sides. This specialization is thought to make complex processing more efficient, which helps explain why such functions are often lateralized." }
    ],
    "t-cns-brainstem": [
      { dok:3, q:"Twelve pairs of cranial nerves, which control much of the head, attach mostly to the brainstem. Why is the brainstem a logical attachment point for them?", a:"It connects the brain to the body and lies near the head structures these nerves serve.", options:["It connects the brain to the body and lies near the head structures these nerves serve.","It is the farthest point from the head.","The brainstem has no connection to the cranial nerves.","Cranial nerves attach there only by accident."], correctIndex:0, explanation:"The brainstem sits at the base of the brain, close to the eyes, ears, face, and throat that the cranial nerves serve, and it links the brain to the rest of the nervous system. Attaching the cranial nerves here puts them near both their targets and the brain, making the brainstem a natural hub for them." },
      { dok:3, q:"The brainstem relays sensory information up to the higher brain and motor commands down to the body. Why does damage to the brainstem often affect both sensation and movement?", a:"Both the ascending sensory and descending motor pathways pass through it, so damage can disrupt both.", options:["Both the ascending sensory and descending motor pathways pass through it, so damage can disrupt both.","Only sensory pathways pass through the brainstem.","Neither sensation nor movement involves the brainstem.","The brainstem carries movement but not sensation."], correctIndex:0, explanation:"The brainstem is a two-way conduit, carrying sensory signals upward to the brain and motor signals downward to the body. Because both kinds of pathway funnel through it, a single lesion there can interrupt sensation and movement at once. The shared passage explains the mixed deficits seen with brainstem injury." },
      { dok:3, q:"The brainstem adjusts heart rate and breathing automatically in response to the body's needs, such as during exercise. Why is automatic, moment-to-moment adjustment valuable here?", a:"It continuously matches breathing and heart rate to changing demands without requiring conscious effort.", options:["It continuously matches breathing and heart rate to changing demands without requiring conscious effort.","It locks heart rate and breathing at fixed values.","Conscious control would adjust these faster.","Automatic adjustment prevents the body from responding to exercise."], correctIndex:0, explanation:"The body's needs for oxygen and circulation change constantly, rising during exertion and falling at rest. The brainstem senses these shifts and adjusts breathing and heart rate automatically, so the response is immediate and does not depend on conscious attention. This continuous self-regulation keeps supply matched to demand at all times." }
    ],
    "t-cns-spinal-cord": [
      { dok:3, q:"The spinal cord is shorter than the vertebral column, ending well above the bottom of the spine. Given that it grows more slowly than the surrounding bone, why does the adult cord fall short of the column's end?", a:"The vertebral column lengthens more than the cord during growth, so the cord ends higher than the bony canal.", options:["The vertebral column lengthens more than the cord during growth, so the cord ends higher than the bony canal.","The cord grows faster than the column and overshoots it.","The cord and column are exactly the same length.","The cord shrinks to nothing in adults."], correctIndex:0, explanation:"Early on the cord and column are about the same length, but as the body grows the vertebral column elongates more than the spinal cord. The cord therefore ends up reaching only partway down the adult canal, with the nerve roots continuing below it. The mismatch in growth explains why the cord stops short of the column's end." },
      { dok:3, q:"The width of the spinal cord is greater in the neck and lower back regions than in between. Why are the cord enlargements located there?", a:"Those regions contain the extra neurons that supply the arms and legs, which need rich innervation.", options:["Those regions contain the extra neurons that supply the arms and legs, which need rich innervation.","The cord is widest where it does the least work.","The enlargements have no relation to the limbs.","The cord is thickest where no nerves leave it."], correctIndex:0, explanation:"The arms and legs require many nerves for their complex movements and sensation, so the cord regions that serve the limbs hold extra neurons and swell in width. These enlargements in the neck and lower back match where the nerves for the upper and lower limbs arise, tying the cord's shape to the limbs it supplies." }
    ],
    "t-cns-meninges-csf": [
      { dok:3, q:"The toughest, outermost meningeal layer is much thicker and stronger than the inner layers. Why is the outer layer built to be the most durable?", a:"As the outermost defense against the skull and outside forces, it needs to be the strongest.", options:["As the outermost defense against the skull and outside forces, it needs to be the strongest.","The inner layers face the most force, so the outer one need not be strong.","The outer layer does no protecting at all.","Strength of the layers is unrelated to their position."], correctIndex:0, explanation:"The outer meningeal layer sits against the inside of the skull and is the first membrane line of defense for the brain. Being outermost, it bears the brunt of contact and force, so it is built thick and tough, while the more delicate inner layers, cushioned within, can be finer. Its position as the front-line barrier explains its durability." },
      { dok:3, q:"Cerebrospinal fluid is clear and watery rather than thick like blood. Why does a thin, watery fluid suit its roles of cushioning and circulating around the brain?", a:"A low-friction watery fluid flows easily through the narrow spaces and cushions without adding weight.", options:["A low-friction watery fluid flows easily through the narrow spaces and cushions without adding weight.","A thick fluid would circulate through the brain faster.","The fluid must be solid to cushion the brain.","Fluid consistency has no effect on its function."], correctIndex:0, explanation:"Cerebrospinal fluid must flow freely through the slender channels in and around the brain and bathe its surfaces. A thin, watery fluid moves easily through these tight spaces and provides buoyant cushioning without the weight or sluggishness of a thick fluid. Its watery nature fits the need to circulate readily and cushion gently." },
      { dok:3, q:"Cerebrospinal fluid is reabsorbed into the bloodstream at about the same rate it is produced. Why must production and reabsorption stay balanced?", a:"Balancing the two keeps the fluid volume and the pressure around the brain stable.", options:["Balancing the two keeps the fluid volume and the pressure around the brain stable.","Imbalance has no effect on the brain.","More production than reabsorption lowers the pressure.","Reabsorption should always greatly exceed production."], correctIndex:0, explanation:"If the fluid were made faster than it is reabsorbed, it would accumulate and raise the pressure inside the rigid skull, compressing the brain. Keeping production and reabsorption matched holds the fluid volume steady and the surrounding pressure normal. The balance is what protects the brain from harmful changes in intracranial pressure." }
    ],
    "t-cranial-nerves": [
      { dok:3, q:"Smell, vision, and hearing are each served by their own separate cranial nerve. Why does the head devote a dedicated nerve to each of these senses?", a:"Each special sense needs a dedicated pathway to carry its distinct information to the brain accurately.", options:["Each special sense needs a dedicated pathway to carry its distinct information to the brain accurately.","One nerve could carry all senses with no loss of accuracy.","The senses share a single nerve in the head.","Separate nerves prevent the senses from working."], correctIndex:0, explanation:"Smell, vision, and hearing each carry a very different kind of information that must reach specific processing areas of the brain. Giving each its own cranial nerve keeps these channels separate and accurate, preventing the signals from mixing. Dedicated pathways for the special senses ensure each kind of information arrives cleanly." },
      { dok:3, q:"The facial nerve controls the muscles of facial expression, so damage to it causes drooping on one side of the face. Why does losing one nerve produce drooping rather than total facial collapse?", a:"It supplies the expression muscles on one side, so its loss weakens that side while the other side, served by its own nerve, still works.", options:["It supplies the expression muscles on one side, so its loss weakens that side while the other side, served by its own nerve, still works.","It controls both sides, so both droop equally.","The facial nerve has no role in facial movement.","Drooping comes from too much nerve activity."], correctIndex:0, explanation:"Each facial nerve drives the expression muscles on its own side of the face. When one is damaged, that side loses muscle tone and droops, while the opposite side, run by the other facial nerve, keeps functioning. The one-sided drooping reflects that each nerve governs only its own half of the face." },
      { dok:3, q:"Some cranial nerves carry parasympathetic fibers to glands and organs, such as those that trigger tear and saliva production. Why is it efficient to route these automatic functions through cranial nerves?", a:"The cranial nerves already reach the head glands and organs, so they can also carry the signals that regulate them.", options:["The cranial nerves already reach the head glands and organs, so they can also carry the signals that regulate them.","These functions cannot travel through nerves.","Cranial nerves never reach any glands.","Routing them this way prevents the glands from working."], correctIndex:0, explanation:"Cranial nerves already travel to the eyes, salivary glands, and other head structures to provide sensation or movement. Carrying the parasympathetic signals that stimulate tearing and salivation along these same nerves reaches the target glands efficiently, without needing separate pathways. Using the existing routes makes regulating these functions economical." }
    ],
    "t-nerve-plexuses": [
      { dok:3, q:"A nerve emerging from a plexus, such as the large nerve running down the back of the leg, contains fibers from several spinal levels. Why does this pooled origin make the nerve more robust?", a:"Drawing on multiple spinal levels means injury to any one level only partly affects the nerve's function.", options:["Drawing on multiple spinal levels means injury to any one level only partly affects the nerve's function.","Pooling levels makes the nerve fail if any level is hurt.","The nerve comes from a single level, not several.","Pooled origin weakens the nerve."], correctIndex:0, explanation:"Because a plexus-derived nerve gathers fibers from several spinal segments, the loss of any single segment removes only a portion of its fibers, leaving the rest functional. This pooled origin builds in resilience, so damage at one spinal level causes partial rather than complete loss in the nerve and the structures it serves." },
      { dok:3, q:"Plexuses are located close to where the limbs attach to the trunk. Why is positioning the nerve networks there sensible?", a:"It lets the spinal nerves regroup right before fanning out into the nearby limb.", options:["It lets the spinal nerves regroup right before fanning out into the nearby limb.","It places the network as far from the limb as possible.","The location keeps nerves from reaching the limb.","Plexus position is unrelated to the limbs."], correctIndex:0, explanation:"Placing each plexus near the base of the limb it serves lets the spinal nerves mix and reorganize just before entering that limb, so the regrouped nerves can fan out directly into it. Locating the network at the limb's attachment point keeps the wiring efficient, with sorting happening right where the nerves head into the limb." },
      { dok:3, q:"Compression of a plexus, for example by poor posture or a tumor, can cause tingling and weakness spread across a limb. Why does pressure on a plexus produce such widespread limb symptoms?", a:"Many of the limb's nerves pass through the plexus together, so pressure there affects several at once.", options:["Many of the limb's nerves pass through the plexus together, so pressure there affects several at once.","A plexus contains only one nerve, so symptoms stay local.","Pressure on a plexus has no effect on the limb.","The plexus is not connected to the limb's nerves."], correctIndex:0, explanation:"At the plexus, numerous nerves destined for different parts of the limb are bundled close together. Pressure there can squeeze several of these at once, so symptoms appear across the areas they serve rather than in a single small region. The convergence of many nerves in the plexus is why compression spreads its effects widely." }
    ],
    "t-pns": [
      { dok:3, q:"Peripheral nerves are organized into bundles of fibers wrapped in connective tissue, much like a cable of many wires. Why is bundling many fibers into one nerve efficient?", a:"It lets a single nerve carry signals for many destinations along one protected route.", options:["It lets a single nerve carry signals for many destinations along one protected route.","Bundling fibers blocks their signals.","Each fiber needs its own separate nerve to function.","Bundling makes the nerve unable to reach any target."], correctIndex:0, explanation:"A region of the body needs signals to and from many points, and running a separate nerve to each would be wasteful. Bundling many fibers into one wrapped nerve lets a single protected structure carry all those signals along a shared path, branching to its targets near the end. The cable-like design is an efficient way to wire the body." },
      { dok:3, q:"Sensory neurons of the peripheral nervous system have their cell bodies clustered in swellings just outside the spinal cord rather than within it. Why might keeping these cell bodies outside the cord be advantageous?", a:"It keeps the crowded sensory cell bodies out of the cord, leaving its interior for processing and pathways.", options:["It keeps the crowded sensory cell bodies out of the cord, leaving its interior for processing and pathways.","The cell bodies must be inside the cord to work.","Their location outside the cord stops them from sensing.","Cell body location has no functional reason."], correctIndex:0, explanation:"Housing the large sensory cell bodies in clusters just outside the spinal cord keeps the cord's interior free for its conducting tracts and processing circuits rather than crowding it with cell bodies. This organization, with sensory cell bodies gathered in nearby swellings, keeps the cord compact while still receiving their incoming fibers." },
      { dok:3, q:"Numbness and tingling in the hands can result from pressure on a peripheral nerve, such as at the wrist. Why does compressing a nerve cause these sensations?", a:"Pressure disrupts the nerve's normal signaling, producing abnormal or reduced sensation in the area it serves.", options:["Pressure disrupts the nerve's normal signaling, producing abnormal or reduced sensation in the area it serves.","Pressure improves the nerve's signaling.","Compressed nerves create signals in unrelated body parts.","Nerve pressure has no effect on sensation."], correctIndex:0, explanation:"A peripheral nerve must conduct signals cleanly to and from the area it serves. Squeezing it interferes with that conduction, so the brain receives faulty or diminished signals from the region, felt as tingling or numbness in the hand. The symptoms map to the territory of the compressed nerve, pointing to where the pressure is." }
    ],
    "t-ans": [
      { dok:3, q:"The two autonomic divisions often originate from different regions of the central nervous system, one from the middle of the spinal cord and one from the brainstem and lowest spinal segments. Why might separating their origins help them act independently?", a:"Distinct origins let the two opposing divisions be activated separately as needed.", options:["Distinct origins let the two opposing divisions be activated separately as needed.","Shared origins would make them easier to control separately.","Separate origins prevent both from ever working.","Their origins are identical and overlap completely."], correctIndex:0, explanation:"Because the sympathetic and parasympathetic divisions push organs in opposite directions, it is useful to be able to call on each one independently. Having them arise from separate regions of the central nervous system supports activating one without automatically triggering the other, which helps the body shift between action and rest as circumstances demand." },
      { dok:3, q:"After the threat in a fight-or-flight response passes, the body returns to normal over minutes rather than instantly. Why does recovery take some time?", a:"The stress chemicals already released must be cleared and the opposing division must restore resting conditions.", options:["The stress chemicals already released must be cleared and the opposing division must restore resting conditions.","The body cannot recover from a stress response at all.","Recovery is instant, so the premise is false.","Stress chemicals vanish the moment the threat ends."], correctIndex:0, explanation:"During the stress response, signaling chemicals are released into the blood and tissues and continue to act until they are broken down and cleared, which takes time. Meanwhile the rest-and-digest division works to slow the heart and restore normal function. Because both clearing the chemicals and reversing their effects take minutes, recovery is gradual." }
    ],
    "t-tissues": [
      { dok:3, q:"Connective tissue is described as cells scattered within a large amount of nonliving material between them. Why does having abundant material between the cells suit connective tissue's roles?", a:"The material between cells, not the cells themselves, provides the support, cushioning, and connection these tissues give.", options:["The material between cells, not the cells themselves, provides the support, cushioning, and connection these tissues give.","Connective tissue has no material between its cells.","The cells alone do all the supporting with no role for the matrix.","The material between cells blocks the tissue from supporting anything."], correctIndex:0, explanation:"Unlike epithelium, where packed cells do the work, connective tissue relies on the nonliving material its cells secrete around them. That material, with its fibers and ground substance, gives bone its hardness, cartilage its cushioning, and tendons their strength. Having abundant matrix between the cells is exactly what lets connective tissue support and connect." }
    ],
    "t-integumentary": [
      { dok:3, q:"Goosebumps form when tiny muscles attached to hair follicles contract, pulling the hairs upright. In a furry animal this traps air for warmth, but why does it persist in humans with little body hair?", a:"It is an inherited reflex retained from furrier ancestors, even though the warming benefit is now minimal.", options:["It is an inherited reflex retained from furrier ancestors, even though the warming benefit is now minimal.","Human goosebumps trap large amounts of warm air effectively.","Goosebumps are a recent human invention unrelated to other animals.","The muscles pull the hairs flat rather than upright."], correctIndex:0, explanation:"Raising the hairs to trap an insulating layer of air warms a furry animal, and the same muscles and reflex remain in humans. Because we have little body hair, the warming effect is now slight, so goosebumps persist mainly as an inherited leftover of that ancestral mechanism rather than as an effective way to stay warm." }
    ],
    "t-articulations": [
      { dok:3, q:"The knee joint is reinforced by ligaments inside and around it and by cartilage pads, more support than a simple hinge would seem to need. Why does the knee require so much reinforcement?", a:"It bears large loads while allowing movement, so extra ligaments and pads provide stability the bones alone cannot.", options:["It bears large loads while allowing movement, so extra ligaments and pads provide stability the bones alone cannot.","The knee bears no weight, so the supports are decorative.","The reinforcement prevents the knee from bending.","Bone shape alone fully stabilizes the knee without soft tissue."], correctIndex:0, explanation:"The knee must carry the body's weight and withstand twisting forces while still bending freely, but its bone surfaces are relatively flat and offer little inherent stability. The surrounding and internal ligaments plus the cartilage pads supply the stability and cushioning the bony fit lacks, which is why this heavily loaded joint is so reinforced." }
    ]
  };

  function injectMap(MAP, prefix){
    Object.keys(MAP).forEach(function(tid){
      var t = byId[tid];
      if (!t || !Array.isArray(t.cards)) return;
      MAP[tid].forEach(function(card, i){
        if (!card.id) card.id = prefix + tid + "-" + (i + 1);
        if (!card.a && card.options && typeof card.correctIndex === "number") card.a = card.options[card.correctIndex];
        shuffleCard(card);
        card.source = card.source || "DOK3 Explain-Why Bank";
        t.cards.push(card);
      });
    });
  }
  injectMap(DOK3, "d3-");
  injectMap(DOK3_EXTRA, "d3x-");

  // Re-run the metadata enrichment so the newly injected cards get
  // global IDs and DOK tags just like the base bank.
  if (typeof window !== "undefined" && typeof window.BIO004_enrich === "function") {
    window.BIO004_enrich();
  }
})();
